CREATE TABLE code_edges (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    from_class TEXT,
    from_method TEXT,
    to_class TEXT,
    to_method TEXT,
    edge_type TEXT NOT NULL CHECK (edge_type IN
        ('CALLS','IMPORTS','CONTAINS','INHERITS','DECORATES','REFERENCES')),
    evidence_line INTEGER
);

CREATE TABLE code_files (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    file_path TEXT UNIQUE,
    file_hash TEXT,
    full_source TEXT,
    line_count INTEGER,
    class_count INTEGER,
    method_count INTEGER,
    ingested_at TEXT DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE code_units (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    file_path TEXT,
    file_hash TEXT,
    class_name TEXT,
    method_name TEXT,
    unit_type TEXT NOT NULL CHECK (unit_type IN
        ('FILE','CLASS','METHOD','FUNCTION','MODULE_CONST','IMPORT','MAIN_BLOCK')),
    source_text TEXT,
    docstring TEXT,
    return_type TEXT,
    dispatch_key TEXT,
    calls TEXT,
    called_by TEXT,
    imports TEXT,
    line_start INTEGER,
    line_end INTEGER,
    parent_class TEXT,
    is_vbstyle INTEGER DEFAULT 0,
    content_hash TEXT,
    ingested_at TEXT DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE mined_findings (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    unit_id INTEGER NOT NULL,
    content_hash TEXT NOT NULL,
    finding_type TEXT NOT NULL,
    finding_text TEXT NOT NULL,
    session_id TEXT,
    message_role TEXT,
    created_at TEXT,
    confidence REAL DEFAULT 0.7,
    ingested_at TEXT DEFAULT CURRENT_TIMESTAMP,
    FOREIGN KEY (unit_id) REFERENCES code_units(id)
);

CREATE TABLE sqlite_sequence(name,seq);

CREATE TABLE stamps (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    unit_id INTEGER NOT NULL,
    content_hash TEXT NOT NULL,
    stamp_text TEXT NOT NULL,
    stamp_tier TEXT NOT NULL DEFAULT 'SURFACE',
    purpose TEXT,
    side_effects TEXT,
    callers TEXT,
    confidence REAL DEFAULT 0.5,
    created_at TEXT DEFAULT CURRENT_TIMESTAMP,
    superseded_by INTEGER,
    FOREIGN KEY (unit_id) REFERENCES code_units(id)
);

CREATE INDEX idx_ce_from ON code_edges(from_class, from_method);

CREATE INDEX idx_ce_to ON code_edges(to_class, to_method);

CREATE INDEX idx_ce_type ON code_edges(edge_type);

CREATE INDEX idx_cu_class ON code_units(class_name);

CREATE INDEX idx_cu_file ON code_units(file_path);

CREATE INDEX idx_cu_hash ON code_units(content_hash);

CREATE INDEX idx_cu_method ON code_units(method_name);

CREATE INDEX idx_cu_type ON code_units(unit_type);

CREATE INDEX idx_mined_hash ON mined_findings(content_hash);

CREATE INDEX idx_mined_type ON mined_findings(finding_type);

CREATE INDEX idx_mined_unit ON mined_findings(unit_id);

CREATE INDEX idx_stamps_active ON stamps(unit_id) WHERE superseded_by IS NULL;

CREATE INDEX idx_stamps_hash ON stamps(content_hash);

CREATE INDEX idx_stamps_tier ON stamps(stamp_tier);

CREATE INDEX idx_stamps_unit ON stamps(unit_id);


