    performance_score REAL DEFAULT 0,
    status TEXT DEFAULT 'active',
    created_at TEXT DEFAULT CURRENT_TIMESTAMP,
    updated_at TEXT DEFAULT CURRENT_TIMESTAMP,
    FOREIGN KEY (class_id) REFERENCES classes(id) ON DELETE CASCADE,
    FOREIGN KEY (method_id) REFERENCES methods(id) ON DELETE CASCADE
);

CREATE TABLE decision_edges (
        edge_id INTEGER PRIMARY KEY AUTOINCREMENT,
        from_node INTEGER,
        to_node INTEGER,
        condition TEXT,
        weight REAL DEFAULT 1.0,
        FOREIGN KEY(from_node) REFERENCES decision_nodes(node_id),
        FOREIGN KEY(to_node) REFERENCES decision_nodes(node_id)
    );

CREATE TABLE decision_nodes (
        node_id INTEGER PRIMARY KEY AUTOINCREMENT,
        domain TEXT,
        name TEXT,
        node_type TEXT,
        payload TEXT,
        created_at TEXT DEFAULT CURRENT_TIMESTAMP
    );

CREATE TABLE execution_contracts (
            contract_id INTEGER PRIMARY KEY AUTOINCREMENT,
            node_type TEXT NOT NULL UNIQUE,
            contract_json TEXT NOT NULL,
            input_schema TEXT,
            output_schema TEXT,
            failure_modes TEXT,
            retry_policy TEXT,
            bcl_alignment TEXT,
            created_at TEXT DEFAULT CURRENT_TIMESTAMP
        );

CREATE TABLE execution_log (
        log_id INTEGER PRIMARY KEY AUTOINCREMENT,
        run_id TEXT,
        node_id INTEGER,
        status TEXT,
        output TEXT,
        timestamp TEXT DEFAULT CURRENT_TIMESTAMP,
        FOREIGN KEY(node_id) REFERENCES decision_nodes(node_id)
    );

CREATE TABLE graph_schema_registry (
            schema_id INTEGER PRIMARY KEY AUTOINCREMENT,
            domain TEXT NOT NULL,
            schema_type TEXT NOT NULL,
            definition TEXT NOT NULL,
            version TEXT DEFAULT '1.0',
            created_at TEXT DEFAULT CURRENT_TIMESTAMP
        );

CREATE TABLE methods (id INTEGER PRIMARY KEY, class_id INTEGER, method_name TEXT, method_code TEXT,
        params TEXT, signature TEXT, is_dunder INTEGER, is_vbstyle INTEGER, returns_tuple3 INTEGER,
        line_start INTEGER, version INTEGER DEFAULT 1, created_at TEXT, FOREIGN KEY(class_id) REFERENCES classes(id));

CREATE TABLE orchestration (id INTEGER PRIMARY KEY, pipeline TEXT, sequence INTEGER, class_id INTEGER, role TEXT, description TEXT);

CREATE TABLE plan_ingredients (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    plan_id INTEGER NOT NULL,
    class_id INTEGER,
    method_id INTEGER,
    role TEXT,                             -- what role this ingredient plays
    FOREIGN KEY (plan_id) REFERENCES plans(id) ON DELETE CASCADE,
    FOREIGN KEY (class_id) REFERENCES classes(id),
    FOREIGN KEY (method_id) REFERENCES methods(id)
);

CREATE TABLE plan_outcomes (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    plan_id INTEGER NOT NULL,
    execution_id INTEGER,                  -- links to execution_log
    success INTEGER DEFAULT 0,
    steps_completed INTEGER DEFAULT 0,
    steps_total INTEGER DEFAULT 0,
    learned_rules TEXT,                    -- rules learned during execution
    gaps_found TEXT,                       -- gaps discovered during execution
    notes TEXT,
    created_at TEXT DEFAULT CURRENT_TIMESTAMP,
    FOREIGN KEY (plan_id) REFERENCES plans(id) ON DELETE CASCADE
);

CREATE TABLE plan_steps (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    plan_id INTEGER NOT NULL,
    sequence INTEGER NOT NULL,
    step_name TEXT NOT NULL,
    domain TEXT,
    class_id INTEGER,
    method_name TEXT,
    description TEXT,
    produces TEXT,                         -- what this step outputs
    consumes TEXT,                         -- what this step needs as input
    FOREIGN KEY (plan_id) REFERENCES plans(id) ON DELETE CASCADE,
    FOREIGN KEY (class_id) REFERENCES classes(id)
);

CREATE TABLE plan_versions (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    plan_id INTEGER NOT NULL,
    version INTEGER NOT NULL,
    change_description TEXT,
    created_at TEXT DEFAULT CURRENT_TIMESTAMP,
    FOREIGN KEY (plan_id) REFERENCES plans(id) ON DELETE CASCADE
);

CREATE TABLE plans (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    name TEXT NOT NULL UNIQUE,
    description TEXT,
    goal TEXT NOT NULL,
    ingredients_needed TEXT,
    expected_outcome TEXT,
    status TEXT DEFAULT 'draft',          -- draft / ready / active / retired
    version INTEGER DEFAULT 1,
    parent_plan_id INTEGER,                -- for plan inheritance/templates
    created_at TEXT DEFAULT CURRENT_TIMESTAMP,
    updated_at TEXT DEFAULT CURRENT_TIMESTAMP, promoted_to_class_id INTEGER REFERENCES classes(id),
    FOREIGN KEY (parent_plan_id) REFERENCES plans(id)
);

CREATE TABLE run_metrics (
    metric_id INTEGER PRIMARY KEY AUTOINCREMENT,
    run_id TEXT,
    domain TEXT,
    total_nodes INTEGER,
    nodes_executed INTEGER,
    nodes_failed INTEGER,
    fallbacks_created INTEGER,
    duration_seconds REAL,
    success INTEGER,
    timestamp TEXT DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE run_state (
        run_id TEXT PRIMARY KEY,
        current_node INTEGER,
        state TEXT,
        updated_at TEXT DEFAULT CURRENT_TIMESTAMP,
        FOREIGN KEY(current_node) REFERENCES decision_nodes(node_id)
    );

