_t\", \"metal_get_max_threads_per_group->int\", \"metal_get_command_buffer->MTLCommandBuffer\"]',185,0,40,'24599107451fe5ad15ca00c76154edfd8d350c6a2e024aef90103c7ffaff623e','HEADER_ONLY','Header file only - no implementation. 42 function declarations for Metal GPU backend. Needs corresponding .c implementation file to test. Functions cover: init/shutdown, device detection/config, kernel compilation, buffer management, kernel execution (sync/async), math operations (matmul, softmax, layer_norm, gelu, rope, mlp), memory optimization, profiling, error handling.','42 functions declared. Architecture verified. Buffer management and kernel execution pattern applies to any GPU compute task including hashing.','Devin - treasure hunt session',NULL),(4,'HashKernel - Metal Entropy Analysis','/Users/wws/contestsystem/models/metal/HashKernel.metal','Metal',_binary '#include <metal_stdlib>\nusing namespace metal;\n\n// Entropy scanning kernel for pattern detection\nkernel void entropyScan(\n    device uchar *input [[buffer(0)]],\n    device uint *hist [[buffer(1)]],\n    uint id [[thread_position_in_grid]]\n) {\n    uchar b = input[id];\n    atomic_fetch_add_explicit((atomic_uint*)&hist[b], 1, memory_order_relaxed);\n}\n\n// Byte frequency analysis for compression hints\nkernel void frequencyAnalysis(\n    device uchar *input [[buffer(0)]],\n    device float *frequencies [[buffer(1)]],\n    uint id [[thread_position_in_grid]]\n) {\n    // Placeholder for more sophisticated pattern analysis\n    // Can be extended to detect run-length encoding opportunities\n    atomic_fetch_add_explicit((atomic_uint*)&frequencies[input[id]], 1, memory_order_relaxed);\n}\n',781,'866080d5809b8d73181ecabe1525fc874c0662c048db7d532a9ed0d857272dd6','Metal compute kernel for entropy scanning and byte frequency analysis. Uses atomic_fetch_add_explicit for parallel byte histogram. Pattern detection for compression hints.','Metal,kernel,entropy,histogram,byte-frequency,compression,atomic,compute-shader','metal-kernel','2026-06-28 12:47:28','Devin session - treasure hunt','contestsystem/models/metal',1,'Metal compute kernel that processes file bytes on GPU in parallel. Uses atomic operations for byte frequency counting. Starting point for Metal GPU SHA256 kernel.','[@file<HashKernel.metal>][@state<active>][@date<2025-01-03>][@ver<1.0>][@auth<wws>]','[@auth<wws>][@role<metal_entropy_kernel>][@return<void>][@orch<gpu_compute>][@no<print|hardcoded>]','/Users/wws/contestsystem/models/metal/HashKernel.metal','Metal compute kernel for entropy scanning and byte frequency analysis. Uses atomic_fetch_add_explicit for parallel byte histogram. Pattern detection for compression hints. Starting point for Metal GPU SHA256 kernel.',NULL,'entropyScan, frequencyAnalysis, entropyScan, frequencyAnalysis',NULL,'[\"entropyScan\", \"frequencyAnalysis\", \"entropyScan\", \"frequencyAnalysis\"]','[\"entropyScan(device uchar *input [[buffer(0)\", \"frequencyAnalysis(device uchar *input [[buffer(0)\", \"atomic_fetch_add_explicit((atomic_uint*)\"]','[\"entropyScan->Entropy scanning kernel for pattern detection\\nkernel void\", \"frequencyAnalysis->Byte frequency analysis for compression hints\\nkernel void\", \"atomic_fetch_add_explicit->length encoding opportunities\"]',24,0,4,'866080d5809b8d73181ecabe1525fc874c0662c048db7d532a9ed0d857272dd6','METAL_KERNEL','Metal compute shader - requires Metal framework and GPU. Two kernels: entropyScan (byte histogram with atomic ops) and frequencyAnalysis (byte frequency for compression). Can be tested by dispatching from a Metal command queue.','24 lines, 2 kernels. Uses atomic_fetch_add_explicit for parallel byte counting. Proves Metal compute shaders can process file bytes on GPU in parallel.','Devin - treasure hunt session',NULL),(5,'GPU Hash Backfill - CommonCrypto SHA256','/Users/wws/contestsystem/gpu_hash_backfill.c','C',_binary '/*\n * gpu_hash_backfill.c — Hardware-accelerated SHA256 backfill for CODEBASE MySQL\n * Uses CommonCrypto (Apple hardware acceleration on M1) + multi-threaded workers\n * Based on tool_fastindex.c architecture\n *\n * Build:\n *   cc -O3 -o gpu_hash_backfill gpu_hash_backfill.c \\\n *     -I/opt/homebrew/Cellar/mysql@8.0/8.0.46_1/include \\\n *     -L/opt/homebrew/Cellar/mysql@8.0/8.0.46_1/lib \\\n *     -lmysqlclient -lssl -lcrypto \\\n *     -Wl,-rpath,/opt/homebrew/Cellar/mysql@8.0/8.0.46_1/lib\n *\n * Usage:\n *   ./gpu_hash_backfill\n */\n\n#include <stdio.h>\n#include <stdlib.h>\n#include <string.h>\n#include <stdint.h>\n#include <limits.h>\n#include <pthread.h>\n#include <stdatomic.h>\n#include <time.h>\n#include <CommonCrypto/CommonDigest.h>\n#include <mysql/mysql.h>\n\n#define BATCH_SIZE 500\n#define MAX_WORKERS 8\n#define HASH_HEX_LEN 64  // SHA256 = 32 bytes = 64 hex chars\n\ntypedef struct {\n    uint64_t id;\n    char *content;\n    size_t content_len;\n    char hash[HASH_HEX_LEN + 1];\n} Row;\n\ntypedef struct {\n    Row *rows;\n    size_t count;\n    atomic_size_t *next_job;\n    int worker_id;\n} HashWorker;\n\nstatic double monotonic_seconds(void) {\n    struct timespec ts;\n    clock_gettime(CLOCK_MONOTONIC, &ts);\n    return (double)ts.tv_sec + (double)ts.tv_nsec / 1000000000.0;\n}\n\nstatic void sha256_to_hex(const unsigned char digest[CC_SHA256_DIGEST_LENGTH], char out[HASH_HEX_LEN + 1]) {\n    static const char hex[] = \"0123456789abcdef\";\n    for (int i = 0; i < CC_SHA256_DIGEST_LENGTH; i++) {\n        out[i * 2] = hex[(digest[i] >> 4) & 0x0F];\n        out[i * 2 + 1] = hex[digest[i] & 0x0F];\n    }\n    out[HASH_HEX_LEN] = \'\\0\';\n}\n\nstatic void compute_sha256(const char *data, size_t len, char out[HASH_HEX_LEN + 1]) {\n    CC_SHA256_CTX ctx;\n    unsigned char digest[CC_SHA256_DIGEST_LENGTH];\n    CC_SHA256_Init(&ctx);\n\n    /* Handle large data in chunks (CC_LONG is uint32_t) */\n    const unsigned char *ptr = (const unsigned char *)data;\n    while (len > 0) {\n        size_t chunk = len > UINT_MAX ? UINT_MAX : len;\n        CC_SHA256_Update(&ctx, ptr, (CC_LONG)chunk);\n        ptr += chunk;\n        len -= chunk;\n    }\n\n    CC_SHA256_Final(digest, &ctx);\n    sha256_to_hex(digest, out);\n}\n\nstatic void *hash_worker_main(void *arg) {\n    HashWorker *worker = (HashWorker *)arg;\n\n    for (;;) {\n        size_t job_index = atomic_fetch_add(worker->next_job, 1);\n        if (job_index >= worker->count) {\n            break;\n        }\n\n        Row *row = &worker->rows[job_index];\n        if (row->content && row->content_len > 0) {\n            compute_sha256(row->content, row->content_len, row->hash);\n        } else {\n            /* Empty content → hash of empty string */\n            compute_sha256(\"\", 0, row->hash);\n        }\n    }\n\n    return NULL;\n}\n\nint main(int argc, char **argv) {\n    const char *host = \"127.0.0.1\";\n    const char *user = \"root\";\n    const char *pass = \"\";\n    const char *db   = \"CODEBASE\";\n    unsigned int port = 3306;\n\n    /* Tables to backfill */\n    const char *tables[] = {\n        \"python_files\", \"c_files\", \"json_files\", \"markdown_files\",\n        \"yaml_files\", \"swift_files\", \"csharp_files\"\n    };\n    int num_tables = sizeof(tables) / sizeof(tables[0]);\n\n    MYSQL *conn = mysql_init(NULL);\n    if (!conn) {\n        fprintf(stderr, \"mysql_init failed\\n\");\n        return 1;\n    }\n\n    if (!mysql_real_connect(conn, host, user, pass, db, port, NULL, 0)) {\n        fprintf(stderr, \"MySQL connect failed: %s\\n\", mysql_error(conn));\n        return 1;\n    }\n\n    printf(\"Connected to MySQL %s\\n\", mysql_get_server_info(conn));\n\n    /* Disable binlogging for this session */\n    mysql_query(conn, \"SET SESSION sql_log_bin = 0\");\n\n    double total_start = monotonic_seconds();\n\n    for (int t = 0; t < num_tables; t++) {\n        const char *table = tables[t];\n\n        /* Count remaining */\n        char count_sql[256];\n        snprintf(count_sql, sizeof(count_sql), \"SELECT COUNT(*) FROM %s WHERE content_hash IS NULL\", table);\n        if (mysql_query(conn, count_sql)) {\n            fprintf(stderr, \"Count query failed for %s: %s\\n\", table, mysql_error(conn));\n            continue;\n        }\n        MYSQL_RES *res = mysql_store_result(conn);\n        MYSQL_ROW row = mysql_fetch_row(res);\n        uint64_t remaining = atoll(row[0]);\n        mysql_free_result(res);\n\n        if (remaining == 0) {\n            printf(\"  %s: already fully hashed\\n\", table);\n            continue;\n        }\n\n        printf(\"  %s: %llu rows to hash...\\n\", table, (unsigned long long)remaining);\n        fflush(stdout);\n\n        uint64_t done = 0;\n        double table_start = monotonic_seconds();\n\n        while (done < remaining) {\n            /* Fetch batch */\n            char fetch_sql[256];\n            snprintf(fetch_sql, sizeof(fetch_sql),\n                     \"SELECT id, content FROM %s WHERE content_hash IS NULL LIMIT %d\",\n                     table, BATCH_SIZE);\n\n            if (mysql_query(conn, fetch_sql)) {\n                fprintf(stderr, \"Fetch failed: %s\\n\", mysql_error(conn));\n                break;\n            }\n\n            MYSQL_RES *batch_res = mysql_store_result(conn);\n            int batch_count = mysql_num_rows(batch_res);\n            if (batch_count == 0) {\n                mysql_free_result(batch_res);\n                break;\n            }\n\n            /* Allocate rows */\n            Row *rows = calloc(batch_count, sizeof(Row));\n            for (int i = 0; i < batch_count; i++) {\n                MYSQL_ROW r = mysql_fetch_row(batch_res);\n                unsigned long *lengths = mysql_fetch_lengths(batch_res);\n                rows[i].id = atoll(r[0]);\n                if (r[1] && lengths[1] > 0) {\n                    rows[i].content_len = lengths[1];\n                    rows[i].content = malloc(lengths[1]);\n                    memcpy(rows[i].content, r[1], lengths[1]);\n                } else {\n                    rows[i].content = NULL;\n                    rows[i].content_len = 0;\n                }\n            }\n            mysql_free_result(batch_res);\n\n            /* Multi-threaded hashing */\n            atomic_size_t next_job = 0;\n            int num_workers = (batch_count < MAX_WORKERS) ? batch_count : MAX_WORKERS;\n            pthread_t threads[MAX_WORKERS];\n            HashWorker workers[MAX_WORKERS];\n\n            for (int w = 0; w < num_workers; w++) {\n                workers[w].rows = rows;\n                workers[w].count = batch_count;\n                workers[w].next_job = &next_job;\n                workers[w].worker_id = w;\n                pthread_create(&threads[w], NULL, hash_worker_main, &workers[w]);\n            }\n            for (int w = 0; w < num_workers; w++) {\n                pthread_join(threads[w], NULL);\n            }\n\n            /* Write hashes back to MySQL */\n            mysql_autocommit(conn, 0);\n            for (int i = 0; i < batch_count; i++) {\n                char update_sql[512];\n                snprintf(update_sql, sizeof(update_sql),\n                         \"UPDATE %s SET content_hash = \'%s\' WHERE id = %llu\",\n                         table, rows[i].hash, (unsigned long long)rows[i].id);\n                mysql_query(conn, update_sql);\n            }\n            mysql_commit(conn);\n            mysql_autocommit(conn, 1);\n\n            /* Free rows */\n            for (int i = 0; i < batch_count; i++) {\n                free(rows[i].content);\n            }\n            free(rows);\n\n            done += batch_count;\n            double elapsed = monotonic_seconds() - table_start;\n            double rate = done / elapsed;\n            printf(\"\\r  %s: %llu/%llu (%.1f%%) — %.0f rows/s — %.0fs\",\n                   table, (unsigned long long)done, (unsigned long long)remaining,\n                   (double)done / remaining * 100.0, rate, elapsed);\n            fflush(stdout);\n        }\n\n        double table_elapsed = monotonic_seconds() - table_start;\n        printf(\"\\n  %s: DONE — %llu rows in %.1fs\\n\", table,\n               (unsigned long long)done, table_elapsed);\n    }\n\n    double total_elapsed = monotonic_seconds() - total_start;\n    printf(\"\\nAll tables done in %.1fs\\n\", total_elapsed);\n\n    /* Final verification */\n    printf(\"\\nVerification:\\n\");\n    for (int t = 0; t < num_tables; t++) {\n        char sql[256];\n        snprintf(sql, sizeof(sql), \"SELECT COUNT(*) FROM %s WHERE content_hash IS NULL\", tables[t]);\n        mysql_query(conn, sql);\n        MYSQL_RES *res = mysql_store_result(conn);\n        MYSQL_ROW row = mysql_fetch_row(res);\n        int unhashed = atoi(row[0]);\n        mysql_free_result(res);\n\n        snprintf(sql, sizeof(sql), \"SELECT COUNT(*) FROM %s\", tables[t]);\n        mysql_query(conn, sql);\n        res = mysql_store_result(conn);\n        row = mysql_fetch_row(res);\n        int total = atoi(row[0]);\n        mysql_free_result(res);\n\n        printf(\"  %s: %d rows — %s\\n\", tables[t], total,\n               unhashed == 0 ? \"OK\" : \"UNHASHED REMAINING\");\n    }\n\n    mysql_close(conn);\n    return 0;\n}\n',8949,'dc8c5fdcb3e983b0287bb920acbdf068a97781dabb4a180e2d46887227cd6174','Hardware-accelerated SHA256 backfill for CODEBASE MySQL. Uses CommonCrypto (Apple hardware acceleration on M1) + multi-threaded pthread workers. Batches 500 rows at a time from MySQL.','SHA256,CommonCrypto,MySQL,backfill,pthread,batch,hardware-accelerated,M1','tool','2026-06-28 12:47:28','Devin session - treasure hunt','contestsystem',1,'SHA256 backfill tool. Uses CommonCrypto which uses Apple hardware SHA extension on M1. Multi-threaded with pthread. Batch processing from MySQL. 270 lines total.','[@file<gpu_hash_backfill.c>][@state<active>][@date<2025-01-03>][@ver<1.0>][@auth<wws>]','[@auth<wws>][@role<sha256_backfill>][@return<void>][@orch<pthread_mysql>][@no<print|hardcoded>]','/Users/wws/contestsystem/gpu_hash_backfill.c','Hardware-accelerated SHA256 backfill for CODEBASE MySQL. Uses CommonCrypto (Apple hardware acceleration on M1) + multi-threaded pthread workers. Batches 500 rows at a time from MySQL. 270 lines.','Row, HashWorker','monotonic_seconds, sha256_to_hex, compute_sha256, hash_worker_main, main, f, f, f, f, f, f, f, f, f, f, f, f, f, f, f, f, f, struct, struct','[\"Row\", \"HashWorker\"]','[\"monotonic_seconds\", \"sha256_to_hex\", \"compute_sha256\", \"hash_worker_main\", \"main\", \"f\", \"f\", \"f\", \"f\", \"f\", \"f\", \"f\", \"f\", \"f\", \"f\", \"f\", \"f\", \"f\", \"f\", \"f\", \"f\", \"f\", \"struct\", \"struct\"]','[\"CommonCrypto(Apple hardware acceleration on M1)\", \"sha256_to_hex(const unsigned char digest[CC_SHA256_DIGEST_LENGTH], char out[HASH_HEX_LEN + 1])\", \"compute_sha256(const char *data, size_t len, char out[HASH_HEX_LEN + 1])\", \"chunks(CC_LONG is uint32_t)\", \"main(int argc, char **argv)\", \"COUNT(*)\", \"COUNT(*)\", \"COUNT(*)\"]','[\"CommonCrypto->accelerated SHA256 backfill for CODEBASE MySQL\\n * Uses\", \"monotonic_seconds->double\", \"chunks->Handle large data in\", \"main->int\", \"COUNT->SELECT\", \"COUNT->SELECT\", \"COUNT->SELECT\"]',271,2,24,'dc8c5fdcb3e983b0287bb920acbdf068a97781dabb4a180e2d46887227cd6174','COMPILABLE','Has main() function. Compiles with: cc -O3 -o gpu_hash_backfill gpu_hash_backfill.c -I/opt/homebrew/Cellar/mysql@8.0/8.0.46_1/include -L/opt/homebrew/Cellar/mysql@8.0/8.0.46_1/lib -lmysqlclient -lssl -lcrypto. Tests: MySQL connection, batch fetching 500 rows, parallel SHA256 with pthread workers, batch UPDATE back to MySQL.','271 lines, 2 structs (Row, HashWorker), 24 functions. Uses CommonCrypto CC_SHA256 (Apple hardware SHA extension on M1). pthread workers for parallelism. Batch size 500. MySQL integration for reading unhashed rows and writing hashes back.','Devin - treasure hunt session',NULL),(6,'Metal Hash Backfill - CryptoKit Swift','/Users/wws/contestsystem/metal_hash_backfill.swift','Swift',_binary 'import Foundation\nimport CryptoKit\nimport MySQL\n\n// Connect to MySQL\nlet conn = MySQL()\nguard conn.connect(host: \"127.0.0.1\", user: \"root\", password: \"\", db: \"CODEBASE\", port: 3306) else {\n    print(\"MySQL connection failed: \\(conn.errorMessage())\")\n    exit(1)\n}\nprint(\"Connected to MySQL\")\n\n// Disable binlogging\n_ = conn.query(\"SET SESSION sql_log_bin = 0\")\n\n// Count remaining\nguard let countResult = conn.query(\"SELECT COUNT(*) FROM python_files WHERE content_hash IS NULL\") else {\n    print(\"Count query failed\")\n    exit(1)\n}\nlet countRow = countResult.nextRow()\nlet total = countRow?[0] as? Int ?? 0\nprint(\"Remaining unhashed: \\(total)\")\n\nif total == 0 {\n    print(\"All done!\")\n    exit(0)\n}\n\nvar done = 0\nlet batchSize = 1000\n\nwhile true {\n    // Fetch unhashed rows\n    guard let result = conn.query(\"SELECT id, content FROM python_files WHERE content_hash IS NULL LIMIT \\(batchSize)\") else {\n        print(\"Query failed: \\(conn.errorMessage())\")\n        break\n    }\n\n    var updates: [(Int, String)] = []\n    while let row = result.nextRow() {\n        guard let id = row[0] as? Int else { continue }\n        var content: Data\n        if let s = row[1] as? String {\n            content = Data(s.utf8)\n        } else if let d = row[1] as? Data {\n            content = d\n        } else {\n            content = Data()\n        }\n\n        // CryptoKit SHA256 — hardware accelerated on M1\n        let hash = SHA256.hash(data: content)\n            .compactMap { String(format: \"%02x\", $0) }\n            .joined()\n        updates.append((id, hash))\n    }\n\n    if updates.isEmpty { break }\n\n    // Batch update\n    var sql = \"UPDATE python_files SET content_hash = CASE id \"\n    var ids: [Int] = []\n    for (id, hash) in updates {\n        sql += \"WHEN \\(id) THEN \'\\(hash)\' \"\n        ids.append(id)\n    }\n    sql += \"END WHERE id IN (\\(ids.map(String.init).joined(separator: \",\")))\"\n\n    if !conn.query(sql) {\n        print(\"Update failed: \\(conn.errorMessage())\")\n        // Fall back to individual updates\n        for (id, hash) in updates {\n            _ = conn.query(\"UPDATE python_files SET content_hash = \'\\(hash)\' WHERE id = \\(id)\")\n        }\n    }\n\n    done += updates.count\n    let pct = Double(done) / Double(total) * 100\n    print(String(format: \"  %d/%d (%.1f%%)\", done, total, pct))\n}\n\nprint(\"Done! \\(done) rows hashed with Metal/CryptoKit SHA256\")\n\n// Verify all tables\nfor table in [\"c_files\", \"python_files\", \"json_files\", \"markdown_files\", \"yaml_files\", \"swift_files\", \"csharp_files\"] {\n    guard let r = conn.query(\"SELECT COUNT(*) FROM \\(table) WHERE content_hash IS NULL\") else { continue }\n    let row = r.nextRow()\n    let unhashed = row?[0] as? Int ?? -1\n    guard let r2 = conn.query(\"SELECT COUNT(*) FROM \\(table)\") else { continue }\n    let row2 = r2.nextRow()\n    let totalRows = row2?[0] as? Int ?? 0\n    let status = unhashed == 0 ? \"OK\" : \"\\(unhashed) UNHASHED\"\n    print(\"  \\(table): \\(totalRows) rows — \\(status)\")\n}\n',2953,'e45da5ec30643585beda8754119f4e9e75950c9b52acf5a21c533cf80d5396a5','SHA256 backfill using CryptoKit (hardware accelerated on M1). Swift version that reads unhashed rows from MySQL, computes SHA256, batch updates.','SHA256,CryptoKit,Swift,MySQL,backfill,hardware-accelerated,M1','tool','2026-06-28 12:47:28','Devin session - treasure hunt','contestsystem',1,'Swift version of hash backfill. CryptoKit uses Apple hardware SHA extension. 95 lines total.','[@file<metal_hash_backfill.swift>][@state<active>][@date<2025-01-03>][@ver<1.0>][@auth<wws>]','[@auth<wws>][@role<sha256_backfill_swift>][@return<void>][@orch<cryptokit_mysql>][@no<print|hardcoded>]','/Users/wws/contestsystem/metal_hash_backfill.swift','SHA256 backfill using CryptoKit (hardware accelerated on M1). Swift version that reads unhashed rows from MySQL, computes SHA256, batch updates. 95 lines.',NULL,'IN',NULL,'[\"IN\"]','[\"COUNT(*)\", \"print(\\\"Remaining unhashed: \\\\(total)\", \"IN(\\\\(ids.map(String.init)\", \"for(id, hash)\", \"print(String(format: \\\"  %d/%d (%.1f%%)\", \"COUNT(*)\", \"COUNT(*)\"]','[\"COUNT->SELECT\", \"print->0\", \"IN->END WHERE id\", \"for->Fall back to individual updates\", \"print->100\", \"COUNT->SELECT\", \"COUNT->SELECT\"]',96,0,1,'e45da5ec30643585beda8754119f4e9e75950c9b52acf5a21c533cf80d5396a5','SWIFT_SOURCE','Swift source - requires swiftc to compile. Uses CryptoKit SHA256 (Apple hardware acceleration). MySQL connection via MySQL Swift package. Batch processing 1000 rows at a time. Batch UPDATE with CASE statement.','96 lines. CryptoKit SHA256.hash() uses Apple hardware SHA extension on M1. Batch size 1000. MySQL integration. Swift version of the C backfill tool.','Devin - treasure hunt session',NULL),(7,'GPT2 Metal Kernels','/Users/wws/Documents/MOVED_FROM_WAYNE_OLD_ACCOUNT/PRj_codex-notes/Ai_Wayne_Made/Sources/GPU/Kernels.metal','Metal',_binary '#include <metal_stdlib>\nusing namespace metal;\n\nkernel void matmul_kernel(\n    device const float* A [[buffer(0)]],\n    device const float* B [[buffer(1)]],\n    device float* C [[buffer(2)]],\n    constant int& inDim [[buffer(3)]],\n    constant int& outDim [[buffer(4)]],\n    uint id [[thread_position_in_grid]]\n) {\n    if (id >= outDim) return;\n    float sum = 0.0;\n    for (int i = 0; i < inDim; i++) {\n        sum += A[i] * B[i * outDim + id];\n    }\n    C[id] = sum;\n}\n\nkernel void relu_kernel(\n    device const float* x [[buffer(0)]],\n    device float* y [[buffer(1)]],\n    uint id [[thread_position_in_grid]]\n) {\n    y[id] = x[id] > 0 ? x[id] : 0;\n}\n\nkernel void silu_mul_kernel(\n    device const float* gate [[buffer(0)]],\n    device const float* up [[buffer(1)]],\n    device float* out [[buffer(2)]],\n    constant int& count [[buffer(3)]],\n    uint id [[thread_position_in_grid]]\n) {\n    if (id >= count) return;\n    float g = gate[id];\n    float silu = g / (1.0 + exp(-g));\n    out[id] = silu * up[id];\n}\n\nkernel void rms_norm_kernel(\n    device const float* x [[buffer(0)]],\n    device const float* scale [[buffer(1)]],\n    device float* out [[buffer(2)]],\n    constant int& count [[buffer(3)]],\n    constant float& eps [[buffer(4)]],\n    uint id [[thread_position_in_grid]]\n) {\n    if (id >= count) return;\n    float meanSq = 0.0;\n    for (int i = 0; i < count; i++) {\n        meanSq += x[i] * x[i];\n    }\n    meanSq /= float(count);\n    float denom = sqrt(meanSq + eps);\n    out[id] = (x[id] / denom) * scale[id];\n}\n\nkernel void attention_scores_kernel(\n    device const float* query [[buffer(0)]],\n    device const float* keys [[buffer(1)]],\n    device float* scores [[buffer(2)]],\n    constant int& headDim [[buffer(3)]],\n    constant int& seqLen [[buffer(4)]],\n    constant float& scale [[buffer(5)]],\n    uint id [[thread_position_in_grid]]\n) {\n    if (id >= seqLen) return;\n    float sum = 0.0;\n    int keyBase = int(id) * headDim;\n    for (int i = 0; i < headDim; i++) {\n        sum += query[i] * keys[keyBase + i];\n    }\n    scores[id] = sum * scale;\n}\n\nkernel void weighted_sum_kernel(\n    device const float* probs [[buffer(0)]],\n    device const float* values [[buffer(1)]],\n    device float* out [[buffer(2)]],\n    constant int& headDim [[buffer(3)]],\n    constant int& seqLen [[buffer(4)]],\n    uint id [[thread_position_in_grid]]\n) {\n    if (id >= headDim) return;\n    float sum = 0.0;\n    for (int pos = 0; pos < seqLen; pos++) {\n        sum += probs[pos] * values[pos * headDim + id];\n    }\n    out[id] = sum;\n}\n\nkernel void add_vec_kernel(\n    device const float* a [[buffer(0)]],\n    device const float* b [[buffer(1)]],\n    device float* out [[buffer(2)]],\n    constant int& count [[buffer(3)]],\n    uint id [[thread_position_in_grid]]\n) {\n    if (id >= count) return;\n    out[id] = a[id] + b[id];\n}\n\nkernel void softmax_kernel(\n    device const float* scores [[buffer(0)]],\n    device float* probs [[buffer(1)]],\n    constant int& count [[buffer(2)]],\n    uint id [[thread_position_in_grid]]\n) {\n    if (id >= count) return;\n    float maxVal = scores[0];\n    for (int i = 1; i < count; i++) {\n        maxVal = max(maxVal, scores[i]);\n    }\n    float sumExp = 0.0;\n    for (int i = 0; i < count; i++) {\n        sumExp += exp(scores[i] - maxVal);\n    }\n    probs[id] = sumExp > 0.0 ? exp(scores[id] - maxVal) / sumExp : 1.0 / float(max(count, 1));\n}\n',3377,'359f5af7513ff764c1ca6faed3794fc16b1c8a97119e100f800f80fbc0817892','Metal compute kernels for GPT2/LLM inference: matmul, relu, silu_mul, rms_norm, attention_scores, weighted_sum, add_vec, softmax. Uses thread_position_in_grid for parallel dispatch.','Metal,kernel,GPT2,LLM,matmul,attention,softmax,rms_norm,inference','metal-kernel','2026-06-28 12:47:28','Devin session - treasure hunt','Ai_Wayne_Made/Sources/GPU',1,'120 lines. Metal compute kernels for transformer inference. Shows the pattern for writing Metal compute shaders that could be adapted for hashing.','[@file<Kernels.metal>][@state<active>][@date<2025-01-03>][@ver<1.0>][@auth<wws>]','[@auth<wws>][@role<llm_metal_kernels>][@return<void>][@orch<gpu_compute>][@no<print|hardcoded>]','/Users/wws/Documents/MOVED_FROM_WAYNE_OLD_ACCOUNT/PRj_codex-notes/Ai_Wayne_Made/Sources/GPU/Kernels.metal','Metal compute kernels for GPT2/LLM inference: matmul, relu, silu_mul, rms_norm, attention_scores, weighted_sum, add_vec, softmax. Uses thread_position_in_grid for parallel dispatch. 120 lines.',NULL,'matmul_kernel, relu_kernel, silu_mul_kernel, rms_norm_kernel, attention_scores_kernel, weighted_sum_kernel, add_vec_kernel, softmax_kernel, matmul_kernel, relu_kernel, silu_mul_kernel, rms_norm_kernel, attention_scores_kernel, weighted_sum_kernel, add_vec_kernel, softmax_kernel',NULL,'[\"matmul_kernel\", \"relu_kernel\", \"silu_mul_kernel\", \"rms_norm_kernel\", \"attention_scores_kernel\", \"weighted_sum_kernel\", \"add_vec_kernel\", \"softmax_kernel\", \"matmul_kernel\", \"relu_kernel\", \"silu_mul_kernel\", \"rms_norm_kernel\", \"attention_scores_kernel\", \"weighted_sum_kernel\", \"add_vec_kernel\", \"softmax_kernel\"]','[\"matmul_kernel(device const float* A [[buffer(0)\", \"relu_kernel(device const float* x [[buffer(0)\", \"silu_mul_kernel(device const float* gate [[buffer(0)\", \"rms_norm_kernel(device const float* x [[buffer(0)\", \"attention_scores_kernel(device const float* query [[buffer(0)\", \"weighted_sum_kernel(device const float* probs [[buffer(0)\", \"add_vec_kernel(device const float* a [[buffer(0)\", \"softmax_kernel(device const float* scores [[buffer(0)\"]','[\"matmul_kernel->kernel void\", \"relu_kernel->kernel void\", \"silu_mul_kernel->kernel void\", \"rms_norm_kernel->kernel void\", \"attention_scores_kernel->kernel void\", \"weighted_sum_kernel->kernel void\", \"add_vec_kernel->kernel void\", \"softmax_kernel->kernel void\"]',121,0,16,'359f5af7513ff764c1ca6faed3794fc16b1c8a97119e100f800f80fbc0817892','METAL_KERNEL','Metal compute shaders - requires Metal framework and GPU. 8 kernels for transformer inference. Shows the pattern for writing Metal compute shaders that could be adapted for hashing. Each kernel uses thread_position_in_grid for parallel dispatch.','121 lines, 8 kernels: matmul_kernel, relu_kernel, silu_mul_kernel, rms_norm_kernel, attention_scores_kernel, weighted_sum_kernel, add_vec_kernel, softmax_kernel. Pattern: device buffers + thread_position_in_grid + parallel compute.','Devin - treasure hunt session',NULL),(8,'GPUPageCompressor - Metal + LZFSE + SQLite','/Users/wws/contestsystem/Sources/GPUPageCompressor/GPUPageCompressor.swift','Swift',_binary 'import Foundation\nimport Metal\nimport Compression\nimport SQLite3\nimport CryptoKit\n\nfinal class GPUPageCompressor {\n\n    let device: MTLDevice\n    let queue: MTLCommandQueue\n    var db: OpaquePointer?\n\n    let pageSize = 1024 * 1024\n    var pipeline: MTLComputePipelineState?\n\n    // MARK: INIT\n    init(dbPath: String) {\n\n        guard let dev = MTLCreateSystemDefaultDevice(),\n              let q = dev.makeCommandQueue() else {\n            fatalError(\"Metal not supported on this device\")\n        }\n\n        device = dev\n        queue = q\n\n        let rc = sqlite3_open(dbPath, &db)\n        if rc != SQLITE_OK {\n            fatalError(\"SQLite open failed\")\n        }\n\n        let sql = \"\"\"\n        PRAGMA journal_mode=WAL;\n\n        CREATE TABLE IF NOT EXISTS pages(\n            id INTEGER PRIMARY KEY,\n            hash TEXT,\n            raw_size INTEGER,\n            compressed_size INTEGER,\n            blob BLOB\n        );\n        \"\"\"\n\n        if sqlite3_exec(db, sql, nil, nil, nil) != SQLITE_OK {\n            print(\"SQLite init warning\")\n        }\n\n        setupMetal()\n    }\n\n    // MARK: METAL SETUP (SAFE)\n    func setupMetal() {\n\n        guard let lib = device.makeDefaultLibrary() else {\n            print(\"Metal library missing → GPU disabled\")\n            return\n        }\n\n        guard let kernel = lib.makeFunction(name: \"histogram_kernel\") else {\n            print(\"Kernel missing → GPU disabled\")\n            return\n        }\n\n        do {\n            pipeline = try device.makeComputePipelineState(function: kernel)\n        } catch {\n            print(\"Pipeline creation failed → GPU disabled\")\n            pipeline = nil\n        }\n    }\n\n    // MARK: FILE STREAM → PAGES\n    func compressFile(_ path: String) throws {\n\n        let handle = try FileHandle(forReadingFrom: URL(fileURLWithPath: path))\n        defer { try? handle.close() }\n\n        var index = 0\n\n        while true {\n\n            autoreleasepool {\n\n                let chunk = handle.readData(ofLength: pageSize)\n                if chunk.isEmpty { return }\n\n                let hash = SHA256.hash(data: chunk)\n                    .compactMap { String(format: \"%02x\", $0) }\n                    .joined()\n\n                let analyzed = gpuAnalyze(chunk)\n                let compressed = lzfseCompress(analyzed)\n\n                store(\n                    id: index,\n                    hash: hash,\n                    raw: chunk.count,\n                    compressed: compressed\n                )\n\n                index += 1\n            }\n        }\n    }\n\n    // MARK: GPU ANALYSIS (SAFE PATH)\n    func gpuAnalyze(_ data: Data) -> Data {\n\n        guard let pipeline else {\n            return data\n        }\n\n        guard let buffer = device.makeBuffer(bytes: [UInt8](data),\n                                             length: data.count) else {\n            return data\n        }\n\n        guard let histBuffer = device.makeBuffer(length: 256 * MemoryLayout<UInt32>.stride) else {\n            return data\n        }\n\n        guard let command = queue.makeCommandBuffer(),\n              let encoder = command.makeComputeCommandEncoder() else {\n            return data\n        }\n\n        encoder.setComputePipelineState(pipeline)\n        encoder.setBuffer(buffer, offset: 0, index: 0)\n        encoder.setBuffer(histBuffer, offset: 0, index: 1)\n\n        let grid = MTLSize(width: data.count, height: 1, depth: 1)\n\n        let tgSize = min(pipeline.maxTotalThreadsPerThreadgroup, 256)\n\n        let tg = MTLSize(width: tgSize, height: 1, depth: 1)\n\n        encoder.dispatchThreads(grid, threadsPerThreadgroup: tg)\n        encoder.endEncoding()\n\n        command.commit()\n        command.waitUntilCompleted()\n\n        // SAFE READ BACK\n        let ptr = histBuffer.contents().bindMemory(\n            to: UInt32.self,\n            capacity: 256\n        )\n\n        _ = Array(UnsafeBufferPointer(start: ptr, count: 256))\n\n        return data\n    }\n\n    // MARK: CPU COMPRESSION (SAFE LZFSE)\n    func lzfseCompress(_ data: Data) -> Data {\n\n        guard !data.isEmpty else { return data }\n\n        let dstCapacity = compression_encode_scratch_buffer_size(COMPRESSION_LZFSE)\n        let srcCount = data.count\n        let dstCount = data.count + dstCapacity\n\n        var dst = Data(count: dstCount)\n\n        let compressedSize = dst.withUnsafeMutableBytes { dstPtr in\n            data.withUnsafeBytes { srcPtr in\n                compression_encode_buffer(\n                    dstPtr.bindMemory(to: UInt8.self).baseAddress!,\n                    dstCount,\n                    srcPtr.bindMemory(to: UInt8.self).baseAddress!,\n                    srcCount,\n                    nil,\n                    COMPRESSION_LZFSE\n                )\n            }\n        }\n\n        guard compressedSize > 0 else { return data }\n\n        return dst.prefix(compressedSize)\n    }\n\n    // MARK: SQLITE STORE (SAFE)\n    func store(id: Int,\n               hash: String,\n               raw: Int,\n               compressed: Data) {\n\n        let sql = \"\"\"\n        INSERT INTO pages(hash, raw_size, compressed_size, blob)\n        VALUES(?,?,?,?)\n        \"\"\"\n\n        var stmt: OpaquePointer?\n\n        guard sqlite3_prepare_v2(db, sql, -1, &stmt, nil) == SQLITE_OK else {\n            print(\"SQL prepare failed\")\n            return\n        }\n\n        defer { sqlite3_finalize(stmt) }\n\n        sqlite3_bind_text(stmt, 1, hash, -1, nil)\n        sqlite3_bind_int(stmt, 2, Int32(raw))\n        sqlite3_bind_int(stmt, 3, Int32(compressed.count))\n\n        _ = compressed.withUnsafeBytes { buf in\n            sqlite3_bind_blob(stmt, 4,\n                              buf.baseAddress,\n                              Int32(compressed.count),\n                              nil)\n        }\n\n        if sqlite3_step(stmt) != SQLITE_DONE {\n            print(\"SQL insert failed\")\n        }\n    }\n}\n',5829,'3dd348697f93985fe35654147fc7c41ce241e2be11c8fd5e05689c8b991eead8','GPU page compressor that reads files in chunks, computes SHA256, runs GPU analysis (entropy/histogram), compresses with LZFSE, stores in SQLite. Combines hashing + GPU + compression + SQLite.','GPU,Metal,SHA256,LZFSE,SQLite,compression,CryptoKit,page,chunk','tool','2026-06-28 12:47:28','Devin session - treasure hunt','contestsystem/Sources/GPUPageCompressor',1,'Combines SHA256 hashing with GPU analysis and compression. Reads file in pageSize chunks, hashes each chunk, runs Metal GPU entropy analysis, compresses, stores in SQLite. This is the closest to the GPU hashing architecture.','[@file<GPUPageCompressor.swift>][@state<active>][@date<2025-01-03>][@ver<1.0>][@auth<wws>]','[@auth<wws>][@role<gpu_page_compressor>][@return<Data>][@orch<metal_lzfse_sqlite>][@no<print|hardcoded>]','/Users/wws/contestsystem/Sources/GPUPageCompressor/GPUPageCompressor.swift','GPU page compressor that reads files in chunks, computes SHA256, runs GPU analysis (entropy/histogram), compresses with LZFSE, stores in SQLite. Combines hashing + GPU + compression + SQLite. The closest to the GPU hashing architecture.','GPUPageCompressor','er, setupMetal, compressFile, gpuAnalyze, lzfseCompress, store','[\"GPUPageCompressor\"]','[\"er\", \"setupMetal\", \"compressFile\", \"gpuAnalyze\", \"lzfseCompress\", \"store\"]','[\"init(dbPath: String)\", \"pages(id INTEGER PRIMARY KEY,\\n            hash TEXT,\\n            raw_size INTEGER,\\n            compressed_size INTEGER,\\n            blob BLOB)\", \"sqlite3_exec(db, sql, nil, nil, nil)\", \"SETUP(SAFE)\", \"compressFile(_ path: String)\", \"FileHandle(forReadingFrom: URL(fileURLWithPath: path)\", \"ANALYSIS(SAFE PATH)\", \"gpuAnalyze(_ data: Data)\", \"COMPRESSION(SAFE LZFSE)\", \"lzfseCompress(_ data: Data)\", \"compression_encode_buffer(dstPtr.bindMemory(to: UInt8.self)\", \"STORE(SAFE)\", \"store(id: Int,\\n               hash: String,\\n               raw: Int,\\n               compressed: Data)\", \"pages(hash, raw_size, compressed_size, blob)\", \"sqlite3_prepare_v2(db, sql, -1, &stmt, nil)\", \"sqlite3_bind_blob(stmt, 4,\\n                              buf.baseAddress,\\n                              Int32(compressed.count)\", \"sqlite3_step(stmt)\"]','[\"init->INIT\", \"pages->CREATE TABLE IF NOT EXISTS\", \"sqlite3_exec->if\", \"SETUP->METAL\", \"setupMetal->func\", \"compressFile->PAGES\\n    func\", \"FileHandle->try\", \"ANALYSIS->GPU\", \"gpuAnalyze->func\", \"COMPRESSION->CPU\", \"lzfseCompress->func\", \"compression_encode_buffer->srcPtr in\", \"STORE->SQLITE\", \"store->func\", \"pages->INSERT INTO\", \"sqlite3_prepare_v2->guard\", \"sqlite3_bind_blob->buf in\", \"sqlite3_step->if\"]',219,1,6,'3dd348697f93985fe35654147fc7c41ce241e2be11c8fd5e05689c8b991eead8','SWIFT_SOURCE','Swift source - requires swiftc to compile. Combines: SHA256 hashing (CryptoKit), Metal GPU analysis (entropy/histogram), LZFSE compression, SQLite storage. Reads file in pageSize chunks. This is the closest existing code to the GPU hashing architecture described in ChatGPT conversation.','219 lines, 1 class (GPUPageCompressor), 6 methods: setupMetal, compressFile, gpuAnalyze, lzfseCompress, store, free. Combines SHA256 + GPU + compression + SQLite. Architecture: read chunk -> SHA256 hash -> GPU entropy analysis -> LZFSE compress -> SQLite store.','Devin - treasure hunt session',NULL),(9,'llama-model','/Users/Shared/VB_ai_Dec/CASCADE_MegaReporter_Project/asm_Egine/models/DDD/cpp/llama-model.cpp','C++',_binary '#include \"llama-model.h\"\n\n#include \"llama-impl.h\"\n#include \"llama-mmap.h\"\n#include \"llama-batch.h\"\n#include \"llama-cparams.h\"\n#include \"llama-model-loader.h\"\n\n#include \"llama-kv-cache.h\"\n#include \"llama-kv-cache-iswa.h\"\n#include \"llama-memory-hybrid.h\"\n#include \"llama-memory-recurrent.h\"\n\n#include \"ggml-cpp.h\"\n\n#include \"models/models.h\"\n\n#include <algorithm>\n#include <cassert>\n#include <cfloat>\n#include <cstring>\n#include <cmath>\n#include <functional>\n#include <map>\n#include <regex>\n#include <sstream>\n#include <stdexcept>\n\nconst char * llm_type_name(llm_type type) {\n    switch (type) {\n        case LLM_TYPE_14M:           return \"14M\";\n        case LLM_TYPE_17M:           return \"17M\";\n        case LLM_TYPE_22M:           return \"22M\";\n        case LLM_TYPE_33M:           return \"33M\";\n        case LLM_TYPE_60M:           return \"60M\";\n        case LLM_TYPE_70M:           return \"70M\";\n        case LLM_TYPE_80M:           return \"80M\";\n        case LLM_TYPE_109M:          return \"109M\";\n        case LLM_TYPE_137M:          return \"137M\";\n        case LLM_TYPE_140M:          return \"140M\";\n        case LLM_TYPE_160M:          return \"160M\";\n        case LLM_TYPE_190M:          return \"190M\";\n        case LLM_TYPE_220M:          return \"220M\";\n        case LLM_TYPE_250M:          return \"250M\";\n        case LLM_TYPE_256M:          return \"256M\";\n        case LLM_TYPE_270M:          return \"270M\";\n        case LLM_TYPE_335M:          return \"335M\";\n        case LLM_TYPE_350M:          return \"350M\";\n        case LLM_TYPE_360M:          return \"360M\";\n        case LLM_TYPE_410M:          return \"410M\";\n        case LLM_TYPE_450M:          return \"450M\";\n        case LLM_TYPE_475M:          return \"475M\";\n        case LLM_TYPE_558M:          return \"558M\";\n        case LLM_TYPE_700M:          return \"700M\";\n        case LLM_TYPE_770M:          return \"770M\";\n        case LLM_TYPE_780M:          return \"780M\";\n        case LLM_TYPE_950M:          return \"950M\";\n        case LLM_TYPE_0_3B:          return \"0.3B\";\n        case LLM_TYPE_0_5B:          return \"0.5B\";\n        case LLM_TYPE_0_6B:          return \"0.6B\";\n        case LLM_TYPE_1B:            return \"1B\";\n        case LLM_TYPE_1_2B:          return \"1.2B\";\n        case LLM_TYPE_1_3B:          return \"1.3B\";\n        case LLM_TYPE_1_4B:          return \"1.4B\";\n        case LLM_TYPE_1_5B:          return \"1.5B\";\n        case LLM_TYPE_1_6B:          return \"1.6B\";\n        case LLM_TYPE_1_7B:          return \"1.7B\";\n        case LLM_TYPE_1_8B:          return \"1.8B\";\n        case LLM_TYPE_2B:            return \"2B\";\n        case LLM_TYPE_2_6B:          return \"2.6B\";\n        case LLM_TYPE_2_8B:          return \"2.8B\";\n        case LLM_TYPE_2_9B:          return \"2.9B\";\n        case LLM_TYPE_3B:            return \"3B\";\n        case LLM_TYPE_4B:            return \"4B\";\n        case LLM_TYPE_6B:            return \"6B\";\n        case LLM_TYPE_6_9B:          return \"6.9B\";\n        case LLM_TYPE_7B:            return \"7B\";\n        case LLM_TYPE_8B:            return \"8B\";\n        case LLM_TYPE_9B:            return \"9B\";\n        case LLM_TYPE_11B:           return \"11B\";\n        case LLM_TYPE_12B:           return \"12B\";\n        case LLM_TYPE_13B:           return \"13B\";\n        case LLM_TYPE_14B:           return \"14B\";\n        case LLM_TYPE_15B:           return \"15B\";\n        case LLM_TYPE_16B:           return \"16B\";\n        case LLM_TYPE_20B:           return \"20B\";\n        case LLM_TYPE_26B:           return \"26B\";\n        case LLM_TYPE_27B:           return \"27B\";\n        case LLM_TYPE_30B:           return \"30B\";\n        case LLM_TYPE_32B:           return \"32B\";\n        case LLM_TYPE_34B:           return \"34B\";\n        case LLM_TYPE_35B:           return \"35B\";\n        case LLM_TYPE_36B:           return \"36B\";\n        case LLM_TYPE_40B:           return \"40B\";\n        case LLM_TYPE_65B:           return \"65B\";\n        case LLM_TYPE_70B:           return \"70B\";\n        case LLM_TYPE_120B:          return \"120B\";\n        case LLM_TYPE_142B:          return \"142B\";\n        case LLM_TYPE_236B:          return \"236B\";\n        case LLM_TYPE_290B:          return \"290B\";\n        case LLM_TYPE_314B:          return \"314B\";\n        case LLM_TYPE_405B:          return \"405B\";\n        case LLM_TYPE_671B:          return \"671B\";\n        case LLM_TYPE_SMALL:         return \"0.1B\";\n        case LLM_TYPE_MEDIUM:        return \"0.4B\";\n        case LLM_TYPE_LARGE:         return \"0.8B\";\n        case LLM_TYPE_XL:            return \"1.5B\";\n        case LLM_TYPE_A1_7B:         return \"A1.7B\";\n        case LLM_TYPE_A2_7B:         return \"A2.7B\";\n        case LLM_TYPE_8x7B:          return \"8x7B\";\n        case LLM_TYPE_8x22B:         return \"8x22B\";\n        case LLM_TYPE_16x12B:        return \"16x12B\";\n        case LLM_TYPE_16x3_8B:       return \"16x3.8B\";\n        case LLM_TYPE_10B_128x3_66B: return \"10B+128x3.66B\";\n        case LLM_TYPE_57B_A14B:      return \"57B.A14B\";\n        case LLM_TYPE_17B_16E:       return \"17Bx16E (Scout)\";\n        case LLM_TYPE_17B_128E:      return \"17Bx128E (Maverick)\";\n        case LLM_TYPE_A13B:          return \"A13B\";\n        case LLM_TYPE_7B_A1B:        return \"7B.A1B\";\n        case LLM_TYPE_8B_A1B:        return \"8B.A1B\";\n        case LLM_TYPE_16B_A1B:       return \"16B.A1B\";\n        case LLM_TYPE_21B_A3B:       return \"21B.A3B\";\n        case LLM_TYPE_30B_A3B:       return \"30B.A3B\";\n        case LLM_TYPE_100B_A6B:      return \"100B.A6B\";\n        case LLM_TYPE_106B_A12B:     return \"106B.A12B\";\n        case LLM_TYPE_230B_A10B:     return \"230B.A10B\";\n        case LLM_TYPE_235B_A22B:     return \"235B.A22B\";\n        case LLM_TYPE_300B_A47B:     return \"300B.A47B\";\n        case LLM_TYPE_355B_A32B:     return \"355B.A32B\";\n        case LLM_TYPE_E2B:           return \"E2B\";\n        case LLM_TYPE_E4B:           return \"E4B\";\n        default:                     return \"?B\";\n    }\n}\n\nstatic const char * llama_expert_gating_func_name(llama_expert_gating_func_type type) {\n    switch (type) {\n        case LLAMA_EXPERT_GATING_FUNC_TYPE_SOFTMAX: return \"softmax\";\n        case LLAMA_EXPERT_GATING_FUNC_TYPE_SIGMOID: return \"sigmoid\";\n        default:                                    return \"unknown\";\n    }\n}\n\nstatic const std::map<llama_rope_scaling_type, const char *> LLAMA_ROPE_SCALING_TYPES = {\n    { LLAMA_ROPE_SCALING_TYPE_NONE,       \"none\"       },\n    { LLAMA_ROPE_SCALING_TYPE_LINEAR,     \"linear\"     },\n    { LLAMA_ROPE_SCALING_TYPE_YARN,       \"yarn\"       },\n    { LLAMA_ROPE_SCALING_TYPE_LONGROPE,   \"longrope\"   },\n};\n\nstd::string llama_rope_scaling_type_name(llama_rope_scaling_type rope_scaling_type) {\n    return LLAMA_ROPE_SCALING_TYPES.at(rope_scaling_type);\n}\n\nstatic llama_rope_scaling_type llama_rope_scaling_type_from_string(const std::string & name) {\n    for (const auto & kv : LLAMA_ROPE_SCALING_TYPES) {\n        if (kv.second == name) {\n            return (llama_rope_scaling_type) kv.first;\n        }\n    }\n\n    return LLAMA_ROPE_SCALING_TYPE_UNSPECIFIED;\n}\n\n// checks if the weight tensor can be used with the specified buffer type and device\nstatic bool weight_buft_supported(const llama_hparams & hparams, ggml_tensor * w, ggml_op op, ggml_backend_buffer_type_t buft, ggml_backend_dev_t dev) {\n    GGML_ASSERT(w != nullptr);\n\n    if (op == GGML_OP_NONE) {\n        return true;\n    }\n\n    ggml_init_params params = {\n        /*.mem_size   =*/ ggml_tensor_overhead()*8,\n        /*.mem_buffer =*/ NULL,\n        /*.no_alloc   =*/ true,\n    };\n    ggml_context_ptr ctx_ptr { ggml_init(params) };\n    if (!ctx_ptr) {\n        throw std::runtime_error(format(\"failed to create ggml context\"));\n    }\n    ggml_context * ctx = ctx_ptr.get();\n\n    ggml_tensor * op_tensor = nullptr;\n\n    switch (op) {\n        case GGML_OP_GET_ROWS:\n            {\n                ggml_tensor * b = ggml_new_tensor_1d(ctx, GGML_TYPE_I32, 512);\n                op_tensor = ggml_get_rows(ctx, w, b);\n            } break;\n        case GGML_OP_MUL_MAT:\n            {\n                ggml_tensor * b = ggml_new_tensor_4d(ctx, GGML_TYPE_F32, w->ne[0], 512, w->ne[2], w->ne[3]);\n                op_tensor = ggml_mul_mat(ctx, w, b);\n            } break;\n        case GGML_OP_MUL_MAT_ID:\n            {\n                int n_expert_used = hparams.n_expert_used;\n                ggml_tensor * b = ggml_new_tensor_3d(ctx, GGML_TYPE_F32, w->ne[0], n_expert_used, 512);\n                ggml_tensor * ids = ggml_new_tensor_2d(ctx, GGML_TYPE_I32, n_expert_used, 512);\n                op_tensor = ggml_mul_mat_id(ctx, w, b, ids);\n            } break;\n        case GGML_OP_ADD:\n            {\n                ggml_tensor * a = ggml_new_tensor_4d(ctx, GGML_TYPE_F32, w->ne[0], w->ne[1], w->ne[2], w->ne[3]);\n                op_tensor = ggml_add(ctx, a, w);\n            } break;\n        case GGML_OP_ADD_ID:\n            {\n                int n_expert_used = hparams.n_expert_used;\n                ggml_tensor * a = ggml_new_tensor_3d(ctx, GGML_TYPE_F32, w->ne[0], n_expert_used, 512);\n                ggml_tensor * c = ggml_new_tensor_2d(ctx, GGML_TYPE_I32, n_expert_used, 512);\n                op_tensor = ggml_add_id(ctx, a, w, c);\n            } break;\n        case GGML_OP_MUL:\n            {\n                ggml_tensor * a = ggml_new_tensor_4d(ctx, GGML_TYPE_F32, w->ne[0], w->ne[1], w->ne[2], w->ne[3]);\n                op_tensor = ggml_mul(ctx, a, w);\n            } break;\n        case GGML_OP_DIV:\n            {\n                ggml_tensor * a = ggml_new_tensor_1d(ctx, GGML_TYPE_F32, w->ne[0]);\n                op_tensor = ggml_div(ctx, a, w);\n            } break;\n        case GGML_OP_ROPE:\n            {\n                int n_embd_head = hparams.n_embd_head_v;\n                int n_head = hparams.n_head();\n                ggml_tensor * a = ggml_new_tensor_3d(ctx, GGML_TYPE_F32, n_embd_head, n_head, 512);\n                ggml_tensor * b = ggml_new_tensor_1d(ctx, GGML_TYPE_I32, 512);\n                op_tensor = ggml_rope_ext(\n                    ctx, a, b, w,\n                    0, 0, 0, 0, 0,\n                    0, 0, 0, 0\n                );\n\n            } break;\n        case GGML_OP_SSM_CONV:\n            {\n                const int64_t n_seq_tokens = 512;\n                const int64_t n_seqs       = 3;\n                ggml_tensor * conv_x = ggml_new_tensor_3d(ctx, GGML_TYPE_F32, w->ne[0] - 1 + n_seq_tokens, w->ne[1], n_seqs);\n                op_tensor = ggml_ssm_conv(ctx, conv_x, w);\n            } break;\n        case GGML_OP_SSM_SCAN:\n            {\n                // w is ssm_a, which is used to distinguish Mamba-1 and Mamba-2\n                const int64_t d_state      = w->ne[0] == 1 ? hparams.ssm_d_state : w->ne[0];\n                const int64_t n_head       = w->ne[1];\n                const int64_t head_dim     = hparams.ssm_d_inner / n_head;\n                const int64_t n_group      = hparams.ssm_n_group ? hparams.ssm_n_group : 1;\n                const int64_t n_seq_tokens = 512;\n                const int64_t n_seqs       = 3;\n                ggml_tensor * s   = ggml_new_tensor_4d(ctx, GGML_TYPE_F32, d_state, head_dim, n_head, n_seqs);\n                ggml_tensor * x   = ggml_new_tensor_4d(ctx, GGML_TYPE_F32, head_dim, n_head, n_seq_tokens, n_seqs);\n                ggml_tensor * dt  = ggml_new_tensor_3d(ctx, GGML_TYPE_F32, n_head, n_seq_tokens, n_seqs);\n                ggml_tensor * B   = ggml_new_tensor_4d(ctx, GGML_TYPE_F32, d_state, n_group, n_seq_tokens, n_seqs);\n                ggml_tensor * C   = ggml_new_tensor_4d(ctx, GGML_TYPE_F32, d_state, n_group, n_seq_tokens, n_seqs);\n                ggml_tensor * ids = ggml_new_tensor_1d(ctx, GGML_TYPE_I32, n_seqs);\n                op_tensor = ggml_ssm_scan(ctx, s, x, dt, w, B, C, ids);\n            } break;\n        case GGML_OP_RWKV_WKV6:\n            {\n                // FIXME\n                const int64_t S = 123;\n                const int64_t H = 123;\n                const int64_t n_tokens = 123;\n                const int64_t n_seqs = 123;\n                ggml_tensor  * k = ggml_new_tensor_3d(ctx, GGML_TYPE_F32, S, H, n_tokens);\n                ggml_tensor  * v = ggml_new_tensor_3d(ctx, GGML_TYPE_F32, S, H, n_tokens);\n                ggml_tensor  * r = ggml_new_tensor_3d(ctx, GGML_TYPE_F32, S, H, n_tokens);\n                ggml_tensor  * tf = w;\n                ggml_tensor  * td = ggml_new_tensor_3d(ctx, GGML_TYPE_F32, S, H, n_tokens);\n                ggml_tensor  * state = ggml_new_tensor_4d(ctx, GGML_TYPE_F32, S, n_seqs, S, H);\n                op_tensor = ggml_rwkv_wkv6(ctx, k, v, r, tf, td, state);\n            } break;\n        case GGML_OP_IM2COL:\n            {\n                const int n_embd_inp = hparams.n_embd_inp();\n                ggml_tensor * b = ggml_new_tensor_4d(ctx, GGML_TYPE_F32, n_embd_inp, w->ne[1], 1, 1);\n                op_tensor = ggml_im2col(ctx, w, b, 1, 0, 0, 0, 1, 0, false, GGML_TYPE_F16);\n            } break;\n        case GGML_OP_SCALE:\n            {\n                op_tensor = ggml_scale(ctx, w, 1.0f);\n            } break;\n        default:\n            GGML_ABORT(\"%s: missing test for op %s for tensor %s\", __func__, ggml_op_name(op), w->name);\n    }\n\n    // create a temporary dummy buffer for the weight so that supports_op can check the buffer type\n    GGML_ASSERT(w->buffer == nullptr);\n    w->buffer = ggml_backend_buft_alloc_buffer(buft, 0);\n    bool op_supported = ggml_backend_dev_supports_op(dev, op_tensor);\n    ggml_backend_buffer_free(w->buffer);\n    w->buffer = nullptr;\n\n    return op_supported;\n}\n\n// lists of buffer types used for each layer\nusing buft_list_t = std::vector<std::pair<ggml_backend_dev_t, ggml_backend_buffer_type_t>>;\n\n// find the first buffer type in the list that can use the tensor\nstatic ggml_backend_buffer_type_t select_weight_buft(const llama_hparams & hparams, ggml_tensor * tensor, ggml_op op, const buft_list_t & buft_list) {\n    GGML_ASSERT(!buft_list.empty());\n    for (const auto & cur : buft_list) {\n        ggml_backend_dev_t cur_dev = cur.first;\n        ggml_backend_buffer_type_t cur_buft = cur.second;\n        if (weight_buft_supported(hparams, tensor, op, cur_buft, cur_dev)) {\n            return cur_buft;\n        }\n    }\n\n    return nullptr;\n}\n\n// CPU: ACCEL -> GPU host -> CPU extra -> CPU\nstatic buft_list_t make_cpu_buft_list(const std::vector<ggml_backend_dev_t> & devices, bool use_extra_bufts, bool no_host) {\n    buft_list_t buft_list;\n\n    // add ACCEL buffer types\n    for (size_t i = 0; i < ggml_backend_dev_count(); ++i) {\n        ggml_backend_dev_t dev = ggml_backend_dev_get(i);\n        if (ggml_backend_dev_type(dev) == GGML_BACKEND_DEVICE_TYPE_ACCEL) {\n            auto * buft = ggml_backend_dev_buffer_type(dev);\n            // skip\n            if (buft != ggml_backend_cpu_buffer_type()) {\n                buft_list.emplace_back(dev, buft);\n            }\n        }\n    }\n\n    // add a host buffer type\n    // storing the tensors in a host buffer is useful when the processing of large batches\n    // is offloaded to a GPU device, since it reduces the time spent on data transfers\n    // generally, this will be done using the first device in the list\n    // a better approach would be to handle this on a weight-by-weight basis using the offload_op\n    // function of the device to determine if it would benefit from being stored in a host buffer\n    if (!no_host) {\n        for (auto * dev : devices) {\n            ggml_backend_buffer_type_t buft = ggml_backend_dev_host_buffer_type(dev);\n            if (buft) {\n                buft_list.emplace_back(dev, buft);\n                break;\n            }\n        }\n    }\n\n    // add extra buffer types\n    if (use_extra_bufts) {\n        auto * cpu_dev = ggml_backend_dev_by_type(GGML_BACKEND_DEVICE_TYPE_CPU);\n        if (cpu_dev == nullptr) {\n            throw std::runtime_error(format(\"%s: no CPU backend found\", __func__));\n        }\n\n        auto * cpu_reg = ggml_backend_dev_backend_reg(cpu_dev);\n        auto ggml_backend_dev_get_extra_bufts_fn = (ggml_backend_dev_get_extra_bufts_t)\n            ggml_backend_reg_get_proc_address(cpu_reg, \"ggml_backend_dev_get_extra_bufts\");\n        if (ggml_backend_dev_get_extra_bufts_fn) {\n            ggml_backend_buffer_type_t * extra_bufts = ggml_backend_dev_get_extra_bufts_fn(cpu_dev);\n            while (extra_bufts && *extra_bufts) {\n                buft_list.emplace_back(cpu_dev, *extra_bufts);\n                ++extra_bufts;\n            }\n        }\n    }\n\n    // add the CPU buffer type\n    for (size_t i = 0; i < ggml_backend_dev_count(); ++i) {\n        ggml_backend_dev_t dev = ggml_backend_dev_get(i);\n        if (ggml_backend_dev_type(dev) == GGML_BACKEND_DEVICE_TYPE_CPU) {\n            buft_list.emplace_back(dev, ggml_backend_dev_buffer_type(dev));\n        }\n    }\n\n    return buft_list;\n}\n\n// GPU: split if LLAMA_SPLIT_MODE_ROW -> GPU\nstatic buft_list_t make_gpu_buft_list(ggml_backend_dev_t dev, llama_split_mode split_mode, const float * tensor_split) {\n    buft_list_t buft_list;\n\n    // add the device split buffer type if requested and available\n    if (split_mode == LLAMA_SPLIT_MODE_ROW) {\n        ggml_backend_reg_t reg = ggml_backend_dev_backend_reg(dev);\n        auto ggml_backend_split_buffer_type_fn = (ggml_backend_split_buffer_type_t)\n            ggml_backend_reg_get_proc_address(reg, \"ggml_backend_split_buffer_type\");\n        if (ggml_backend_split_buffer_type_fn) {\n            size_t dev_index = [&]() {\n                auto * reg = ggml_backend_dev_backend_reg(dev);\n                for (size_t i = 0; i < ggml_backend_reg_dev_count(reg); ++i) {\n                    if (ggml_backend_reg_dev_get(reg, i) == dev) {\n                        return i;\n                    }\n                }\n                throw std::runtime_error(format(\"device %s not found in its backend reg\", ggml_backend_dev_name(dev)));\n            }();\n            auto * buft = ggml_backend_split_buffer_type_fn(dev_index, tensor_split);\n            if (buft != nullptr) {\n                buft_list.emplace_back(dev, buft);\n            }\n        }\n    }\n\n    // add the device default buffer type\n    buft_list.emplace_back(dev, ggml_backend_dev_buffer_type(dev));\n\n    // add the device extra buffer type (if any)\n    ggml_backend_reg_t reg = ggml_backend_dev_backend_reg(dev);\n    auto ggml_backend_dev_get_extra_bufts_fn = (ggml_backend_dev_get_extra_bufts_t)\n        ggml_backend_reg_get_proc_address(reg, \"ggml_backend_dev_get_extra_bufts\");\n\n    if (ggml_backend_dev_get_extra_bufts_fn) {\n        ggml_backend_buffer_type_t * extra_bufts = ggml_backend_dev_get_extra_bufts_fn(dev);\n        while (extra_bufts && *extra_bufts) {\n            buft_list.emplace_back(dev, *extra_bufts);\n            ++extra_bufts;\n        }\n    }\n\n    return buft_list;\n}\n\nstruct llama_model::impl {\n    impl() {}\n    ~impl() {}\n\n    uint64_t n_elements = 0;\n\n    size_t n_bytes = 0;\n\n    std::string desc_str;\n\n    // model memory mapped files\n    llama_mmaps mappings;\n\n    // objects representing data potentially being locked in memory\n    llama_mlocks mlock_bufs;\n    llama_mlocks mlock_mmaps;\n\n    // contexts where the model tensors metadata is stored as well ass the corresponding buffers:\n    std::vector<std::pair<ggml_context_ptr, std::vector<ggml_backend_buffer_ptr>>> ctxs_bufs;\n\n    buft_list_t cpu_buft_list;\n    std::map<ggml_backend_dev_t, buft_list_t> gpu_buft_list;\n\n    struct layer_dev {\n        ggml_backend_dev_t dev;\n        buft_list_t * buft_list;\n    };\n\n    layer_dev dev_input = {};\n    layer_dev dev_output = {};\n    std::vector<layer_dev> dev_layer;\n\n    bool has_tensor_overrides;\n};\n\nllama_model::llama_model(const llama_model_params & params) : params(params), pimpl(std::make_unique<impl>()) {\n    pimpl->has_tensor_overrides = params.tensor_buft_overrides && params.tensor_buft_overrides[0].pattern;\n}\n\nllama_model::~llama_model() {}\n\nvoid llama_model::load_stats(llama_model_loader & ml) {\n    pimpl->n_elements = ml.n_elements;\n    pimpl->n_bytes = ml.n_bytes;\n}\n\nvoid llama_model::load_arch(llama_model_loader & ml) {\n    arch = ml.get_arch();\n    if (arch == LLM_ARCH_UNKNOWN) {\n        throw std::runtime_error(\"unknown model architecture: \'\" + ml.get_arch_name() + \"\'\");\n    }\n}\n\nvoid llama_model::load_hparams(llama_model_loader & ml) {\n    const gguf_context * ctx = ml.meta.get();\n\n    // get metadata as string\n    for (int i = 0; i < gguf_get_n_kv(ctx); i++) {\n        gguf_type type = gguf_get_kv_type(ctx, i);\n        if (type == GGUF_TYPE_ARRAY) {\n            continue;\n        }\n        const char * name = gguf_get_key(ctx, i);\n        const std::string value = gguf_kv_to_str(ctx, i);\n        gguf_kv.emplace(name, value);\n    }\n\n    // get general kv\n    ml.get_key(LLM_KV_GENERAL_NAME, name, false);\n\n    // everything past this point is not vocab-related\n    // for CLIP models, we only need to load tensors, no hparams\n    if (hparams.vocab_only || ml.get_arch() == LLM_ARCH_CLIP) {\n        return;\n    }\n\n    ml.get_key(LLM_KV_CONTEXT_LENGTH,          hparams.n_ctx_train);\n    ml.get_key(LLM_KV_EMBEDDING_LENGTH,        hparams.n_embd);\n    ml.get_key(LLM_KV_BLOCK_COUNT,             hparams.n_layer);\n    ml.get_key(LLM_KV_EXPERT_COUNT,            hparams.n_expert,        false);\n    ml.get_key(LLM_KV_EXPERT_USED_COUNT,       hparams.n_expert_used,   false);\n    ml.get_key(LLM_KV_EXPERT_GROUP_COUNT,      hparams.n_expert_groups, false);\n    ml.get_key(LLM_KV_EXPERT_GROUP_USED_COUNT, hparams.n_group_used,    false);\n\n    if (arch == LLM_ARCH_WAVTOKENIZER_DEC) {\n        ml.get_key(LLM_KV_FEATURES_LENGTH, hparams.n_embd_features);\n\n        ml.get_key(LLM_KV_POSNET_EMBEDDING_LENGTH, hparams.posnet.n_embd);\n        ml.get_key(LLM_KV_POSNET_BLOCK_COUNT,      hparams.posnet.n_layer);\n\n        ml.get_key(LLM_KV_CONVNEXT_EMBEDDING_LENGTH, hparams.convnext.n_embd);\n        ml.get_key(LLM_KV_CONVNEXT_BLOCK_COUNT,      hparams.convnext.n_layer);\n    }\n\n    GGML_ASSERT(hparams.n_expert <= LLAMA_MAX_EXPERTS);\n    GGML_ASSERT(hparams.n_expert_used <= hparams.n_expert);\n    if (hparams.n_expert > 0) {\n        GGML_ASSERT(hparams.n_expert_used > 0);\n        GGML_ASSERT(hparams.n_expert_groups < hparams.n_expert);\n        if (hparams.n_expert_groups > 1) {\n            GGML_ASSERT(hparams.n_expert % hparams.n_expert_groups == 0);\n            GGML_ASSERT(hparams.n_group_used > 0);\n            GGML_ASSERT(hparams.n_group_used < hparams.n_expert_groups);\n        }\n    } else {\n        GGML_ASSERT(hparams.n_expert_used == 0);\n        GGML_ASSERT(hparams.n_expert_groups == 0);\n    }\n\n    std::fill(hparams.n_head_arr.begin(),    hparams.n_head_arr.end(),    0);\n    std::fill(hparams.n_head_kv_arr.begin(), hparams.n_head_kv_arr.end(), 0);\n    std::fill(hparams.n_ff_arr.begin(),      hparams.n_ff_arr.end(),      0);\n    std::fill(\n        hparams.recurrent_layer_arr.begin(),\n        hparams.recurrent_layer_arr.end(),\n        llm_arch_is_recurrent(ml.get_arch()));\n\n    std::fill(hparams.rope_sections.begin(), hparams.rope_sections.end(), 0);\n    std::fill(hparams.swa_layers.begin(), hparams.swa_layers.end(), 0);\n\n    std::fill(hparams.xielu_alpha_n.begin(), hparams.xielu_alpha_n.end(), 0.0f);\n    std::fill(hparams.xielu_alpha_p.begin(), hparams.xielu_alpha_p.end(), 0.0f);\n    std::fill(hparams.xielu_beta.begin(), hparams.xielu_beta.end(), 0.0f);\n    std::fill(hparams.xielu_eps.begin(), hparams.xielu_eps.end(), 0.0f);\n\n    ml.get_key_or_arr(LLM_KV_FEED_FORWARD_LENGTH,  hparams.n_ff_arr,   hparams.n_layer, false);\n    ml.get_key_or_arr(LLM_KV_ATTENTION_HEAD_COUNT, hparams.n_head_arr, hparams.n_layer, false);\n\n    // n_head_kv is optional, default to n_head\n    hparams.n_head_kv_arr = hparams.n_head_arr;\n\n    ml.get_key_or_arr(LLM_KV_ATTENTION_HEAD_COUNT_KV, hparams.n_head_kv_arr, hparams.n_layer, false);\n\n    bool rope_finetuned = false;\n    ml.get_key(LLM_KV_ROPE_SCALING_FINETUNED, rope_finetuned, false);\n    hparams.rope_finetuned = rope_finetuned;\n\n    hparams.n_ctx_orig_yarn = hparams.n_ctx_train;\n    ml.get_key(LLM_KV_ROPE_SCALING_ORIG_CTX_LEN, hparams.n_ctx_orig_yarn, false);\n\n    // rope_freq_base (optional)\n    hparams.rope_freq_base_train = 10000.0f;\n    ml.get_key(LLM_KV_ROPE_FREQ_BASE, hparams.rope_freq_base_train, false);\n\n    std::string rope_scaling(\"linear\");\n    ml.get_key(LLM_KV_ROPE_SCALING_TYPE, rope_scaling, false);\n    hparams.rope_scaling_type_train = llama_rope_scaling_type_from_string(rope_scaling);\n    GGML_ASSERT(hparams.rope_scaling_type_train != LLAMA_ROPE_SCALING_TYPE_UNSPECIFIED);\n\n    // rope_freq_scale (inverse of the kv) is optional\n    float ropescale = 0.0f;\n    if (!ml.get_key(LLM_KV_ROPE_SCALING_FACTOR, ropescale, false)) {\n        // try the old key name\n        ml.get_key(LLM_KV_ROPE_SCALE_LINEAR, ropescale, false);\n    }\n    hparams.rope_freq_scale_train = ropescale == 0.0f ? 1.0f : 1.0f/ropescale;\n\n    // by default assume that the sliding-window layers use the same scaling type as the non-sliding-window layers\n    hparams.rope_freq_base_train_swa  = hparams.rope_freq_base_train;\n    hparams.rope_freq_scale_train_swa = hparams.rope_freq_scale_train;\n\n    ml.get_key(LLM_KV_ROPE_SCALING_ATTN_FACTOR, hparams.rope_attn_factor, false);\n\n    // non-transformer models do not have attention heads\n    if (hparams.n_head() > 0) {\n        // gpt-neox n_rot = rotary_pct * (n_embd / n_head)\n        // gpt-j n_rot = rotary_dim\n\n        hparams.n_embd_head_k = hparams.n_embd / hparams.n_head();\n        ml.get_key(LLM_KV_ATTENTION_KEY_LENGTH, hparams.n_embd_head_k, false);\n\n        hparams.n_embd_head_v = hparams.n_embd / hparams.n_head();\n        ml.get_key(LLM_KV_ATTENTION_VALUE_LENGTH, hparams.n_embd_head_v, false);\n\n        // sanity check for n_rot (optional)\n        hparams.n_rot = hparams.n_embd_head_k;\n\n        ml.get_key(LLM_KV_ROPE_DIMENSION_COUNT, hparams.n_rot, false);\n\n        if (arch == LLM_ARCH_LLAMA || arch == LLM_ARCH_DECI || arch == LLM_ARCH_FALCON) {\n            if (hparams.n_rot != hparams.n_embd_head_k) {\n                throw std::runtime_error(format(\"invalid n_rot: %u, expected %u\", hparams.n_rot, hparams.n_embd_head_k));\n            }\n        }\n    } else {\n        hparams.n_rot = 0;\n        hparams.n_embd_head_k = 0;\n        hparams.n_embd_head_v = 0;\n    }\n\n    // for differentiating model types\n    uint32_t n_vocab = 0;\n    ml.get_key(LLM_KV_VOCAB_SIZE, n_vocab, false) || ml.get_arr_n(LLM_KV_TOKENIZER_LIST, n_vocab, false);\n\n    // for classifier models\n    ml.get_arr(LLM_KV_CLASSIFIER_OUTPUT_LABELS, classifier_labels, false);\n    if (!classifier_labels.empty()) {\n        hparams.n_cls_out = classifier_labels.size();\n    }\n\n    // arch-specific KVs\n    switch (arch) {\n        case LLM_ARCH_LLAMA:\n            {\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS, hparams.f_norm_rms_eps);\n\n                if (hparams.n_expert == 8) {\n                    switch (hparams.n_layer) {\n                        case 32: type = LLM_TYPE_8x7B; break;\n                        case 56: type = LLM_TYPE_8x22B; break;\n                        default: type = LLM_TYPE_UNKNOWN;\n                    }\n                } else {\n                    switch (hparams.n_layer) {\n                        case 16: type = LLM_TYPE_1B; break; // Llama 3.2 1B\n                        case 22: type = LLM_TYPE_1B; break;\n                        case 26: type = LLM_TYPE_3B; break;\n                        case 28: type = LLM_TYPE_3B; break; // Llama 3.2 3B\n                        case 30: type = LLM_TYPE_256M; break; // smoldocling 256M\n                        // granite uses a vocab with len 49152\n                        case 32: type = n_vocab == 49152 ? LLM_TYPE_3B : (n_vocab < 40000 ? LLM_TYPE_7B : LLM_TYPE_8B); break;\n                        case 36: type = LLM_TYPE_8B; break; // granite\n                        case 40: type = LLM_TYPE_13B; break;\n                        case 48: type = LLM_TYPE_34B; break;\n                        case 60: type = LLM_TYPE_30B; break;\n                        case 80: type = hparams.n_head() == hparams.n_head_kv() ? LLM_TYPE_65B : LLM_TYPE_70B; break;\n                        default: type = LLM_TYPE_UNKNOWN;\n                    }\n                }\n            } break;\n        case LLM_ARCH_LLAMA4:\n            {\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS, hparams.f_norm_rms_eps);\n                ml.get_key(LLM_KV_EXPERT_FEED_FORWARD_LENGTH,  hparams.n_ff_exp);\n                ml.get_key(LLM_KV_INTERLEAVE_MOE_LAYER_STEP,   hparams.n_moe_layer_step);\n\n                const bool found_swa = ml.get_key(LLM_KV_ATTENTION_SLIDING_WINDOW, hparams.n_swa, false);\n                if (found_swa && hparams.n_swa == 0) {\n                    hparams.swa_type             = LLAMA_SWA_TYPE_NONE;\n                    hparams.n_no_rope_layer_step = hparams.n_layer; // always use rope\n                } else {\n                    hparams.swa_type      = LLAMA_SWA_TYPE_CHUNKED;\n                    hparams.n_swa         = 8192;\n                    hparams.set_swa_pattern(4);   // pattern: 3 chunked - 1 full\n                }\n\n                switch (hparams.n_expert) {\n                    case 0: {\n                        // MobileLLM (no MoE)\n                        switch (hparams.n_embd) {\n                            case 2048: type = LLM_TYPE_140M; break;\n                            case 4096: type = LLM_TYPE_360M; break;\n                            case 6144: type = LLM_TYPE_950M; break;\n                            default:   type = LLM_TYPE_UNKNOWN;\n                        }\n                    } break;\n                    case 16:  type = LLM_TYPE_17B_16E; break;\n                    case 128: type = LLM_TYPE_17B_128E; break;\n                    default:  type = LLM_TYPE_UNKNOWN;\n                }\n\n                hparams.use_kq_norm = type != LLM_TYPE_17B_128E;\n            } break;\n        case LLM_ARCH_ARCEE:\n            {\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS, hparams.f_norm_rms_eps);\n\n                // Arcee uses the same structure as Llama\n                switch (hparams.n_layer) {\n                    case 36: type = LLM_TYPE_4B; break;\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n            } break;\n        case LLM_ARCH_AFMOE:\n            {\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS, hparams.f_norm_rms_eps);\n                ml.get_key(LLM_KV_LEADING_DENSE_BLOCK_COUNT,   hparams.n_layer_dense_lead);\n                ml.get_key(LLM_KV_EXPERT_FEED_FORWARD_LENGTH,  hparams.n_ff_exp);\n                ml.get_key(LLM_KV_EXPERT_SHARED_COUNT,         hparams.n_expert_shared);\n                ml.get_key(LLM_KV_EXPERT_GATING_FUNC,          hparams.expert_gating_func, false);\n                ml.get_key(LLM_KV_EXPERT_WEIGHTS_SCALE,        hparams.expert_weights_scale, false);\n                ml.get_key(LLM_KV_EXPERT_WEIGHTS_NORM,         hparams.expert_weights_norm, false);\n                ml.get_key(LLM_KV_ATTENTION_SLIDING_WINDOW,    hparams.n_swa, false);\n\n                // Set up interleaved sliding window attention (ISWA)\n                // Pattern: 3 sliding - 1 full (global_attn_every_n_layers = 4)\n                if (hparams.n_swa > 0) {\n                    hparams.swa_type = LLAMA_SWA_TYPE_STANDARD;\n                    hparams.set_swa_pattern(4);\n                } else {\n                    hparams.swa_type = LLAMA_SWA_TYPE_NONE;\n                }\n\n                // Default to sigmoid if not set\n                if (hparams.expert_gating_func == LLAMA_EXPERT_GATING_FUNC_TYPE_NONE) {\n                    hparams.expert_gating_func = LLAMA_EXPERT_GATING_FUNC_TYPE_SIGMOID;\n                }\n\n                switch (hparams.n_layer) {\n                    case 56: type = LLM_TYPE_6B; break;\n                    case 32: type = LLM_TYPE_26B; break;\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n            } break;\n        case LLM_ARCH_DECI:\n            {\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS, hparams.f_norm_rms_eps);\n                switch (hparams.n_layer) {\n                    case 32: type = LLM_TYPE_7B; break;\n                    case 80: type = LLM_TYPE_70B; break;\n                    case 162: type = LLM_TYPE_405B; break;\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n            } break;\n        case LLM_ARCH_MINICPM:\n            {\n                // Backward-compatible defaults for older MiniCPM GGUFs\n                hparams.f_embedding_scale = 12.0f;\n                hparams.f_residual_scale  = 1.4f / sqrtf(float(hparams.n_layer));\n                hparams.f_logit_scale     = hparams.n_embd ? (256.0f / float(hparams.n_embd)) : 1.0f;\n\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS, hparams.f_norm_rms_eps);\n\n                // Optional KV reads, override defaults if present in newer GGUF exports\n                ml.get_key(LLM_KV_EMBEDDING_SCALE, hparams.f_embedding_scale, /*required=*/false);\n                ml.get_key(LLM_KV_RESIDUAL_SCALE, hparams.f_residual_scale, /*required=*/false);\n                ml.get_key(LLM_KV_LOGIT_SCALE, hparams.f_logit_scale, /*required=*/false);\n\n                // MiniCPM uses rope by default, unlike Granite which uses it as a switch\n                hparams.rope_finetuned = true;\n\n                switch (hparams.n_layer) {\n                    case 52: type = LLM_TYPE_1B; break;\n                    case 40: type = LLM_TYPE_2B; break;\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n            } break;\n        case LLM_ARCH_MINICPM3:\n            {\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS, hparams.f_norm_rms_eps);\n                ml.get_key(LLM_KV_ATTENTION_Q_LORA_RANK,       hparams.n_lora_q);\n                ml.get_key(LLM_KV_ATTENTION_KV_LORA_RANK,      hparams.n_lora_kv);\n\n                switch (hparams.n_layer) {\n                    case 62: type = LLM_TYPE_4B; break;\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n            } break;\n        case LLM_ARCH_GROK:\n            {\n                // defaults for old GGUFs\n                hparams.yarn_beta_fast = 8.0f;\n                hparams.f_logit_scale = 0.5773502691896257f;\n                hparams.f_embedding_scale = 78.38367176906169f;\n                hparams.f_attn_out_scale = 0.08838834764831845f;\n                hparams.f_attn_logit_softcapping = 30.0f;\n                hparams.f_router_logit_softcapping = 30.0f;\n                // no final_logit_softcapping in grok-1\n                hparams.f_final_logit_softcapping = 0.0f;\n\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS,  hparams.f_norm_rms_eps);\n                ml.get_key(LLM_KV_EXPERT_FEED_FORWARD_LENGTH,   hparams.n_ff_exp, false);\n                ml.get_key(LLM_KV_LOGIT_SCALE,                  hparams.f_logit_scale, false);\n                ml.get_key(LLM_KV_EMBEDDING_SCALE,              hparams.f_embedding_scale, false);\n                ml.get_key(LLM_KV_ATTENTION_OUTPUT_SCALE,       hparams.f_attn_out_scale, false);\n                ml.get_key(LLM_KV_ATTN_LOGIT_SOFTCAPPING,       hparams.f_attn_logit_softcapping, false);\n                ml.get_key(LLM_KV_ROUTER_LOGIT_SOFTCAPPING,     hparams.f_router_logit_softcapping, false);\n                ml.get_key(LLM_KV_FINAL_LOGIT_SOFTCAPPING,      hparams.f_final_logit_softcapping, false);\n\n                ml.get_key(LLM_KV_ATTENTION_TEMPERATURE_LENGTH,  hparams.attn_temp_length, false);\n                ml.get_key(LLM_KV_ROPE_SCALING_YARN_EXT_FACTOR,  hparams.yarn_ext_factor, false);\n                ml.get_key(LLM_KV_ROPE_SCALING_YARN_ATTN_FACTOR, hparams.yarn_attn_factor, false);\n                ml.get_key(LLM_KV_ROPE_SCALING_YARN_BETA_FAST,   hparams.yarn_beta_fast, false);\n                ml.get_key(LLM_KV_ROPE_SCALING_YARN_BETA_SLOW,   hparams.yarn_beta_slow, false);\n\n                switch (hparams.n_layer) {\n                    case 64: type = LLM_TYPE_314B; break;\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n            } break;\n        case LLM_ARCH_FALCON:\n            {\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_EPS, hparams.f_norm_eps);\n\n                switch (hparams.n_layer) {\n                    case 32: type = LLM_TYPE_7B; break;\n                    case 60: type = LLM_TYPE_40B; break;\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n            } break;\n        case LLM_ARCH_BAICHUAN:\n            {\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS, hparams.f_norm_rms_eps);\n                switch (hparams.n_layer) {\n                    case 32: type = LLM_TYPE_7B; break;\n                    case 40: type = LLM_TYPE_13B; break;\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n\n                if (type == LLM_TYPE_13B) {\n                    // TODO: become GGUF KV parameter\n                    hparams.f_max_alibi_bias = 8.0f;\n                }\n            } break;\n        case LLM_ARCH_STARCODER:\n            {\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_EPS, hparams.f_norm_eps);\n                switch (hparams.n_layer) {\n                    case 24: type = LLM_TYPE_1B; break;\n                    case 36: type = LLM_TYPE_3B; break;\n                    case 42: type = LLM_TYPE_7B; break;\n                    case 40: type = LLM_TYPE_15B; break;\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n            } break;\n        case LLM_ARCH_REFACT:\n            {\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS, hparams.f_norm_rms_eps);\n                switch (hparams.n_layer) {\n                    case 32: type = LLM_TYPE_1B; break;\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n\n                // TODO: become GGUF KV parameter\n                hparams.f_max_alibi_bias = 8.0f;\n            } break;\n        case LLM_ARCH_BERT:\n            {\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_EPS,    hparams.f_norm_eps);\n                ml.get_key(LLM_KV_ATTENTION_CAUSAL,           hparams.causal_attn);\n                ml.get_key(LLM_KV_POOLING_TYPE,               hparams.pooling_type, false);\n\n                switch (hparams.n_layer) {\n                    case 3:\n                        type = LLM_TYPE_17M; break; // bge-micro\n                    case 6:\n                        type = LLM_TYPE_22M; break; // MiniLM-L6\n                    case 12:\n                        switch (hparams.n_embd) {\n                            case 384: type = LLM_TYPE_33M; break; // MiniLM-L12, bge-small\n                            case 768: type = LLM_TYPE_109M; break; // bge-base\n                            default: type = LLM_TYPE_UNKNOWN;\n                        } break;\n                    case 24:\n                        type = LLM_TYPE_335M; break; // bge-large\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n            } break;\n        case LLM_ARCH_JINA_BERT_V2:\n            {\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_EPS,    hparams.f_norm_eps);\n                ml.get_key(LLM_KV_ATTENTION_CAUSAL,           hparams.causal_attn);\n                ml.get_key(LLM_KV_POOLING_TYPE,               hparams.pooling_type, false);\n                hparams.f_max_alibi_bias = 8.0f;\n\n                switch (hparams.n_layer) {\n                    case 4:  type = LLM_TYPE_33M;  break; // jina-embeddings-small\n                    case 12: type = LLM_TYPE_137M; break; // jina-embeddings-base\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n            } break;\n        case LLM_ARCH_JINA_BERT_V3:\n            {\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_EPS,    hparams.f_norm_eps);\n                ml.get_key(LLM_KV_ATTENTION_CAUSAL,           hparams.causal_attn);\n                ml.get_key(LLM_KV_POOLING_TYPE,               hparams.pooling_type, false);\n\n                switch (hparams.n_layer) {\n                    case 24:\n                        type = LLM_TYPE_558M; break;\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n            } break;\n        case LLM_ARCH_NOMIC_BERT:\n        case LLM_ARCH_NOMIC_BERT_MOE:\n            {\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_EPS,    hparams.f_norm_eps);\n                ml.get_key(LLM_KV_ATTENTION_CAUSAL,           hparams.causal_attn);\n                ml.get_key(LLM_KV_POOLING_TYPE,               hparams.pooling_type);\n                ml.get_key(LLM_KV_MOE_EVERY_N_LAYERS,         hparams.moe_every_n_layers, 0);\n\n                if (hparams.n_layer == 12 && hparams.n_embd == 768) {\n                    if (arch == LLM_ARCH_NOMIC_BERT) {\n                        type = LLM_TYPE_137M;\n                    } else if (arch == LLM_ARCH_NOMIC_BERT_MOE && hparams.moe_every_n_layers == 2) {\n                        type = LLM_TYPE_475M;\n                    }\n                }\n            } break;\n        case LLM_ARCH_NEO_BERT:\n            {\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS, hparams.f_norm_rms_eps);\n                ml.get_key(LLM_KV_ATTENTION_CAUSAL,            hparams.causal_attn);\n                ml.get_key(LLM_KV_POOLING_TYPE,                hparams.pooling_type);\n\n                if (hparams.n_layer == 28) {\n                    type = LLM_TYPE_250M;\n                }\n            } break;\n        case LLM_ARCH_BLOOM:\n            {\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_EPS, hparams.f_norm_eps);\n\n                switch (hparams.n_layer) {\n                    case 24: type = LLM_TYPE_1B; break;\n                    case 30:\n                        switch (hparams.n_embd) {\n                            case 2560: type = LLM_TYPE_3B; break;\n                            case 4096: type = LLM_TYPE_7B; break;\n                            default: type = LLM_TYPE_UNKNOWN;\n                        } break;\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n\n                // TODO: become GGUF KV parameter\n                hparams.f_max_alibi_bias = 8.0f;\n            } break;\n        case LLM_ARCH_MPT:\n            {\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_EPS,  hparams.f_norm_eps);\n                ml.get_key(LLM_KV_ATTENTION_CLAMP_KQV,      hparams.f_clamp_kqv, false);\n                ml.get_key(LLM_KV_ATTENTION_MAX_ALIBI_BIAS, hparams.f_max_alibi_bias);\n\n                switch (hparams.n_layer) {\n                    case 32: type = LLM_TYPE_7B; break;\n                    case 48: type = LLM_TYPE_30B; break;\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n            } break;\n        case LLM_ARCH_STABLELM:\n            {\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_EPS, hparams.f_norm_eps);\n\n                switch (hparams.n_layer) {\n                    case 24: type = LLM_TYPE_1B; break;\n                    case 32: type = LLM_TYPE_3B; break;\n                    case 40: type = LLM_TYPE_12B; break;\n                    default: type = LLM_TYPE_UNKNOWN;\n               }\n            } break;\n        case LLM_ARCH_QWEN:\n            {\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS, hparams.f_norm_rms_eps);\n\n                switch (hparams.n_layer) {\n                    case 32: type = LLM_TYPE_7B; break;\n                    case 40: type = LLM_TYPE_13B; break;\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n            } break;\n        case LLM_ARCH_QWEN2VL:\n            {\n                ml.get_key_or_arr(LLM_KV_ROPE_DIMENSION_SECTIONS, hparams.rope_sections, 4, true);\n            }\n            // fall through\n        case LLM_ARCH_QWEN2:\n            {\n                ml.get_key(LLM_KV_POOLING_TYPE, hparams.pooling_type, false);\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS, hparams.f_norm_rms_eps);\n                switch (hparams.n_layer) {\n                    case 24: type = hparams.n_embd == 1024 ? LLM_TYPE_0_5B : LLM_TYPE_1B; break;\n                    case 28: type = hparams.n_embd == 1536 ? LLM_TYPE_1_5B : LLM_TYPE_7B; break;\n                    case 32: type = LLM_TYPE_7B; break;\n                    case 36: type = LLM_TYPE_3B; break;\n                    case 40: type = hparams.n_head() == 20 ? LLM_TYPE_4B : LLM_TYPE_13B; break;\n                    case 48: type = LLM_TYPE_14B; break;\n                    case 64: type = LLM_TYPE_32B; break;\n                    case 80: type = LLM_TYPE_70B; break;\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n            } break;\n        case LLM_ARCH_DREAM:\n            {\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS, hparams.f_norm_rms_eps);\n                // Dream models are primarily 7B with 28 layers\n                switch (hparams.n_layer) {\n                    case 28:\n                        type = LLM_TYPE_7B;\n                        break;\n                    default:\n                        type = LLM_TYPE_UNKNOWN;\n                }\n                // Set non-causal attention for diffusion models\n                hparams.causal_attn = false;\n            }\n            break;\n        case LLM_ARCH_LLADA:\n            {\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS, hparams.f_norm_rms_eps);\n                // LLaDA-8B has 32 layers, similar to LLaMA but for diffusion\n                switch (hparams.n_layer) {\n                    case 32:\n                        type = LLM_TYPE_8B;\n                        break;\n                    default:\n                        type = LLM_TYPE_UNKNOWN;\n                }\n                // Set non-causal attention for diffusion models\n                hparams.causal_attn = false;\n            }\n            break;\n        case LLM_ARCH_LLADA_MOE:\n            {\n                ml.get_key(LLM_KV_EXPERT_FEED_FORWARD_LENGTH, hparams.n_ff_exp, false);\n\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS, hparams.f_norm_rms_eps);\n                // diffusion language model uses non-causal attention\n                hparams.causal_attn = false;\n                switch (hparams.n_layer) {\n                    case 16: type = LLM_TYPE_A1_7B; break;\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n            } break;\n        case LLM_ARCH_RND1:\n            {\n                ml.get_key(LLM_KV_EXPERT_FEED_FORWARD_LENGTH, hparams.n_ff_exp, false);\n\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS, hparams.f_norm_rms_eps);\n                switch (hparams.n_layer) {\n                    case 48: type = LLM_TYPE_30B_A3B; break;\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n                // Set non-causal attention for diffusion models\n                hparams.causal_attn = false;\n            } break;\n        case LLM_ARCH_QWEN2MOE:\n            {\n                ml.get_key(LLM_KV_EXPERT_FEED_FORWARD_LENGTH,        hparams.n_ff_exp, false);\n                ml.get_key(LLM_KV_EXPERT_SHARED_FEED_FORWARD_LENGTH, hparams.n_ff_shexp, false);\n\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS, hparams.f_norm_rms_eps);\n                switch (hparams.n_layer) {\n                    case 24: type = LLM_TYPE_A2_7B; break;\n                    case 28: type = LLM_TYPE_57B_A14B; break;\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n            } break;\n        case LLM_ARCH_QWEN3:\n            {\n                ml.get_key(LLM_KV_POOLING_TYPE, hparams.pooling_type, false);\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS, hparams.f_norm_rms_eps);\n                switch (hparams.n_layer) {\n                    case 28: type = hparams.n_embd == 1024 ? LLM_TYPE_0_6B : LLM_TYPE_1_7B; break;\n                    case 36: type = hparams.n_embd == 2560 ? LLM_TYPE_4B : LLM_TYPE_8B; break;\n                    case 40: type = LLM_TYPE_14B; break;\n                    case 64: type = LLM_TYPE_32B; break;\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n            } break;\n        case LLM_ARCH_QWEN3VL:\n            {\n                ml.get_key(LLM_KV_NUM_DEEPSTACK_LAYERS, hparams.n_deepstack_layers, false);\n                ml.get_key_or_arr(LLM_KV_ROPE_DIMENSION_SECTIONS, hparams.rope_sections, 4, true);\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS, hparams.f_norm_rms_eps);\n                switch (hparams.n_layer) {\n                    case 28: type = LLM_TYPE_1_7B; break;\n                    case 36: type = hparams.n_embd == 2560 ? LLM_TYPE_4B : LLM_TYPE_8B; break;\n                    case 64: type = LLM_TYPE_32B; break;\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n            } break;\n        case LLM_ARCH_QWEN3MOE:\n            {\n                ml.get_key(LLM_KV_EXPERT_FEED_FORWARD_LENGTH,        hparams.n_ff_exp, false);\n\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS, hparams.f_norm_rms_eps);\n                switch (hparams.n_layer) {\n                    case 48: type = LLM_TYPE_30B_A3B; break;\n                    case 94: type = LLM_TYPE_235B_A22B; break;\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n            } break;\n        case LLM_ARCH_QWEN3VLMOE:\n            {\n                ml.get_key(LLM_KV_NUM_DEEPSTACK_LAYERS, hparams.n_deepstack_layers, false);\n                ml.get_key_or_arr(LLM_KV_ROPE_DIMENSION_SECTIONS, hparams.rope_sections, 4, true);\n                ml.get_key(LLM_KV_EXPERT_FEED_FORWARD_LENGTH, hparams.n_ff_exp, false);\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS, hparams.f_norm_rms_eps);\n                switch (hparams.n_layer) {\n                    case 48: type = LLM_TYPE_30B_A3B; break;\n                    case 94: type = LLM_TYPE_235B_A22B; break;\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n            } break;\n        case LLM_ARCH_PHI2:\n            {\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_EPS, hparams.f_norm_eps);\n\n                switch (hparams.n_layer) {\n                    case 24: type = LLM_TYPE_1B; break;\n                    case 32: type = LLM_TYPE_3B; break;\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n            } break;\n        case LLM_ARCH_PHI3:\n            {\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS, hparams.f_norm_rms_eps);\n\n                switch (hparams.n_layer) {\n                    case 24: type = LLM_TYPE_1B; break;\n                    case 32: type = LLM_TYPE_3B; break;\n                    case 40: type = LLM_TYPE_14B; break;\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n\n                const bool found_swa = ml.get_key(LLM_KV_ATTENTION_SLIDING_WINDOW, hparams.n_swa, false);\n\n                if (found_swa && hparams.n_swa > 0) {\n                    LLAMA_LOG_WARN(\"%s: Phi SWA is currently disabled - results might be suboptimal for some models (see %s)\\n\",\n                            __func__, \"https://github.com/ggml-org/llama.cpp/pull/13676\");\n\n                    // TODO: fix conversion scripts to correctly populate `n_swa` and `n_swa_pattern`\n                    hparams.swa_type = LLAMA_SWA_TYPE_NONE;\n\n                    hparams.n_swa         = 0;\n                    hparams.set_swa_pattern(1);\n                }\n            } break;\n        case LLM_ARCH_PHIMOE:\n            {\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS, hparams.f_norm_rms_eps);\n\n                switch (hparams.n_layer) {\n                    case 32: type = LLM_TYPE_16x3_8B; break;\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n            } break;\n        case LLM_ARCH_PLAMO:\n            {\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS, hparams.f_norm_rms_eps);\n\n                switch (hparams.n_layer) {\n                    case 40: type = LLM_TYPE_13B; break;\n                    default: type = LLM_TYPE_UNKNOWN;\n               }\n            } break;\n        case LLM_ARCH_PLAMO2:\n            {\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS, hparams.f_norm_rms_eps);\n\n                // Load Mamba SSM parameters\n                ml.get_key(LLM_KV_SSM_CONV_KERNEL,    hparams.ssm_d_conv);\n                ml.get_key(LLM_KV_SSM_INNER_SIZE,     hparams.ssm_d_inner);\n                ml.get_key(LLM_KV_SSM_STATE_SIZE,     hparams.ssm_d_state);\n                ml.get_key(LLM_KV_SSM_TIME_STEP_RANK, hparams.ssm_dt_rank);\n                ml.get_key(LLM_KV_SSM_GROUP_COUNT,    hparams.ssm_n_group);\n\n                for (uint32_t i = 0; i < hparams.n_layer; ++i) {\n                    hparams.recurrent_layer_arr[i] = hparams.n_head_kv(i) == 0;\n                }\n\n                switch (hparams.n_layer) {\n                    case 16: type = LLM_TYPE_1B; break;\n                    case 32:\n                        if (hparams.n_embd == 2048) {\n                            type = LLM_TYPE_2B;\n                        } else if (hparams.n_embd == 4096) {\n                            type = LLM_TYPE_8B;\n                        }\n                        break;\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n\n                // Load attention parameters\n                ml.get_key(LLM_KV_ATTENTION_KEY_LENGTH,   hparams.n_embd_head_k, false);\n                ml.get_key(LLM_KV_ATTENTION_VALUE_LENGTH, hparams.n_embd_head_v, false);\n            } break;\n        case LLM_ARCH_GPT2:\n            {\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_EPS, hparams.f_norm_eps);\n                switch (hparams.n_layer) {\n                    case 12: type = LLM_TYPE_SMALL; break;\n                    case 24: type = LLM_TYPE_MEDIUM; break;\n                    case 36: type = LLM_TYPE_LARGE; break;\n                    case 48: type = LLM_TYPE_XL; break;\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n            } break;\n        case LLM_ARCH_CODESHELL:\n            {\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_EPS, hparams.f_norm_eps);\n                switch (hparams.n_layer) {\n                    case 42: type = LLM_TYPE_7B; break;\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n            } break;\n        case LLM_ARCH_ORION:\n            {\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_EPS, hparams.f_norm_eps);\n\n                switch (hparams.n_layer) {\n                    case 40: type = LLM_TYPE_14B; break;\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n            } break;\n        case LLM_ARCH_INTERNLM2:\n            {\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS, hparams.f_norm_rms_eps);\n                switch (hparams.n_layer) {\n                    case 32: type = LLM_TYPE_7B; break;\n                    case 48: type = LLM_TYPE_20B; break;\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n            } break;\n        case LLM_ARCH_GEMMA:\n            {\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS, hparams.f_norm_rms_eps);\n\n                switch (hparams.n_layer) {\n                    case 18: type = LLM_TYPE_2B; break;\n                    case 28: type = LLM_TYPE_7B; break;\n                    default: type = LLM_TYPE_UNKNOWN;\n               }\n            } break;\n        case LLM_ARCH_GEMMA2:\n            {\n                hparams.swa_type = LLAMA_SWA_TYPE_STANDARD;\n                hparams.n_swa = 4096; // default value of gemma 2\n                hparams.set_swa_pattern(2);\n                hparams.attn_soft_cap = true;\n\n                ml.get_key(LLM_KV_ATTENTION_SLIDING_WINDOW,    hparams.n_swa, false);\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS, hparams.f_norm_rms_eps);\n                ml.get_key(LLM_KV_ATTN_LOGIT_SOFTCAPPING,      hparams.f_attn_logit_softcapping, false);\n                ml.get_key(LLM_KV_FINAL_LOGIT_SOFTCAPPING,     hparams.f_final_logit_softcapping, false);\n\n                switch (hparams.n_layer) {\n                    case 26: type = LLM_TYPE_2B; break;\n                    case 42: type = LLM_TYPE_9B; break;\n                    case 46: type = LLM_TYPE_27B; break;\n                    default: type = LLM_TYPE_UNKNOWN;\n               }\n\n                // ref: https://github.com/google/gemma_pytorch/blob/014acb7ac4563a5f77c76d7ff98f31b568c16508/gemma/config.py#L173\n                hparams.f_attention_scale = type == LLM_TYPE_27B\n                    ? 1.0f / std::sqrt(float(hparams.n_embd / hparams.n_head(0)))\n                    : 1.0f / std::sqrt(float(hparams.n_embd_head_k));\n            } break;\n        case LLM_ARCH_GEMMA3:\n            {\n                hparams.swa_type = LLAMA_SWA_TYPE_STANDARD;\n                hparams.set_swa_pattern(6);\n\n                hparams.rope_freq_base_train_swa  = 10000.0f;\n                hparams.rope_freq_scale_train_swa = 1.0f;\n\n                ml.get_key(LLM_KV_ATTENTION_SLIDING_WINDOW,    hparams.n_swa);\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS, hparams.f_norm_rms_eps);\n\n                switch (hparams.n_layer) {\n                    case 18: type = LLM_TYPE_270M; break;\n                    case 26: type = LLM_TYPE_1B; break;\n                    case 34: type = LLM_TYPE_4B; break;\n                    case 48: type = LLM_TYPE_12B; break;\n                    case 62: type = LLM_TYPE_27B; break;\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n\n                // ref: https://github.com/google/gemma_pytorch/blob/014acb7ac4563a5f77c76d7ff98f31b568c16508/gemma/config.py#L289\n                hparams.f_attention_scale = type == LLM_TYPE_27B\n                    ? 1.0f / std::sqrt(float(hparams.n_embd / hparams.n_head(0)))\n                    : 1.0f / std::sqrt(float(hparams.n_embd_head_k));\n            } break;\n        case LLM_ARCH_GEMMA3N:\n            {\n                hparams.swa_type = LLAMA_SWA_TYPE_STANDARD;\n                hparams.set_swa_pattern(5);\n\n                hparams.n_layer_kv_from_start     = 20;\n                hparams.rope_freq_base_train_swa  = 10000.0f;\n                hparams.rope_freq_scale_train_swa = 1.0f;\n                hparams.f_attention_scale         = 1.0f;\n\n                ml.get_key(LLM_KV_ATTENTION_SLIDING_WINDOW,    hparams.n_swa);\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS, hparams.f_norm_rms_eps);\n\n                switch (hparams.n_layer) {\n                    case 30: type = LLM_TYPE_E2B; break;\n                    case 35: type = LLM_TYPE_E4B; break;\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n            } break;\n        case LLM_ARCH_GEMMA_EMBEDDING:\n            {\n                hparams.swa_type = LLAMA_SWA_TYPE_SYMMETRIC;\n                hparams.set_swa_pattern(6);\n\n                hparams.causal_attn = false; // embeddings do not use causal attention\n                hparams.rope_freq_base_train_swa = 10000.0f;\n                hparams.rope_freq_scale_train_swa = 1.0f;\n\n                ml.get_key(LLM_KV_ATTENTION_SLIDING_WINDOW, hparams.n_swa);\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS, hparams.f_norm_rms_eps);\n                ml.get_key(LLM_KV_POOLING_TYPE, hparams.pooling_type);\n\n                //applied only if model converted with --sentence-transformers-dense-modules\n                ml.get_key(LLM_KV_DENSE_2_FEAT_IN, hparams.dense_2_feat_in, false);\n                ml.get_key(LLM_KV_DENSE_2_FEAT_OUT, hparams.dense_2_feat_out, false);\n                ml.get_key(LLM_KV_DENSE_3_FEAT_IN, hparams.dense_3_feat_in, false);\n                ml.get_key(LLM_KV_DENSE_3_FEAT_OUT, hparams.dense_3_feat_out, false);\n\n                GGML_ASSERT((hparams.dense_2_feat_in == 0 || hparams.dense_2_feat_in == hparams.n_embd) && \"dense_2_feat_in must be equal to n_embd\");\n                GGML_ASSERT((hparams.dense_3_feat_out == 0 || hparams.dense_3_feat_out == hparams.n_embd) && \"dense_3_feat_out must be equal to n_embd\");\n\n                switch (hparams.n_layer) {\n                    case 24: type = LLM_TYPE_0_3B; break;\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n                hparams.f_attention_scale = 1.0f / std::sqrt(float(hparams.n_embd_head_k));\n\n            } break;\n        case LLM_ARCH_STARCODER2:\n            {\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_EPS, hparams.f_norm_eps);\n                switch (hparams.n_layer) {\n                    case 30: type = LLM_TYPE_3B; break;\n                    case 32: type = LLM_TYPE_7B; break;\n                    case 40: type = LLM_TYPE_15B; break;\n                    case 52: type = LLM_TYPE_20B; break; // granite\n                    case 88: type = LLM_TYPE_34B; break; // granite\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n            } break;\n        case LLM_ARCH_MAMBA:\n            {\n                ml.get_key(LLM_KV_SSM_CONV_KERNEL,    hparams.ssm_d_conv);\n                ml.get_key(LLM_KV_SSM_INNER_SIZE,     hparams.ssm_d_inner);\n                ml.get_key(LLM_KV_SSM_STATE_SIZE,     hparams.ssm_d_state);\n                ml.get_key(LLM_KV_SSM_TIME_STEP_RANK, hparams.ssm_dt_rank);\n                ml.get_key(LLM_KV_SSM_DT_B_C_RMS,     hparams.ssm_dt_b_c_rms, false);\n\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS, hparams.f_norm_rms_eps);\n\n                switch (hparams.n_layer) {\n                    case 24:\n                        switch (hparams.n_embd) {\n                            case 768: type = LLM_TYPE_SMALL; break;\n                            default: type = LLM_TYPE_UNKNOWN;\n                        } break;\n                    case 48:\n                        switch (hparams.n_embd) {\n                            case 1024: type = LLM_TYPE_MEDIUM; break;\n                            case 1536: type = LLM_TYPE_LARGE; break;\n                            case 2048: type = LLM_TYPE_XL; break;\n                            default:   type = LLM_TYPE_UNKNOWN;\n                        } break;\n                    case 64:\n                        switch (hparams.n_embd) {\n                            case 2560: type = LLM_TYPE_3B; break;\n                            default: type = LLM_TYPE_UNKNOWN;\n                        } break;\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n            } break;\n        case LLM_ARCH_MAMBA2:\n            {\n                ml.get_key(LLM_KV_SSM_CONV_KERNEL,    hparams.ssm_d_conv);\n                ml.get_key(LLM_KV_SSM_INNER_SIZE,     hparams.ssm_d_inner);\n                ml.get_key(LLM_KV_SSM_STATE_SIZE,     hparams.ssm_d_state);\n                ml.get_key(LLM_KV_SSM_TIME_STEP_RANK, hparams.ssm_dt_rank);\n                ml.get_key(LLM_KV_SSM_GROUP_COUNT,    hparams.ssm_n_group);\n\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS, hparams.f_norm_rms_eps);\n\n                switch (hparams.n_layer) {\n                    case 24:\n                        switch (hparams.n_embd) {\n                            case 768: type = LLM_TYPE_SMALL; break;\n                            default: type = LLM_TYPE_UNKNOWN;\n                        } break;\n                    case 48:\n                        switch (hparams.n_embd) {\n                            case 1024: type = LLM_TYPE_MEDIUM; break;\n                            case 1536: type = LLM_TYPE_LARGE; break;\n                            case 2048: type = LLM_TYPE_XL; break;\n                            default: type = LLM_TYPE_UNKNOWN;\n                        } break;\n                    case 64:\n                        switch (hparams.n_embd) {\n                            case 2560: type = LLM_TYPE_3B; break;\n                            case 4096: type = LLM_TYPE_7B; break;\n                            default: type = LLM_TYPE_UNKNOWN;\n                        } break;\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n            } break;\n        case LLM_ARCH_JAMBA:\n            {\n                ml.get_key(LLM_KV_SSM_CONV_KERNEL,    hparams.ssm_d_conv);\n                ml.get_key(LLM_KV_SSM_INNER_SIZE,     hparams.ssm_d_inner);\n                ml.get_key(LLM_KV_SSM_STATE_SIZE,     hparams.ssm_d_state);\n                ml.get_key(LLM_KV_SSM_TIME_STEP_RANK, hparams.ssm_dt_rank);\n\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS, hparams.f_norm_rms_eps);\n\n                for (uint32_t i = 0; i < hparams.n_layer; ++i) {\n                    hparams.recurrent_layer_arr[i] = hparams.n_head_kv(i) == 0;\n                }\n\n                switch (hparams.n_layer) {\n                    // TODO: Jamba layers are a bit heterogenous, so naming this is hard.\n                    case 12: // 900M  8x???M\n                    case 32: // 51B  16x?B\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n            } break;\n        case LLM_ARCH_XVERSE:\n            {\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS, hparams.f_norm_rms_eps);\n                switch (hparams.n_layer) {\n                    case 32: type = LLM_TYPE_7B; break;\n                    case 40: type = LLM_TYPE_13B; break;\n                    case 80: type = LLM_TYPE_65B; break;\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n            } break;\n        case LLM_ARCH_COMMAND_R:\n            {\n                ml.get_key(LLM_KV_LOGIT_SCALE,             hparams.f_logit_scale);\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_EPS, hparams.f_norm_eps);\n                switch (hparams.n_layer) {\n                    case 40: type = LLM_TYPE_35B; break;\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n            } break;\n        case LLM_ARCH_COHERE2:\n            {\n                hparams.swa_type = LLAMA_SWA_TYPE_STANDARD;\n                hparams.set_swa_pattern(4);\n\n                ml.get_key(LLM_KV_ATTENTION_SLIDING_WINDOW, hparams.n_swa);\n                ml.get_key(LLM_KV_LOGIT_SCALE,              hparams.f_logit_scale);\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_EPS,  hparams.f_norm_eps);\n                switch (hparams.n_layer) {\n                    case 32: type = LLM_TYPE_8B; break;\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n            } break;\n        case LLM_ARCH_DBRX:\n        {\n            ml.get_key(LLM_KV_ATTENTION_LAYERNORM_EPS, hparams.f_norm_eps);\n            ml.get_key(LLM_KV_ATTENTION_CLAMP_KQV,     hparams.f_clamp_kqv);\n\n            switch (hparams.n_layer) {\n                case 40: type = LLM_TYPE_16x12B; break;\n                default: type = LLM_TYPE_UNKNOWN;\n            }\n        } break;\n        case LLM_ARCH_OLMO:\n            {\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_EPS, hparams.f_norm_eps);\n                ml.get_key(LLM_KV_ATTENTION_CLAMP_KQV,     hparams.f_clamp_kqv, false);\n\n                switch (hparams.n_layer) {\n                    case 22: type = LLM_TYPE_1B; break;\n                    case 32: type = LLM_TYPE_7B; break;\n                    case 80: type = LLM_TYPE_70B; break;\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n            } break;\n        case LLM_ARCH_OLMO2:\n            {\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS, hparams.f_norm_rms_eps);\n\n                const bool found_swa = ml.get_key(LLM_KV_ATTENTION_SLIDING_WINDOW, hparams.n_swa, false);\n                if (found_swa && hparams.n_swa > 0) {\n                    hparams.swa_type = LLAMA_SWA_TYPE_STANDARD;\n                    hparams.set_swa_pattern(4);\n                } else {\n                    hparams.swa_type = LLAMA_SWA_TYPE_NONE;\n                }\n\n                switch (hparams.n_layer) {\n                    case 16: type = LLM_TYPE_1B; break;\n                    case 32: type = LLM_TYPE_7B; break;\n                    case 40: type = LLM_TYPE_13B; break;\n                    case 64: type = LLM_TYPE_32B; break;\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n            } break;\n        case LLM_ARCH_SEED_OSS:\n            {\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS, hparams.f_norm_rms_eps);\n                switch (hparams.n_layer) {\n                    case 64: type = LLM_TYPE_36B; break;\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n            } break;\n        case LLM_ARCH_OLMOE:\n            {\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS, hparams.f_norm_rms_eps);\n                switch (hparams.n_layer) {\n                    case 16: type = LLM_TYPE_A1_7B; break;\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n            } break;\n        case LLM_ARCH_OPENELM:\n            {\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS, hparams.f_norm_rms_eps);\n\n                switch (hparams.n_layer) {\n                case 16: type = LLM_TYPE_270M; break;\n                case 20: type = LLM_TYPE_450M; break;\n                case 28: type = LLM_TYPE_1B; break;\n                case 36: type = LLM_TYPE_3B; break;\n                default: type = LLM_TYPE_UNKNOWN;\n                }\n            } break;\n        case LLM_ARCH_GPTNEOX:\n            {\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_EPS, hparams.f_norm_eps);\n                ml.get_key(LLM_KV_USE_PARALLEL_RESIDUAL,   hparams.use_par_res);\n                switch (hparams.n_layer) {\n                    case 6:\n                        switch (hparams.n_ff()) {\n                            case 512:  type = LLM_TYPE_14M; break;\n                            case 2048: type = LLM_TYPE_70M; break;\n                            default:   type = LLM_TYPE_UNKNOWN;\n                        } break;\n                    case 12:\n                        switch (hparams.n_ff()) {\n                            case 3072: type = LLM_TYPE_160M; break;\n                            default: type = LLM_TYPE_UNKNOWN;\n                        } break;\n                    case 16:\n                        switch (hparams.n_ff()) {\n                            case 8192: type = LLM_TYPE_1B; break;\n                            default: type = LLM_TYPE_UNKNOWN;\n                        } break;\n                    case 24:\n                        switch (hparams.n_ff()) {\n                            case 4096: type = LLM_TYPE_410M; break;\n                            case 8192: type = LLM_TYPE_1_4B; break;\n                            default: type = LLM_TYPE_UNKNOWN;\n                        } break;\n                    case 32:\n                        switch (hparams.n_ff()) {\n                            case 10240: type = LLM_TYPE_2_8B; break;\n                            case 16384: type = LLM_TYPE_6_9B; break;\n                            default: type = LLM_TYPE_UNKNOWN;\n                        } break;\n                    case 36:\n                        switch (hparams.n_ff()) {\n                            case 20480: type = LLM_TYPE_12B; break;\n                            default: type = LLM_TYPE_UNKNOWN;\n                        } break;\n                    case 44:\n                        switch (hparams.n_ff()) {\n                            case 24576: type = LLM_TYPE_20B; break;\n                            default: type = LLM_TYPE_UNKNOWN;\n                        } break;\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n            } break;\n        case LLM_ARCH_ARCTIC:\n            {\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS, hparams.f_norm_rms_eps);\n\n                if (hparams.n_expert == 128) {\n                    switch (hparams.n_layer) {\n                        case 35: type = LLM_TYPE_10B_128x3_66B; break;\n                        default: type = LLM_TYPE_UNKNOWN;\n                    }\n                } else {\n                    type = LLM_TYPE_UNKNOWN;\n                }\n            } break;\n        case LLM_ARCH_DEEPSEEK:\n            {\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS, hparams.f_norm_rms_eps);\n                ml.get_key(LLM_KV_LEADING_DENSE_BLOCK_COUNT,   hparams.n_layer_dense_lead);\n                ml.get_key(LLM_KV_EXPERT_FEED_FORWARD_LENGTH,  hparams.n_ff_exp);\n                ml.get_key(LLM_KV_EXPERT_SHARED_COUNT,         hparams.n_expert_shared);\n                ml.get_key(LLM_KV_EXPERT_WEIGHTS_SCALE,        hparams.expert_weights_scale);\n\n                switch (hparams.n_layer) {\n                    case 28: type = LLM_TYPE_20B; break;\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n            } break;\n        case LLM_ARCH_DEEPSEEK2:\n            {\n                // lite variants include DeepSeek-V2-Lite, GigaChat3-10B-A1.8B\n                bool is_lite = (hparams.n_layer == 27 || hparams.n_layer == 26);\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS, hparams.f_norm_rms_eps);\n                ml.get_key(LLM_KV_LEADING_DENSE_BLOCK_COUNT,   hparams.n_layer_dense_lead);\n                if (!is_lite) {\n                    ml.get_key(LLM_KV_ATTENTION_Q_LORA_RANK, hparams.n_lora_q);\n                }\n                ml.get_key(LLM_KV_ATTENTION_KV_LORA_RANK,     hparams.n_lora_kv);\n                ml.get_key(LLM_KV_ATTENTION_KEY_LENGTH_MLA,   hparams.n_embd_head_k_mla, false);\n                ml.get_key(LLM_KV_ATTENTION_VALUE_LENGTH_MLA, hparams.n_embd_head_v_mla, false);\n                ml.get_key(LLM_KV_EXPERT_FEED_FORWARD_LENGTH, hparams.n_ff_exp);\n                ml.get_key(LLM_KV_EXPERT_SHARED_COUNT,        hparams.n_expert_shared);\n                ml.get_key(LLM_KV_EXPERT_WEIGHTS_SCALE,       hparams.expert_weights_scale);\n                ml.get_key(LLM_KV_EXPERT_WEIGHTS_NORM,        hparams.expert_weights_norm, false);\n                ml.get_key(LLM_KV_EXPERT_GATING_FUNC,         hparams.expert_gating_func, false);\n                if (hparams.expert_gating_func == LLAMA_EXPERT_GATING_FUNC_TYPE_NONE) {\n                    // for compatibility with existing DeepSeek V2 and V2.5 GGUFs\n                    // that have no expert_gating_func model parameter set\n                    hparams.expert_gating_func = LLAMA_EXPERT_GATING_FUNC_TYPE_SOFTMAX;\n                }\n                ml.get_key(LLM_KV_ROPE_SCALING_YARN_LOG_MUL, hparams.rope_yarn_log_mul, false);\n\n                switch (hparams.n_layer) {\n                    case 27: type = LLM_TYPE_16B; break;\n                    case 60: type = LLM_TYPE_236B; break;\n                    case 61: type = LLM_TYPE_671B; break;\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n            } break;\n        case LLM_ARCH_PLM:\n            {\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS, hparams.f_norm_rms_eps);\n                ml.get_key(LLM_KV_ATTENTION_KV_LORA_RANK, hparams.n_lora_kv);\n                switch (hparams.n_layer) {\n                    case 32: type = LLM_TYPE_1_8B; break;\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n            } break;\n        case LLM_ARCH_CHATGLM:\n            {\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS, hparams.f_norm_rms_eps);\n                switch (hparams.n_layer) {\n                    case 28: {\n                        if (hparams.n_head(0) == 16) {\n                            type = LLM_TYPE_1_5B;\n                        } else {\n                            type = LLM_TYPE_6B;\n                        }\n                    } break;\n                    case 40: {\n                        if (hparams.n_head(0) == 24) {\n                            type = LLM_TYPE_4B;\n                        } else {\n                            type = LLM_TYPE_9B;\n                        }\n                    } break;\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n            } break;\n        case LLM_ARCH_GLM4:\n            {\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS, hparams.f_norm_rms_eps);\n                switch (hparams.n_layer) {\n                    case 40: type = LLM_TYPE_9B; break;\n                    case 61: type = LLM_TYPE_32B; break;\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n            } break;\n        case LLM_ARCH_GLM4_MOE:\n            {\n                ml.get_key(LLM_KV_EXPERT_FEED_FORWARD_LENGTH,  hparams.n_ff_exp);\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS, hparams.f_norm_rms_eps);\n\n                // MoE parameters\n                ml.get_key(LLM_KV_EXPERT_COUNT,                hparams.n_expert);\n                ml.get_key(LLM_KV_EXPERT_USED_COUNT,           hparams.n_expert_used);\n                ml.get_key(LLM_KV_EXPERT_SHARED_COUNT,         hparams.n_expert_shared);\n                ml.get_key(LLM_KV_LEADING_DENSE_BLOCK_COUNT,   hparams.n_layer_dense_lead, false);\n                ml.get_key(LLM_KV_EXPERT_WEIGHTS_SCALE,        hparams.expert_weights_scale);\n                ml.get_key(LLM_KV_EXPERT_WEIGHTS_NORM,         hparams.expert_weights_norm, false);\n\n                // Expert gating function (GLM-4.5 uses sigmoid)\n                ml.get_key(LLM_KV_EXPERT_GATING_FUNC,          hparams.expert_gating_func, false);\n                if (hparams.expert_gating_func == LLAMA_EXPERT_GATING_FUNC_TYPE_NONE) {\n                    hparams.expert_gating_func =  LLAMA_EXPERT_GATING_FUNC_TYPE_SIGMOID;\n                }\n\n                // NextN/MTP parameters\n                ml.get_key(LLM_KV_NEXTN_PREDICT_LAYERS,        hparams.nextn_predict_layers, false);\n\n                // TODO: when MTP is implemented, this should probably be updated if needed\n                hparams.n_layer_kv_from_start = hparams.n_layer - hparams.nextn_predict_layers;\n\n                switch (hparams.n_layer) {\n                    case 47: type = LLM_TYPE_106B_A12B; break; // GLM-4.5-Air (46 layers + 1 NextN layer)\n                    case 93: type = LLM_TYPE_355B_A32B; break; // GLM-4.5 (92 layers + 1 NextN layer)\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n            } break;\n        case LLM_ARCH_BITNET:\n            {\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS, hparams.f_norm_rms_eps);\n\n                switch (hparams.n_layer) {\n                    case 26: type = LLM_TYPE_3B; break;\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n            } break;\n        case LLM_ARCH_T5:\n            {\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS,      hparams.f_norm_rms_eps);\n                ml.get_key(LLM_KV_ATTENTION_RELATIVE_BUCKETS_COUNT, hparams.n_rel_attn_bkts);\n\n                uint32_t dec_start_token_id;\n                if (ml.get_key(LLM_KV_DECODER_START_TOKEN_ID, dec_start_token_id, false)) {\n                    hparams.dec_start_token_id = dec_start_token_id;\n                }\n\n                hparams.dec_n_layer = hparams.n_layer;\n                ml.get_key(LLM_KV_DECODER_BLOCK_COUNT, hparams.dec_n_layer, false);\n\n                switch (hparams.n_layer) {\n                    case 6:  type = LLM_TYPE_60M;  break; // t5-small\n                    case 8:  type = LLM_TYPE_80M;  break; // flan-t5-small\n                    case 12:\n                        switch (hparams.n_ff()) {\n                            case 3072: type = LLM_TYPE_220M; break; // t5-base\n                            case 2048: type = LLM_TYPE_250M; break; // flan-t5-base\n                            default: type = LLM_TYPE_UNKNOWN;\n                        } break;\n                    case 24:\n                        switch (hparams.n_ff()) {\n                            case 4096:  type = LLM_TYPE_770M; break; // t5-large\n                            case 2816:  type = LLM_TYPE_780M; break; // flan-t5-large\n                            case 16384: type = LLM_TYPE_3B;   break; // t5-3b\n                            case 5120:  type = LLM_TYPE_3B;   break; // flan-t5-xl\n                            case 65536: type = LLM_TYPE_11B;  break; // t5-11b\n                            case 10240: type = LLM_TYPE_11B;  break; // flan-t5-xxl\n                            default: type = LLM_TYPE_UNKNOWN;\n                        } break;\n                    default: type = LLM_TYPE_UNKNOWN;\n               }\n            } break;\n        case LLM_ARCH_T5ENCODER:\n            {\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS, hparams.f_norm_rms_eps);\n                ml.get_key(LLM_KV_ATTENTION_RELATIVE_BUCKETS_COUNT, hparams.n_rel_attn_bkts);\n                type = LLM_TYPE_UNKNOWN;\n            } break;\n        case LLM_ARCH_JAIS:\n            {\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_EPS, hparams.f_norm_eps);\n                ml.get_key(LLM_KV_ATTENTION_MAX_ALIBI_BIAS, hparams.f_max_alibi_bias);\n\n                switch (hparams.n_layer) {\n                    case 24: type = LLM_TYPE_1_3B; break;\n                    case 40: type = LLM_TYPE_13B; break;\n                    /* TODO: add variants */\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n            } break;\n        case LLM_ARCH_NEMOTRON:\n            {\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_EPS, hparams.f_norm_eps);\n                switch (hparams.n_layer) {\n                    case 32: type = LLM_TYPE_4B; break;\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n            } break;\n        case LLM_ARCH_NEMOTRON_H:\n            {\n                ml.get_key(LLM_KV_SSM_CONV_KERNEL,    hparams.ssm_d_conv);\n                ml.get_key(LLM_KV_SSM_INNER_SIZE,     hparams.ssm_d_inner);\n                ml.get_key(LLM_KV_SSM_STATE_SIZE,     hparams.ssm_d_state);\n                ml.get_key(LLM_KV_SSM_TIME_STEP_RANK, hparams.ssm_dt_rank);\n                ml.get_key(LLM_KV_SSM_GROUP_COUNT,    hparams.ssm_n_group);\n\n                // A layer is recurrent IFF the n_head_kv value is set to 0 and\n                // the n_ff value is set to 0\n                for (uint32_t i = 0; i < hparams.n_layer; ++i) {\n                    hparams.recurrent_layer_arr[i] = (hparams.n_head_kv(i) == 0 && hparams.n_ff(i) == 0);\n                }\n\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS, hparams.f_norm_rms_eps);\n\n                switch (hparams.n_layer) {\n                    case 56: type = LLM_TYPE_9B; break;\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n            } break;\n        case LLM_ARCH_EXAONE:\n            {\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS, hparams.f_norm_rms_eps);\n\n                switch (hparams.n_layer) {\n                    case 32: type = LLM_TYPE_8B; break;\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n            } break;\n        case LLM_ARCH_EXAONE4:\n            {\n                if (hparams.n_layer == 64) {    // 32B\n                    hparams.swa_type = LLAMA_SWA_TYPE_STANDARD;\n                    hparams.n_swa = 4096;\n                    hparams.set_swa_pattern(4);\n                }\n\n                ml.get_key(LLM_KV_ATTENTION_SLIDING_WINDOW,    hparams.n_swa, false);\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS, hparams.f_norm_rms_eps);\n\n                switch (hparams.n_layer) {\n                    case 30: type = LLM_TYPE_1_2B; break;\n                    case 64: type = LLM_TYPE_32B; break;\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n            } break;\n        case LLM_ARCH_RWKV6:\n        case LLM_ARCH_RWKV6QWEN2:\n            {\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_EPS,     hparams.f_norm_eps, false);\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS, hparams.f_norm_rms_eps, false);\n                ml.get_key(LLM_KV_WKV_HEAD_SIZE,               hparams.wkv_head_size);\n                ml.get_key(LLM_KV_TIME_MIX_EXTRA_DIM,          hparams.time_mix_extra_dim);\n                ml.get_key(LLM_KV_TIME_DECAY_EXTRA_DIM,        hparams.time_decay_extra_dim);\n                ml.get_key(LLM_KV_RESCALE_EVERY_N_LAYERS,      hparams.rescale_every_n_layers, false);\n                ml.get_key(LLM_KV_TOKEN_SHIFT_COUNT,           hparams.token_shift_count, false);\n\n                switch (hparams.n_layer) {\n                    case 24: type = LLM_TYPE_1_6B; break;\n                    case 32:\n                        switch (hparams.n_embd) {\n                            case 2560: type = LLM_TYPE_3B; break;\n                            case 4096: type = LLM_TYPE_7B; break;\n                            default: type = LLM_TYPE_UNKNOWN;\n                        } break;\n                    case 61: type = LLM_TYPE_14B; break;\n                    case 64: type = LLM_TYPE_32B; break;\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n            } break;\n        case LLM_ARCH_RWKV7:\n        case LLM_ARCH_ARWKV7:\n            {\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_EPS,                hparams.f_norm_eps, false);\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS,            hparams.f_norm_rms_eps, false);\n                ml.get_key(LLM_KV_WKV_HEAD_SIZE,                          hparams.wkv_head_size);\n                ml.get_key(LLM_KV_ATTENTION_DECAY_LORA_RANK,              hparams.n_lora_decay);\n                ml.get_key(LLM_KV_ATTENTION_ICLR_LORA_RANK,               hparams.n_lora_iclr);\n                ml.get_key(LLM_KV_ATTENTION_VALUE_RESIDUAL_MIX_LORA_RANK, hparams.n_lora_value_res_mix);\n                ml.get_key(LLM_KV_ATTENTION_GATE_LORA_RANK,               hparams.n_lora_gate, false);\n                ml.get_key(LLM_KV_TOKEN_SHIFT_COUNT,                      hparams.token_shift_count, false);\n\n                switch (hparams.n_layer) {\n                    case 12:\n                        switch (hparams.n_embd) {\n                            case 768: type = LLM_TYPE_190M; break;\n                            default: type = LLM_TYPE_UNKNOWN;\n                        } break;\n                    case 24:\n                        switch (hparams.n_embd) {\n                            case 1024: type = LLM_TYPE_450M; break;\n                            case 2048: type = LLM_TYPE_1_5B; break;\n                            default: type = LLM_TYPE_UNKNOWN;\n                        } break;\n                    case 28:\n                        switch (hparams.n_embd) {\n                            case 1536: type = LLM_TYPE_1_5B; break;\n                            case 3584: type = LLM_TYPE_7B; break;\n                            default: type = LLM_TYPE_UNKNOWN;\n                        } break;\n                    case 32:\n                        switch (hparams.n_embd) {\n                            case 2560: type = LLM_TYPE_2_9B; break;\n                            case 4096: type = LLM_TYPE_7B; break;\n                            default: type = LLM_TYPE_UNKNOWN;\n                        } break;\n                    case 61:\n                        switch (hparams.n_embd) {\n                            case 4096: type = LLM_TYPE_14B; break;\n                            default: type = LLM_TYPE_UNKNOWN;\n                        } break;\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n            } break;\n        case LLM_ARCH_GRANITE:\n        case LLM_ARCH_GRANITE_MOE:\n            {\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS, hparams.f_norm_rms_eps);\n                ml.get_key(LLM_KV_LOGIT_SCALE,                 hparams.f_logit_scale);\n                ml.get_key(LLM_KV_RESIDUAL_SCALE,              hparams.f_residual_scale);\n                ml.get_key(LLM_KV_EMBEDDING_SCALE,             hparams.f_embedding_scale);\n                ml.get_key(LLM_KV_ATTENTION_SCALE,             hparams.f_attention_scale);\n\n                // Granite uses rope_finetuned as a switch for rope, so default to true\n                bool rope_finetuned = true;\n                ml.get_key(LLM_KV_ROPE_SCALING_FINETUNED, rope_finetuned, false);\n                hparams.rope_finetuned = rope_finetuned;\n\n                switch (hparams.n_layer) {\n                    case 32: type = LLM_TYPE_3B; break;\n                    case 40: type = LLM_TYPE_3B; break;\n                    // Add additional layer/vocab/etc checks here for other model sizes\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n\n                // For Granite MoE Shared\n                ml.get_key(LLM_KV_EXPERT_SHARED_FEED_FORWARD_LENGTH, hparams.n_ff_shexp, /* required */ false);\n            } break;\n        case LLM_ARCH_GRANITE_HYBRID:\n            {\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS, hparams.f_norm_rms_eps);\n                ml.get_key(LLM_KV_LOGIT_SCALE,                 hparams.f_logit_scale, /* required */ false);\n                ml.get_key(LLM_KV_RESIDUAL_SCALE,              hparams.f_residual_scale, /* required */ false);\n                ml.get_key(LLM_KV_EMBEDDING_SCALE,             hparams.f_embedding_scale, /* required */ false);\n                ml.get_key(LLM_KV_ATTENTION_SCALE,             hparams.f_attention_scale, /* required */ false);\n\n                ml.get_key(LLM_KV_SSM_CONV_KERNEL,    hparams.ssm_d_conv);\n                ml.get_key(LLM_KV_SSM_INNER_SIZE,     hparams.ssm_d_inner);\n                ml.get_key(LLM_KV_SSM_STATE_SIZE,     hparams.ssm_d_state);\n                ml.get_key(LLM_KV_SSM_TIME_STEP_RANK, hparams.ssm_dt_rank);\n                ml.get_key(LLM_KV_SSM_GROUP_COUNT,    hparams.ssm_n_group);\n\n                // Granite uses rope_finetuned as a switch for rope, so default to true\n                bool rope_finetuned = true;\n                ml.get_key(LLM_KV_ROPE_SCALING_FINETUNED, rope_finetuned, false);\n                hparams.rope_finetuned = rope_finetuned;\n\n                // A layer is recurrent IFF the n_head_kv value is set to 0\n                for (uint32_t i = 0; i < hparams.n_layer; ++i) {\n                    hparams.recurrent_layer_arr[i] = hparams.n_head_kv(i) == 0;\n                }\n\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS, hparams.f_norm_rms_eps);\n\n                switch (hparams.n_embd) {\n                    case 768: type = LLM_TYPE_350M; break;\n                    case 1536: type = (hparams.n_embd == 2048 ? LLM_TYPE_7B_A1B : LLM_TYPE_1B); break;\n                    case 2048: case 2560: type = LLM_TYPE_3B; break;\n                    case 4096: type = LLM_TYPE_32B; break;\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n\n                // For Granite MoE Shared\n                ml.get_key(LLM_KV_EXPERT_SHARED_FEED_FORWARD_LENGTH, hparams.n_ff_shexp, /* required */ false);\n            } break;\n        case LLM_ARCH_CHAMELEON:\n            {\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS, hparams.f_norm_rms_eps);\n                hparams.f_norm_eps = 1e-5;  // eps for qk-norm, torch default\n                ml.get_key(LLM_KV_SWIN_NORM, hparams.swin_norm);\n\n                switch (hparams.n_layer) {\n                    case 32: type = LLM_TYPE_7B; break;\n                    case 48: type = LLM_TYPE_34B; break;\n                    default: type = LLM_TYPE_UNKNOWN;\n               }\n            } break;\n        case LLM_ARCH_WAVTOKENIZER_DEC:\n            {\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_EPS,    hparams.f_norm_eps);\n                ml.get_key(LLM_KV_ATTENTION_GROUPNORM_EPS,    hparams.f_norm_group_eps);\n                ml.get_key(LLM_KV_ATTENTION_GROUPNORM_GROUPS, hparams.n_norm_groups);\n                ml.get_key(LLM_KV_ATTENTION_CAUSAL,           hparams.causal_attn);\n            } break;\n        case LLM_ARCH_BAILINGMOE:\n            {\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS, hparams.f_norm_rms_eps);\n                ml.get_key(LLM_KV_LEADING_DENSE_BLOCK_COUNT,   hparams.n_layer_dense_lead);\n                ml.get_key(LLM_KV_EXPERT_FEED_FORWARD_LENGTH,  hparams.n_ff_exp);\n                ml.get_key(LLM_KV_EXPERT_SHARED_COUNT,         hparams.n_expert_shared);\n                ml.get_key(LLM_KV_EXPERT_WEIGHTS_SCALE,        hparams.expert_weights_scale);\n                ml.get_key(LLM_KV_EXPERT_WEIGHTS_NORM,         hparams.expert_weights_norm, false);\n\n                switch (hparams.n_layer) {\n                    case 28: type = LLM_TYPE_16B; break;\n                    case 88: type = LLM_TYPE_290B; break;\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n            } break;\n        case LLM_ARCH_BAILINGMOE2:\n            {\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS,       hparams.f_norm_rms_eps);\n                ml.get_key(LLM_KV_LEADING_DENSE_BLOCK_COUNT,         hparams.n_layer_dense_lead);\n                ml.get_key(LLM_KV_EXPERT_FEED_FORWARD_LENGTH,        hparams.n_ff_exp);\n                ml.get_key(LLM_KV_EXPERT_SHARED_FEED_FORWARD_LENGTH, hparams.n_ff_shexp);\n                ml.get_key(LLM_KV_EXPERT_SHARED_COUNT,               hparams.n_expert_shared);\n                ml.get_key(LLM_KV_EXPERT_WEIGHTS_SCALE,              hparams.expert_weights_scale);\n                ml.get_key(LLM_KV_EXPERT_WEIGHTS_NORM,               hparams.expert_weights_norm, false);\n                ml.get_key(LLM_KV_EXPERT_GATING_FUNC,                hparams.expert_gating_func);\n                ml.get_key(LLM_KV_NEXTN_PREDICT_LAYERS,              hparams.nextn_predict_layers, false);\n\n                // TODO: when MTP is implemented, this should probably be updated if needed\n                hparams.n_layer_kv_from_start = hparams.n_layer - hparams.nextn_predict_layers;\n\n                switch (hparams.n_layer) {\n                    case 20: type = LLM_TYPE_16B_A1B; break;\n                    case 21: type = LLM_TYPE_16B_A1B; break;\n                    case 32: type = LLM_TYPE_100B_A6B; break;\n                    case 33: type = LLM_TYPE_100B_A6B; break;\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n            } break;\n        case LLM_ARCH_DOTS1:\n            {\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS, hparams.f_norm_rms_eps);\n                ml.get_key(LLM_KV_LEADING_DENSE_BLOCK_COUNT,   hparams.n_layer_dense_lead);\n                ml.get_key(LLM_KV_EXPERT_FEED_FORWARD_LENGTH,  hparams.n_ff_exp);\n                ml.get_key(LLM_KV_EXPERT_SHARED_COUNT,         hparams.n_expert_shared);\n                ml.get_key(LLM_KV_EXPERT_WEIGHTS_SCALE,        hparams.expert_weights_scale);\n                ml.get_key(LLM_KV_EXPERT_WEIGHTS_NORM,         hparams.expert_weights_norm, false);\n                ml.get_key(LLM_KV_EXPERT_GATING_FUNC,          hparams.expert_gating_func, false);\n                switch (hparams.n_layer) {\n                    case 62: type = LLM_TYPE_142B; break;\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n            } break;\n        case LLM_ARCH_ERNIE4_5:\n        case LLM_ARCH_ERNIE4_5_MOE:\n            {\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS, hparams.f_norm_rms_eps);\n                if (arch == LLM_ARCH_ERNIE4_5_MOE) {\n                    ml.get_key(LLM_KV_EXPERT_FEED_FORWARD_LENGTH,        hparams.n_ff_exp);\n                    ml.get_key(LLM_KV_EXPERT_SHARED_FEED_FORWARD_LENGTH, hparams.n_ff_shexp, false);\n                    ml.get_key(LLM_KV_INTERLEAVE_MOE_LAYER_STEP,         hparams.n_moe_layer_step);\n                    ml.get_key(LLM_KV_LEADING_DENSE_BLOCK_COUNT,         hparams.n_layer_dense_lead);\n                }\n\n                switch (hparams.n_layer) {\n                    case 18: type = LLM_TYPE_0_3B; break;\n                    case 28: type = LLM_TYPE_21B_A3B; break;\n                    case 54: type = LLM_TYPE_300B_A47B; break;\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n            } break;\n        case LLM_ARCH_FALCON_H1:\n            {\n                // Common parameters\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS, hparams.f_norm_rms_eps);\n\n                // SSM parameters\n                ml.get_key(LLM_KV_SSM_CONV_KERNEL,    hparams.ssm_d_conv);\n                ml.get_key(LLM_KV_SSM_INNER_SIZE,     hparams.ssm_d_inner);\n                ml.get_key(LLM_KV_SSM_STATE_SIZE,     hparams.ssm_d_state);\n                ml.get_key(LLM_KV_SSM_TIME_STEP_RANK, hparams.ssm_dt_rank);\n                ml.get_key(LLM_KV_SSM_GROUP_COUNT,    hparams.ssm_n_group);\n\n                std::fill(hparams.recurrent_layer_arr.begin(), hparams.recurrent_layer_arr.end(), true);\n\n                switch (hparams.n_layer) {\n                    case 36:\n                        type = LLM_TYPE_0_5B; break;\n                    case 24:\n                        type = LLM_TYPE_1_5B; break;\n                    case 66:\n                        type = LLM_TYPE_1B; break;\n                    case 32:\n                        type = LLM_TYPE_3B; break;\n                    case 44:\n                        type = LLM_TYPE_7B; break;\n                    case 72:\n                        type = LLM_TYPE_34B; break;\n                    default:\n                        type = LLM_TYPE_UNKNOWN;\n                }\n            } break;\n        case LLM_ARCH_HUNYUAN_MOE:\n            {\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS,       hparams.f_norm_rms_eps);\n                ml.get_key(LLM_KV_EXPERT_FEED_FORWARD_LENGTH,        hparams.n_ff_exp);\n                ml.get_key(LLM_KV_EXPERT_SHARED_FEED_FORWARD_LENGTH, hparams.n_ff_shexp);\n\n                switch (hparams.n_layer) {\n                    case 32: type = LLM_TYPE_A13B; break;\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n            } break;\n        case LLM_ARCH_HUNYUAN_DENSE:\n            {\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS, hparams.f_norm_rms_eps);\n\n                switch (hparams.n_embd) {\n                    case 1024: type = LLM_TYPE_0_5B; break;\n                    case 2048: type = LLM_TYPE_1_8B; break;\n                    case 3072: type = LLM_TYPE_4B; break;\n                    case 4096: type = LLM_TYPE_7B; break;\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n            } break;\n        case LLM_ARCH_SMOLLM3:\n            {\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS, hparams.f_norm_rms_eps);\n                hparams.n_no_rope_layer_step = 4;\n\n                switch (hparams.n_layer) {\n                    case 36: type = LLM_TYPE_3B; break;\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n            } break;\n        case LLM_ARCH_OPENAI_MOE:\n            {\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS, hparams.f_norm_rms_eps);\n                ml.get_key(LLM_KV_EXPERT_FEED_FORWARD_LENGTH,  hparams.n_ff_exp);\n                ml.get_key(LLM_KV_ATTENTION_SLIDING_WINDOW,    hparams.n_swa);\n\n                hparams.swa_type = LLAMA_SWA_TYPE_STANDARD;\n                hparams.set_swa_pattern(2);\n\n                switch (hparams.n_layer) {\n                    case 24: type = LLM_TYPE_20B; break;\n                    case 36: type = LLM_TYPE_120B; break;\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n            } break;\n        case LLM_ARCH_LFM2:\n            {\n                ml.get_key(LLM_KV_SHORTCONV_L_CACHE,           hparams.n_shortconv_l_cache);\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS, hparams.f_norm_rms_eps);\n                for (uint32_t il = 0; il < hparams.n_layer; ++il) {\n                    hparams.recurrent_layer_arr[il] = hparams.n_head_kv(il) == 0;\n                }\n                hparams.n_layer_dense_lead = hparams.n_layer;\n                switch (hparams.n_ff()) {\n                    case  4608: type = LLM_TYPE_350M; break;\n                    case  6912: type = LLM_TYPE_700M; break;\n                    case  8192: type = LLM_TYPE_1_2B; break;\n                    case 10752: type = LLM_TYPE_2_6B; break;\n                    default:    type = LLM_TYPE_UNKNOWN;\n                }\n            } break;\n        case LLM_ARCH_LFM2MOE:\n            {\n                ml.get_key(LLM_KV_SHORTCONV_L_CACHE,           hparams.n_shortconv_l_cache);\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS, hparams.f_norm_rms_eps);\n                ml.get_key(LLM_KV_LEADING_DENSE_BLOCK_COUNT,   hparams.n_layer_dense_lead);\n                ml.get_key(LLM_KV_EXPERT_FEED_FORWARD_LENGTH,  hparams.n_ff_exp);\n                ml.get_key(LLM_KV_EXPERT_GATING_FUNC,          hparams.expert_gating_func);\n\n                for (uint32_t il = 0; il < hparams.n_layer; ++il) {\n                    hparams.recurrent_layer_arr[il] = hparams.n_head_kv(il) == 0;\n                }\n\n                type = LLM_TYPE_8B_A1B;\n            } break;\n        case LLM_ARCH_SMALLTHINKER:\n            {\n                const bool found_swa = ml.get_key(LLM_KV_ATTENTION_SLIDING_WINDOW, hparams.n_swa, false);\n\n                if (found_swa && hparams.n_swa > 0) {\n                    hparams.swa_type      = LLAMA_SWA_TYPE_STANDARD;\n                    hparams.n_swa         = 4096;\n                    hparams.set_swa_pattern(4, true);\n                } else {\n                    hparams.swa_type             = LLAMA_SWA_TYPE_NONE;\n                    hparams.n_no_rope_layer_step = hparams.n_layer;\n                }\n\n                ml.get_key(LLM_KV_EXPERT_FEED_FORWARD_LENGTH,  hparams.n_ff_exp, false);\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS, hparams.f_norm_rms_eps);\n                ml.get_key(LLM_KV_EXPERT_GATING_FUNC,          hparams.expert_gating_func, false);\n\n                switch (hparams.n_layer) {\n                    case 32: type = LLM_TYPE_4B;  break;\n                    case 52: type = LLM_TYPE_20B; break;\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n            } break;\n        case LLM_ARCH_GROVEMOE:\n            {\n                ml.get_key(LLM_KV_EXPERT_FEED_FORWARD_LENGTH,        hparams.n_ff_exp);\n                ml.get_key(LLM_KV_EXPERT_CHUNK_FEED_FORWARD_LENGTH,  hparams.n_ff_chexp);\n                ml.get_key(LLM_KV_EXPERT_GROUP_SCALE,                hparams.expert_group_scale);\n                ml.get_key(LLM_KV_EXPERTS_PER_GROUP,                 hparams.n_group_experts);\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS,       hparams.f_norm_rms_eps);\n\n                switch (hparams.n_layer) {\n                    case 48: type = LLM_TYPE_30B_A3B; break;\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n            } break;\n        case LLM_ARCH_APERTUS:\n            {\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS, hparams.f_norm_rms_eps);\n                ml.get_key_or_arr(LLM_KV_XIELU_ALPHA_N,        hparams.xielu_alpha_n, hparams.n_layer);\n                ml.get_key_or_arr(LLM_KV_XIELU_ALPHA_P,        hparams.xielu_alpha_p, hparams.n_layer);\n                ml.get_key_or_arr(LLM_KV_XIELU_BETA,           hparams.xielu_beta,    hparams.n_layer);\n                ml.get_key_or_arr(LLM_KV_XIELU_EPS,            hparams.xielu_eps,     hparams.n_layer);\n\n                switch (hparams.n_layer) {\n                    case 32: type = LLM_TYPE_8B; break;\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n            } break;\n        case LLM_ARCH_MINIMAX_M2:\n            {\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS,  hparams.f_norm_rms_eps);\n                ml.get_key(LLM_KV_EXPERT_FEED_FORWARD_LENGTH,   hparams.n_ff_exp);\n                ml.get_key(LLM_KV_EXPERT_GATING_FUNC,           hparams.expert_gating_func, false);\n\n                switch (hparams.n_layer) {\n                    case 62: type = LLM_TYPE_230B_A10B; break;\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n            } break;\n        case LLM_ARCH_COGVLM:\n            {\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS, hparams.f_norm_rms_eps);\n                switch (hparams.n_layer) {\n                    case 32: type = LLM_TYPE_13B; break;\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n            } break;\n        case LLM_ARCH_PANGU_EMBED:\n            {\n                ml.get_key(LLM_KV_ATTENTION_LAYERNORM_RMS_EPS, hparams.f_norm_rms_eps);\n                switch (hparams.n_layer) {\n                    case 26: type = LLM_TYPE_1B; break; // openPangu-Embedded-1B-V1.1\n                    case 34: type = LLM_TYPE_7B; break; // openPangu-Embedded-7B-V1.1\n                    default: type = LLM_TYPE_UNKNOWN;\n                }\n            } break;\n        default: throw std::runtime_error(\"unsupported model architecture\");\n    }\n\n    pimpl->n_bytes = ml.n_bytes;\n\n    pimpl->desc_str = arch_name() + \" \" + type_name() + \" \" + ml.ftype_name();\n\n    if (hparams.f_max_alibi_bias > 0.0f) {\n        hparams.use_alibi = true;\n    }\n\n    hparams.rope_type = llama_model_rope_type(this);\n}\n\nvoid llama_model::load_vocab(llama_model_loader & ml) {\n    const auto kv = LLM_KV(arch);\n\n    vocab.load(ml, kv);\n}\n\nbool llama_model::load_tensors(llama_model_loader & ml) {\n    const auto & split_mode   = params.split_mode;\n    const auto & n_gpu_layers = params.n_gpu_layers;\n    const auto & use_mlock    = params.use_mlock;\n    const auto & tensor_split = params.tensor_split;\n\n    const int n_layer = hparams.n_layer;\n\n    const bool use_mmap_buffer = true;\n\n    LLAMA_LOG_INFO(\"%s: loading model tensors, this can take a while... (mmap = %s)\\n\", __func__, ml.use_mmap ? \"true\" : \"false\");\n\n    // build a list of buffer types for the CPU and GPU devices\n    pimpl->cpu_buft_list = make_cpu_buft_list(devices, params.use_extra_bufts, params.no_host);\n    for (auto * dev : devices) {\n        buft_list_t buft_list = make_gpu_buft_list(dev, split_mode, tensor_split);\n        // add CPU buffer types as a fallback\n        buft_list.insert(buft_list.end(), pimpl->cpu_buft_list.begin(), pimpl->cpu_buft_list.end());\n        pimpl->gpu_buft_list.emplace(dev, std::move(buft_list));\n    }\n\n    // calculate the split points\n    bool all_zero = tensor_split == nullptr || std::all_of(tensor_split, tensor_split + n_devices(), [](float x) { return x == 0.0f; });\n    std::vector<float> splits(n_devices());\n    if (all_zero) {\n        // default split, by free memory\n        for (size_t i = 0; i < n_devices(); ++i) {\n            ggml_backend_dev_t dev = devices[i];\n            size_t total;\n            size_t free;\n            ggml_backend_dev_memory(dev, &free, &total);\n            splits[i] = free;\n        }\n    } else {\n        std::copy(tensor_split, tensor_split + n_devices(), splits.begin());\n    }\n\n    // sum and normalize the splits to get the split points\n    float split_sum = 0.0f;\n    for (size_t i = 0; i < n_devices(); ++i) {\n        split_sum += splits[i];\n        splits[i] = split_sum;\n    }\n    for (size_t i = 0; i < n_devices(); ++i) {\n        splits[i] /= split_sum;\n    }\n\n    ggml_backend_dev_t cpu_dev = ggml_backend_dev_by_type(GGML_BACKEND_DEVICE_TYPE_CPU);\n    if (cpu_dev == nullptr) {\n        throw std::runtime_error(format(\"%s: no CPU backend found\", __func__));\n    }\n    const int i_gpu_start = std::max((int) hparams.n_layer - n_gpu_layers, (int) 0);\n    const int act_gpu_layers = devices.empty() ? 0 : std::min(n_gpu_layers, (int)n_layer + 1);\n    auto get_layer_buft_list = [&](int il) -> llama_model::impl::layer_dev {\n        const bool is_swa = il < (int) hparams.n_layer && hparams.is_swa(il);\n        if (il < i_gpu_start || (il - i_gpu_start) >= act_gpu_layers) {\n            LLAMA_LOG_DEBUG(\"load_tensors: layer %3d assigned to device %s, is_swa = %d\\n\", il, ggml_backend_dev_name(cpu_dev), is_swa);\n            return {cpu_dev, &pimpl->cpu_buft_list};\n        }\n        const int layer_gpu = std::upper_bound(splits.begin(), splits.begin() + n_devices(), float(il - i_gpu_start)/act_gpu_layers) - splits.begin();\n        auto * dev = devices.at(layer_gpu);\n        LLAMA_LOG_DEBUG(\"load_tensors: layer %3d assigned to device %s, is_swa = %d\\n\", il, ggml_backend_dev_name(dev), is_swa);\n        return {dev, &pimpl->gpu_buft_list.at(dev)};\n    };\n\n    // assign the input layer\n    // there is very little benefit to offloading the input layer, so always keep it on the CPU\n    pimpl->dev_input = { cpu_dev, &pimpl->cpu_buft_list };\n\n    // assign the repeating layers to the devices according to the splits\n    pimpl->dev_layer.resize(n_layer);\n    for (int il = 0; il < n_layer; ++il) {\n        pimpl->dev_layer[il] = get_layer_buft_list(il);\n    }\n\n    // assign the output layer\n    pimpl->dev_output = get_layer_buft_list(n_layer);\n\n    // one ggml context per buffer type\n    int max_n_tensors = ml.n_tensors;\n    max_n_tensors += 1;         // duplicated output tensor\n    max_n_tensors += n_layer*2; // duplicated rope freq tensors\n    const size_t ctx_size = ggml_tensor_overhead()*max_n_tensors;\n\n    // define a comparator for the buft -> ctx map to ensure that the order is well-defined:\n    struct ggml_backend_buft_comparator {\n        bool operator()(const ggml_backend_buffer_type_t & lhs, const ggml_backend_buffer_type_t & rhs) const {\n            return strcmp(ggml_backend_buft_name(lhs), ggml_backend_buft_name(rhs)) < 0;\n        }\n    };\n    std::map<ggml_backend_buffer_type_t, ggml_context_ptr, ggml_backend_buft_comparator> ctx_map;\n\n    auto ctx_for_buft = [&](ggml_backend_buffer_type_t buft) -> ggml_context * {\n        auto it = ctx_map.find(buft);\n        if (it == ctx_map.end()) {\n            ggml_init_params params = {\n                /*.mem_size   =*/ ctx_size,\n                /*.mem_buffer =*/ NULL,\n                /*.no_alloc   =*/ true,\n            };\n\n            ggml_context * ctx = ggml_init(params);\n            if (!ctx) {\n                throw std::runtime_error(format(\"failed to create ggml context\"));\n            }\n\n            ctx_map.emplace(buft, ctx);\n\n            return ctx;\n        }\n        return it->second.get();\n    };\n\n    const auto TENSOR_DUPLICATED   = llama_model_loader::TENSOR_DUPLICATED;\n    const auto TENSOR_NOT_REQUIRED = llama_model_loader::TENSOR_NOT_REQUIRED;\n    const auto TENSOR_SKIP         = llama_model_loader::TENSOR_SKIP;\n\n    // create tensors for the weights\n    {\n        // note: cast to int64_t since we will use these for the tensor dimensions\n        const int64_t n_head        = hparams.n_head();\n        const int64_t n_head_kv     = hparams.n_head_kv();\n        const int64_t n_embd        = hparams.n_embd;\n        const int64_t n_embd_k_gqa  = hparams.n_embd_k_gqa();\n        const int64_t n_embd_v_gqa  = hparams.n_embd_v_gqa();\n        const int64_t n_embd_head_k = hparams.n_embd_head_k;\n        const int64_t n_embd_head_v = hparams.n_embd_head_v;\n        const int64_t n_ff          = hparams.n_ff();\n        const int64_t n_embd_gqa    = n_embd_v_gqa;\n        const int64_t n_vocab       = vocab.n_tokens();\n        const int64_t n_token_types = vocab.n_token_types();\n        const int64_t n_rot         = hparams.n_rot;\n        const int64_t n_expert      = hparams.n_expert;\n        const int64_t n_expert_used = hparams.n_expert_used;\n        const int64_t n_ctx_train   = hparams.n_ctx_train;\n\n        if (n_expert > 0 && hparams.n_expert_used == 0) {\n            throw std::runtime_error(\"model has expert layers but no expert layers are used\");\n        }\n\n        int n_moved_tensors = 0;\n        ggml_tensor * first_moved_tensor = nullptr;\n        ggml_backend_buffer_type_t first_moved_from_buft = nullptr;\n        ggml_backend_buffer_type_t first_moved_to_buft = nullptr;\n\n        auto create_tensor = [&](const LLM_TN_IMPL & tn, const std::initializer_list<int64_t> & ne, int flags) -> ggml_tensor * {\n            ggml_tensor * t_meta = ml.get_tensor_meta(tn.str().c_str());\n\n            if (!t_meta) {\n                if (flags & TENSOR_NOT_REQUIRED) {\n                    return nullptr;\n                }\n                throw std::runtime_error(format(\"missing tensor \'%s\'\", tn.str().c_str()));\n            }\n\n            // some models use the token embedding tensor as the output, but since these are used in different layers and with different ops\n            // the tensor is duplicated\n            // to handle this, we check if the tensor is duplicated, and if so, we assume that it is being loaded as the output tensor\n            llm_tensor tn_tensor = tn.tensor;\n            if (tn.tensor == LLM_TENSOR_TOKEN_EMBD && flags & TENSOR_DUPLICATED) {\n                tn_tensor = LLM_TENSOR_OUTPUT;\n            }\n\n            llm_tensor_info info;\n            try {\n                info = llm_tensor_info_for(tn_tensor);\n            } catch (const std::out_of_range & e) {\n                throw std::runtime_error(format(\"missing tensor info mapping for %s\", tn.str().c_str()));\n            }\n\n            // skip unused tensors\n            if (info.op == GGML_OP_NONE || flags & TENSOR_SKIP) {\n                const size_t nbytes = ggml_nbytes(t_meta);\n                LLAMA_LOG_WARN(\"model has unused tensor %s (size = %zu bytes) -- ignoring\\n\", tn.str().c_str(), nbytes);\n\n                ml.size_data -= nbytes;\n                ml.n_created++;\n\n                return nullptr;\n            }\n\n            // tensors with \"bias\" suffix are always used with GGML_OP_ADD or GGML_OP_ADD_ID\n            ggml_op op;\n            bool bias = tn.suffix != nullptr && strcmp(tn.suffix, \"bias\") == 0;\n            if (bias) {\n                if (info.op == GGML_OP_MUL_MAT_ID) {\n                    op = GGML_OP_ADD_ID;\n                } else {\n                    op = GGML_OP_ADD;\n                }\n            } else {\n                op = info.op;\n            }\n\n            // sanity checks\n            if (info.layer == LLM_TENSOR_LAYER_INPUT || info.layer == LLM_TENSOR_LAYER_OUTPUT) {\n                if (tn.bid != -1) {\n                    GGML_ABORT(\"input/output layer tensor %s used with a layer number\", tn.str().c_str());\n                }\n            } else {\n                if (tn.bid == -1) {\n                    GGML_ABORT(\"repeating layer tensor %s used without a layer number\", tn.str().c_str());\n                }\n            }\n\n            // select the buffer type for this tensor\n            buft_list_t * buft_list;\n            switch (info.layer) {\n                case LLM_TENSOR_LAYER_INPUT:\n                    buft_list = pimpl->dev_input.buft_list;\n                    break;\n                case LLM_TENSOR_LAYER_OUTPUT:\n                    buft_list = pimpl->dev_output.buft_list;\n                    break;\n                case LLM_TENSOR_LAYER_REPEATING:\n                    buft_list = pimpl->dev_layer.at(tn.bid).buft_list;\n                    break;\n                default:\n                    GGML_ABORT(\"invalid layer %d for tensor %s\", info.layer, tn.str().c_str());\n            }\n\n            ggml_backend_buffer_type_t buft = nullptr;\n\n            // check overrides\n            if (ml.tensor_buft_overrides) {\n                std::string tensor_name = tn.str();\n                for (const auto * overrides = ml.tensor_buft_overrides; overrides->pattern != nullptr; ++overrides) {\n                    std::regex pattern(overrides->pattern);\n                    if (std::regex_search(tensor_name, pattern)) {\n                        if (overrides->buft == ggml_backend_cpu_buffer_type()) {\n                            // when overriding to a CPU buffer, consider the extra buffer types\n                            buft = select_weight_buft(hparams, t_meta, op, pimpl->cpu_buft_list);\n                        } else {\n                            buft = overrides->buft;\n                        }\n\n                        LLAMA_LOG_DEBUG(\"tensor %s (%zu MiB %s) buffer type overridden to %s\\n\",\n                                tensor_name.c_str(),\n                                ggml_nbytes(t_meta) / 1024 / 1024, ggml_type_name(t_meta->type),\n                                ggml_backend_buft_name(buft));\n                        break;\n                    }\n                }\n            }\n\n            if (!buft) {\n                buft = select_weight_buft(hparams, t_meta, op, *buft_list);\n                if (!buft) {\n                    throw std::runtime_error(format(\"failed to find a compatible buffer type for tensor %s\", tn.str().c_str()));\n                }\n            }\n\n            // avoid using a host buffer when using mmap\n            auto * buft_dev = ggml_backend_buft_get_device(buft);\n            if (ml.use_mmap && buft_dev && buft == ggml_backend_dev_host_buffer_type(buft_dev)) {\n                auto * cpu_dev = ggml_backend_dev_by_type(GGML_BACKEND_DEVICE_TYPE_CPU);\n                if (!cpu_dev) {\n                    throw std::runtime_error(\"no CPU backend found\");\n                }\n                buft = ggml_backend_dev_buffer_type(cpu_dev);\n            }\n\n            if (buft != buft_list->front().second) {\n                n_moved_tensors++;\n                if (!first_moved_tensor) {\n                    first_moved_tensor = t_meta;\n                    first_moved_from_buft = buft_list->front().second;\n                    first_moved_to_buft   = buft;\n                }\n            }\n\n            ggml_context * ctx = ctx_for_buft(buft);\n\n            // if duplicated, check if the original tensor was allocated in the same buffer type context and avoid creating a new one\n            if (flags & TENSOR_DUPLICATED) {\n                ggml_tensor * t = ggml_get_tensor(ctx, tn.str().c_str());\n                if (t) {\n                    return t;\n                }\n            }\n            return ml.create_tensor(ctx, tn, ne, flags);\n        };\n\n        layers.resize(n_layer);\n\n        // TODO: move to a separate function\n        const auto tn = LLM_TN(arch);\n        switch (arch) {\n            case LLM_ARCH_LLAMA:\n            case LLM_ARCH_REFACT:\n            case LLM_ARCH_MINICPM:\n            case LLM_ARCH_GRANITE:\n            case LLM_ARCH_GRANITE_MOE:\n                {\n                    tok_embd = create_tensor(tn(LLM_TENSOR_TOKEN_EMBD, \"weight\"), {n_embd, n_vocab}, 0);\n\n                    // output\n                    output_norm = create_tensor(tn(LLM_TENSOR_OUTPUT_NORM, \"weight\"), {n_embd}, 0);\n                    output      = create_tensor(tn(LLM_TENSOR_OUTPUT,      \"weight\"), {n_embd, n_vocab}, TENSOR_NOT_REQUIRED);\n\n                    // if output is NULL, init from the input tok embed\n                    if (output == NULL) {\n                        output = create_tensor(tn(LLM_TENSOR_TOKEN_EMBD, \"weight\"), {n_embd, n_vocab}, TENSOR_DUPLICATED);\n                    }\n\n                    for (int i = 0; i < n_layer; ++i) {\n                        auto & layer = layers[i];\n\n                        layer.attn_norm = create_tensor(tn(LLM_TENSOR_ATTN_NORM, \"weight\", i), {n_embd}, 0);\n\n                        layer.wq = create_tensor(tn(LLM_TENSOR_ATTN_Q,   \"weight\", i), {n_embd, n_embd_head_k * n_head}, 0);\n                        layer.wk = create_tensor(tn(LLM_TENSOR_ATTN_K,   \"weight\", i), {n_embd, n_embd_k_gqa}, 0);\n                        layer.wv = create_tensor(tn(LLM_TENSOR_ATTN_V,   \"weight\", i), {n_embd, n_embd_v_gqa}, 0);\n                        layer.wo = create_tensor(tn(LLM_TENSOR_ATTN_OUT, \"weight\", i), {n_embd_head_k * n_head, n_embd}, 0);\n\n                        // optional bias tensors\n                        layer.bq = create_tensor(tn(LLM_TENSOR_ATTN_Q,   \"bias\", i), {n_embd},     TENSOR_NOT_REQUIRED);\n                        layer.bk = create_tensor(tn(LLM_TENSOR_ATTN_K,   \"bias\", i), {n_embd_gqa}, TENSOR_NOT_REQUIRED);\n                        layer.bv = create_tensor(tn(LLM_TENSOR_ATTN_V,   \"bias\", i), {n_embd_gqa}, TENSOR_NOT_REQUIRED);\n                        layer.bo = create_tensor(tn(LLM_TENSOR_ATTN_OUT, \"bias\", i), {n_embd},     TENSOR_NOT_REQUIRED);\n\n                        layer.ffn_norm = create_tensor(tn(LLM_TENSOR_FFN_NORM, \"weight\", i), {n_embd}, 0);\n\n                        if (hparams.rope_scaling_type_train == LLAMA_ROPE_SCALING_TYPE_LONGROPE) {\n                            layer.rope_long  = create_tensor(tn(LLM_TENSOR_ROPE_FACTORS_LONG,  \"weight\", i), {n_rot/2}, TENSOR_NOT_REQUIRED | (i != 0 ? TENSOR_DUPLICATED : 0));\n                            layer.rope_short = create_tensor(tn(LLM_TENSOR_ROPE_FACTORS_SHORT, \"weight\", i), {n_rot/2}, TENSOR_NOT_REQUIRED | (i != 0 ? TENSOR_DUPLICATED : 0));\n                        }\n                        else {\n                            layer.rope_freqs = create_tensor(tn(LLM_TENSOR_ROPE_FREQS, \"weight\", i), {n_rot/2}, TENSOR_NOT_REQUIRED | (i != 0 ? TENSOR_DUPLICATED : 0));\n                        }\n\n                        if (n_expert == 0) {\n                            layer.ffn_gate = create_tensor(tn(LLM_TENSOR_FFN_GATE, \"weight\", i), {n_embd,   n_ff}, 0);\n                            layer.ffn_down = create_tensor(tn(LLM_TENSOR_FFN_DOWN, \"weight\", i), {  n_ff, n_embd}, 0);\n                            layer.ffn_up   = create_tensor(tn(LLM_TENSOR_FFN_UP,   \"weight\", i), {n_embd,   n_ff}, 0);\n\n                            // optional MLP bias\n                            layer.ffn_gate_b = create_tensor(tn(LLM_TENSOR_FFN_GATE, \"bias\", i), {n_ff}, TENSOR_NOT_REQUIRED);\n                            layer.ffn_down_b = create_tensor(tn(LLM_TENSOR_FFN_DOWN, \"bias\", i), {n_embd}, TENSOR_NOT_REQUIRED);\n                            layer.ffn_up_b   = create_tensor(tn(LLM_TENSOR_FFN_UP,   \"bias\", i), {n_ff}, TENSOR_NOT_REQUIRED);\n                        } else {\n                            layer.ffn_gate_inp  = create_tensor(tn(LLM_TENSOR_FFN_GATE_INP,  \"weight\", i), {n_embd, n_expert}, 0);\n                            layer.ffn_gate_exps = create_tensor(tn(LLM_TENSOR_FFN_GATE_EXPS, \"weight\", i), {n_embd,   n_ff, n_expert}, TENSOR_NOT_REQUIRED);\n                            layer.ffn_down_exps = create_tensor(tn(LLM_TENSOR_FFN_DOWN_EXPS, \"weight\", i), {  n_ff, n_embd, n_expert}, 0);\n                            layer.ffn_up_exps   = create_tensor(tn(LLM_TENSOR_FFN_UP_EXPS,   \"weight\", i), {n_embd,   n_ff, n_expert}, 0);\n\n                            // For Granite MoE Shared\n                            if (hparams.n_ff_shexp > 0) {\n                                layer.ffn_gate_shexp = create_tensor(tn(LLM_TENSOR_FFN_GATE_SHEXP, \"weight\", i), {n_embd, hparams.n_ff_shexp}, 0);\n                                layer.ffn_up_shexp   = create_tensor(tn(LLM_TENSOR_FFN_UP_SHEXP,   \"weight\", i), {n_embd, hparams.n_ff_shexp}, 0);\n                                layer.ffn_down_shexp = create_tensor(tn(LLM_TENSOR_FFN_DOWN_SHEXP, \"weight\", i), {hparams.n_ff_shexp, n_embd}, 0);\n                            }\n                        }\n                    }\n                } break;\n            case LLM_ARCH_LLADA:\n                {\n                    tok_embd = create_tensor(tn(LLM_TENSOR_TOKEN_EMBD, \"weight\"), { n_embd, n_vocab }, 0);\n\n                    // output\n                    output_norm = create_tensor(tn(LLM_TENSOR_OUTPUT_NORM, \"weight\"), { n_embd }, 0);\n                    output = create_tensor(tn(LLM_TENSOR_OUTPUT, \"weight\"), { n_embd, n_vocab }, TENSOR_NOT_REQUIRED);\n\n                    // if output is NULL, init from the input tok embed\n                    if (output == NULL) {\n                        output =\n                            create_tensor(tn(LLM_TENSOR_TOKEN_EMBD, \"weight\"), { n_embd, n_vocab }, TENSOR_DUPLICATED);\n                    }\n\n                    for (int i = 0; i < n_layer; ++i) {\n                        auto & layer = layers[i];\n\n                        layer.attn_norm = create_tensor(tn(LLM_TENSOR_ATTN_NORM, \"weight\", i), { n_embd }, 0);\n\n                        // Use separate Q, K, V projections without bias, matching LLaDALlamaBlock\n                        layer.wq =\n                            create_tensor(tn(LLM_TENSOR_ATTN_Q, \"weight\", i), { n_embd, n_embd_head_k * n_head }, 0);\n                        layer.wk = create_tensor(tn(LLM_TENSOR_ATTN_K, \"weight\", i), { n_embd, n_embd_k_gqa }, 0);\n                        layer.wv = create_tensor(tn(LLM_TENSOR_ATTN_V, \"weight\", i), { n_embd, n_embd_v_gqa }, 0);\n                        // No bias for QKV projections as per config: include_bias=false, include_qkv_bias=false\n                        layer.wo =\n                            create_tensor(tn(LLM_TENSOR_ATTN_OUT, \"weight\", i), { n_embd_head_k * n_head, n_embd }, 0);\n                        layer.bo = create_tensor(tn(LLM_TENSOR_ATTN_OUT, \"bias\", i), { n_embd }, TENSOR_NOT_REQUIRED);\n\n                        layer.ffn_norm = create_tensor(tn(LLM_TENSOR_FFN_NORM, \"weight\", i), { n_embd }, 0);\n\n                        layer.rope_freqs = create_tensor(tn(LLM_TENSOR_ROPE_FREQS, \"weight\", i), { n_rot / 2 },\n                                                         TENSOR_NOT_REQUIRED | (i != 0 ? TENSOR_DUPLICATED : 0));\n\n                        layer.ffn_gate = create_tensor(tn(LLM_TENSOR_FFN_GATE, \"weight\", i), { n_embd, n_ff }, 0);\n                        layer.ffn_down = create_tensor(tn(LLM_TENSOR_FFN_DOWN, \"weight\", i), { n_ff, n_embd }, 0);\n                        layer.ffn_up   = create_tensor(tn(LLM_TENSOR_FFN_UP, \"weight\", i), { n_embd, n_ff }, 0);\n\n                        // optional MLP bias\n                        layer.ffn_gate_b =\n                            create_tensor(tn(LLM_TENSOR_FFN_GATE, \"bias\", i), { n_ff }, TENSOR_NOT_REQUIRED);\n                        layer.ffn_down_b =\n                            create_tensor(tn(LLM_TENSOR_FFN_DOWN, \"bias\", i), { n_embd }, TENSOR_NOT_REQUIRED);\n                        layer.ffn_up_b = create_tensor(tn(LLM_TENSOR_FFN_UP, \"bias\", i), { n_ff }, TENSOR_NOT_REQUIRED);\n                    }\n                }\n                break;\n            case LLM_ARCH_LLADA_MOE:\n                {\n                    tok_embd = create_tensor(tn(LLM_TENSOR_TOKEN_EMBD, \"weight\"), {n_embd, n_vocab}, 0);\n\n                    // output\n                    output_norm = create_tensor(tn(LLM_TENSOR_OUTPUT_NORM, \"weight\"), {n_embd}, 0);\n                    output      = create_tensor(tn(LLM_TENSOR_OUTPUT,      \"weight\"), {n_embd, n_vocab}, 0);\n\n                    GGML_ASSERT(n_expert > 0 && \"n_expert must be > 0 for llada-moe\");\n                    GGML_ASSERT(n_expert_used > 0 && \"n_expert_used must be > 0 for llada-moe\");\n\n                    for (int i = 0; i < n_layer; ++i) {\n                        auto & layer = layers[i];\n\n                        layer.attn_norm = create_tensor(tn(LLM_TENSOR_ATTN_NORM, \"weight\", i), {n_embd}, 0);\n\n                        layer.wq = create_tensor(tn(LLM_TENSOR_ATTN_Q,   \"weight\", i), {n_embd, n_embd}, 0);\n                        layer.wk = create_tensor(tn(LLM_TENSOR_ATTN_K,   \"weight\", i), {n_embd, n_embd_gqa}, 0);\n                        layer.wv = create_tensor(tn(LLM_TENSOR_ATTN_V,   \"weight\", i), {n_embd, n_embd_gqa}, 0);\n                        layer.wo = create_tensor(tn(LLM_TENSOR_ATTN_OUT, \"weight\", i), {n_embd, n_embd}, 0);\n                        layer.attn_q_norm = create_tensor(tn(LLM_TENSOR_ATTN_Q_NORM, \"weight\", i), {n_embd_head_k}, 0);\n                        layer.attn_k_norm = create_tensor(tn(LLM_TENSOR_ATTN_K_NORM, \"weight\", i), {n_embd_head_k}, 0);\n\n                        layer.ffn_norm = create_tensor(tn(LLM_TENSOR_FFN_NORM, \"weight\", i), {n_embd}, 0);\n\n                        layer.ffn_gate_inp = create_tensor(tn(LLM_TENSOR_FFN_GATE_INP, \"weight\", i), {n_embd, n_expert}, 0);\n\n                        const int64_t n_ff_exp = hparams.n_ff_exp ? hparams.n_ff_exp : n_ff / n_expert_used;\n\n                        layer.ffn_gate_exps = create_tensor(tn(LLM_TENSOR_FFN_GATE_EXPS, \"weight\", i), {  n_embd, n_ff_exp, n_expert}, 0);\n                        layer.ffn_down_exps = create_tensor(tn(LLM_TENSOR_FFN_DOWN_EXPS, \"weight\", i), {n_ff_exp,   n_embd, n_expert}, 0);\n                        layer.ffn_up_exps   = create_tensor(tn(LLM_TENSOR_FFN_UP_EXPS,   \"weight\", i), {  n_embd, n_ff_exp, n_expert}, 0);\n                    }\n                } break;\n            case LLM_ARCH_LLAMA4:\n                {\n                    tok_embd = create_tensor(tn(LLM_TENSOR_TOKEN_EMBD, \"weight\"), {n_embd, n_vocab}, 0);\n\n                    // output\n                    output_norm = create_tensor(tn(LLM_TENSOR_OUTPUT_NORM, \"weight\"), {n_embd}, 0);\n                    output      = create_tensor(tn(LLM_TENSOR_OUTPUT,      \"weight\"), {n_embd, n_vocab}, TENSOR_NOT_REQUIRED);\n\n                    // if output is NULL, init from the input tok embed\n                    if (output == NULL) {\n                        output = create_tensor(tn(LLM_TENSOR_TOKEN_EMBD, \"weight\"), {n_embd, n_vocab}, TENSOR_DUPLICATED);\n                    }\n\n                    for (int i = 0; i < n_layer; ++i) {\n                        bool is_moe_layer = hparams.n_moe_layer_step > 0 && (i + 1) % hparams.n_moe_layer_step == 0;\n\n                        auto & layer = layers[i];\n\n                        layer.attn_norm = create_tensor(tn(LLM_TENSOR_ATTN_NORM, \"weight\", i), {n_embd}, 0);\n\n                        layer.wq = create_tensor(tn(LLM_TENSOR_ATTN_Q,   \"weight\", i), {n_embd, n_embd_head_k * n_head}, 0);\n                        layer.wk = create_tensor(tn(LLM_TENSOR_ATTN_K,   \"weight\", i), {n_embd, n_embd_k_gqa}, 0);\n                        layer.wv = create_tensor(tn(LLM_TENSOR_ATTN_V,   \"weight\", i), {n_embd, n_embd_v_gqa}, 0);\n                        layer.wo = create_tensor(tn(LLM_TENSOR_ATTN_OUT, \"weight\", i), {n_embd_head_k * n_head, n_embd}, 0);\n\n                        layer.ffn_norm = create_tensor(tn(LLM_TENSOR_FFN_NORM, \"weight\", i), {n_embd}, 0);\n\n                        layer.rope_freqs = create_tensor(tn(LLM_TENSOR_ROPE_FREQS, \"weight\", i), {n_rot/2}, TENSOR_NOT_REQUIRED | (i != 0 ? TENSOR_DUPLICATED : 0));\n\n                        if (is_moe_layer) {\n                            int n_ff_exp = hparams.n_ff_exp;\n\n                            layer.ffn_gate_inp  = create_tensor(tn(LLM_TENSOR_FFN_GATE_INP,  \"weight\", i), {n_embd, n_expert}, 0);\n                            layer.ffn_gate_exps = create_tensor(tn(LLM_TENSOR_FFN_GATE_EXPS, \"weight\", i), {n_embd,   n_ff_exp, n_expert}, 0);\n                            layer.ffn_down_exps = create_tensor(tn(LLM_TENSOR_FFN_DOWN_EXPS, \"weight\", i), {  n_ff_exp, n_embd, n_expert}, 0);\n                            layer.ffn_up_exps   = create_tensor(tn(LLM_TENSOR_FFN_UP_EXPS,   \"weight\", i), {n_embd,   n_ff_exp, n_expert}, 0);\n\n                            // Shared expert\n                            const int64_t n_ff_shexp = n_ff_exp;\n                            layer.ffn_gate_shexp = create_tensor(tn(LLM_TENSOR_FFN_GATE_SHEXP, \"weight\", i), {    n_embd, n_ff_shexp}, 0);\n                            layer.ffn_down_shexp = create_tensor(tn(LLM_TENSOR_FFN_DOWN_SHEXP, \"weight\", i), {n_ff_shexp, n_embd    }, 0);\n                            layer.ffn_up_shexp   = create_tensor(tn(LLM_TENSOR_FFN_UP_SHEXP,   \"weight\", i), {    n_embd, n_ff_shexp}, 0);\n                        } else {\n                            layer.ffn_gate = create_tensor(tn(LLM_TENSOR_FFN_GATE, \"weight\", i), {n_embd,   n_ff}, 0);\n                            layer.ffn_down = create_tensor(tn(LLM_TENSOR_FFN_DOWN, \"weight\", i), {  n_ff, n_embd}, 0);\n                            layer.ffn_up   = create_tensor(tn(LLM_TENSOR_FFN_UP,   \"weight\", i), {n_embd,   n_ff}, 0);\n                        }\n                    }\n                } break;\n            case LLM_ARCH_DECI:\n                {\n                    tok_embd = create_tensor(tn(LLM_TENSOR_TOKEN_EMBD, \"weight\"), {n_embd, n_vocab}, 0);\n\n                    // output\n                    output_norm = create_tensor(tn(LLM_TENSOR_OUTPUT_NORM, \"weight\"), {n_embd}, 0);\n                    output      = create_tensor(tn(LLM_TENSOR_OUTPUT,      \"weight\"), {n_embd, n_vocab}, TENSOR_NOT_REQUIRED);\n\n                    // if output is NULL, init from the input tok embed\n                    if (output == NULL) {\n                        output = create_tensor(tn(LLM_TENSOR_TOKEN_EMBD, \"weight\"), {n_embd, n_vocab}, TENSOR_DUPLICATED);\n                    }\n\n                    for (int i = 0; i < n_layer; ++i) {\n                        auto & layer = layers[i];\n                        const int64_t n_embd_k_gqa  = hparams.n_embd_k_gqa(i);\n                        const int64_t n_embd_v_gqa  = hparams.n_embd_v_gqa(i);\n                        const int64_t n_embd_gqa    = hparams.n_embd_v_gqa(i);\n                        const int64_t n_ff          = hparams.n_ff(i);\n                        const int64_t n_head        = hparams.n_head(i);\n                        const int64_t n_head_kv     = hparams.n_head_kv(i);\n\n                        if (n_head_kv == 0 && n_head > 0) {\n                            // linear attention for DeciLMCausalModel\n                            layer.attn_norm = create_tensor(tn(LLM_TENSOR_ATTN_NORM, \"weight\", i), {n_embd}, 0);\n                            layer.wo = create_tensor(tn(LLM_TENSOR_ATTN_OUT, \"weight\", i), {n_embd, n_embd}, 0);\n                        }\n                        else if (n_head_kv > 0) {\n                            layer.attn_norm = create_tensor(tn(LLM_TENSOR_ATTN_NORM, \"weight\", i), {n_embd}, 0);\n\n                            layer.wq = create_tensor(tn(LLM_TENSOR_ATTN_Q,   \"weight\", i), {n_embd, n_embd_head_k * n_head}, 0);\n                            layer.wk = create_tensor(tn(LLM_TENSOR_ATTN_K,   \"weight\", i), {n_embd, n_embd_k_gqa}, 0);\n                            layer.wv = create_tensor(tn(LLM_TENSOR_ATTN_V,   \"weight\", i), {n_embd, n_embd_v_gqa}, 0);\n                            layer.wo = create_tensor(tn(LLM_TENSOR_ATTN_OUT, \"weight\", i), {n_embd_head_k * n_head, n_embd}, 0);\n                        }\n\n                        // optional bias tensors\n                        layer.bq = create_tensor(tn(LLM_TENSOR_ATTN_Q,   \"bias\", i), {n_embd},     TENSOR_NOT_REQUIRED);\n                        layer.bk = create_tensor(tn(LLM_TENSOR_ATTN_K,   \"bias\", i), {n_embd_gqa}, TENSOR_NOT_REQUIRED);\n                        layer.bv = create_tensor(tn(LLM_TENSOR_ATTN_V,   \"bias\", i), {n_embd_gqa}, TENSOR_NOT_REQUIRED);\n                        layer.bo = create_tensor(tn(LLM_TENSOR_ATTN_OUT, \"bias\", i), {n_embd},     TENSOR_NOT_REQUIRED);\n\n                        if (n_ff > 0) {\n                            layer.ffn_norm = create_tensor(tn(LLM_TENSOR_FFN_NORM, \"weight\", i), {n_embd}, 0);\n                        }\n\n                        if (hparams.rope_scaling_type_train == LLAMA_ROPE_SCALING_TYPE_LONGROPE) {\n                            layer.rope_long  = create_tensor(tn(LLM_TENSOR_ROPE_FACTORS_LONG,  \"weight\", i), {n_rot/2}, TENSOR_NOT_REQUIRED | (i != 0 ? TENSOR_DUPLICATED : 0));\n                            layer.rope_short = create_tensor(tn(LLM_TENSOR_ROPE_FACTORS_SHORT, \"weight\", i), {n_rot/2}, TENSOR_NOT_REQUIRED | (i != 0 ? TENSOR_DUPLICATED : 0));\n                        }\n                        else {\n                            layer.rope_freqs = create_tensor(tn(LLM_TENSOR_ROPE_FREQS, \"weight\", i), {n_rot/2}, TENSOR_NOT_REQUIRED | (i != 0 ? TENSOR_DUPLICATED : 0));\n                        }\n\n                        if (n_ff > 0) {\n                            layer.ffn_gate = create_tensor(tn(LLM_TENSOR_FFN_GATE, \"weight\", i), {n_embd,   n_ff}, 0);\n                            layer.ffn_down = create_tensor(tn(LLM_TENSOR_FFN_DOWN, \"weight\", i), {  n_ff, n_embd}, 0);\n                            layer.ffn_up   = create_tensor(tn(LLM_TENSOR_FFN_UP,   \"weight\", i), {n_embd,   n_ff}, 0);\n                        }\n\n                        // optional MLP bias\n                        layer.ffn_gate_b = create_tensor(tn(LLM_TENSOR_FFN_GATE, \"bias\", i), {n_ff}, TENSOR_NOT_REQUIRED);\n                        layer.ffn_down_b = create_tensor(tn(LLM_TENSOR_FFN_DOWN, \"bias\", i), {n_embd}, TENSOR_NOT_REQUIRED);\n                        layer.ffn_up_b   = create_tensor(tn(LLM_TENSOR_FFN_UP,   \"bias\", i), {n_ff}, TENSOR_NOT_REQUIRED);\n                    }\n                } break;\n            case LLM_ARCH_MINICPM3:\n                {\n                    const int64_t n_embd_head_qk_rope = hparams.n_rot;\n                    const int64_t n_embd_head_qk_nope = hparams.n_embd_head_k - hparams.n_rot;\n\n                    const int64_t q_lora_rank  = hparams.n_lora_q;\n                    const int64_t kv_lora_rank = hparams.n_lora_kv;\n                    tok_embd = create_tensor(tn(LLM_TENSOR_TOKEN_EMBD, \"weight\"), {n_embd, n_vocab}, 0);\n\n                    // output\n                    output_norm = create_tensor(tn(LLM_TENSOR_OUTPUT_NORM, \"weight\"), {n_embd}, 0);\n                    output      = create_tensor(tn(LLM_TENSOR_OUTPUT,      \"weight\"), {n_embd, n_vocab}, TENSOR_NOT_REQUIRED);\n\n                    // if output is NULL, init from the input tok embed\n                    if (output == NULL) {\n                        output = create_tensor(tn(LLM_TENSOR_TOKEN_EMBD, \"weight\"), {n_embd, n_vocab}, TENSOR_DUPLICATED);\n                    }\n\n                    for (int i = 0; i < n_layer; ++i) {\n                        auto & layer = layers[i];\n\n                        layer.attn_norm = create_tensor(tn(LLM_TENSOR_ATTN_NORM, \"weight\", i), {n_embd}, 0);\n                        layer.attn_q_a_norm = create_tensor(tn(LLM_TENSOR_ATTN_Q_A_NORM, \"weight\", i), {q_lora_rank}, 0);\n\n                        layer.attn_kv_a_norm = create_tensor(tn(LLM_TENSOR_ATTN_KV_A_NORM, \"weight\", i), {kv_lora_rank}, 0);\n\n                        layer.wq_a = create_tensor(tn(LLM_TENSOR_ATTN_Q_A, \"weight\", i), {n_embd, q_lora_rank}, 0);\n                        layer.wq_b = create_tensor(tn(LLM_TENSOR_ATTN_Q_B, \"weight\", i), {q_lora_rank, n_head * n_embd_head_k}, 0);\n\n                        layer.wkv_a_mqa = create_tensor(tn(LLM_TENSOR_ATTN_KV_A_MQA, \"weight\", i), {n_embd, kv_lora_rank + (n_embd_head_qk_rope)}, 0);\n                        layer.wkv_b     = create_tensor(tn(LLM_TENSOR_ATTN_KV_B,     \"weight\", i), {kv_lora_rank, n_head * (n_embd_head_qk_nope + n_embd_head_v)}, 0);\n                        layer.wo        = create_tensor(tn(LLM_TENSOR_ATTN_OUT,      \"weight\", i), {              n_head * (                      n_embd_head_v), n_embd}, 0);\n\n                        layer.ffn_norm = create_tensor(tn(LLM_TENSOR_FFN_NORM, \"weight\", i), {n_embd}, 0);\n\n                        layer.ffn_gate = create_tensor(tn(LLM_TENSOR_FFN_GATE, \"weight\", i), {n_embd,   n_ff}, 0);\n                        layer.ffn_down = create_tensor(tn(LLM_TENSOR_FFN_DOWN, \"weight\", i), {  n_ff, n_embd}, 0);\n                        layer.ffn_up   = create_tensor(tn(LLM_TENSOR_FFN_UP,   \"weight\", i), {n_embd,   n_ff}, 0);\n\n                        layer.rope_long  = create_tensor(tn(LLM_TENSOR_ROPE_FACTORS_LONG,  \"weight\", i), { n_embd_head_qk_rope/2 }, TENSOR_NOT_REQUIRED | (i != 0 ? TENSOR_DUPLICATED : 0));\n                        layer.rope_short = create_tensor(tn(LLM_TENSOR_ROPE_FACTORS_SHORT, \"weight\", i), { n_embd_head_qk_rope/2 }, TENSOR_NOT_REQUIRED | (i != 0 ? TENSOR_DUPLICATED : 0));\n                    }\n                } break;\n            case LLM_ARCH_GROK:\n                {\n                    if (n_expert == 0) {\n                        throw std::runtime_error(\"Grok model cannot have zero experts\");\n                    }\n\n                    tok_embd = create_tensor(tn(LLM_TENSOR_TOKEN_EMBD, \"weight\"), {n_embd, n_vocab}, 0);\n\n                    // output\n                    output_norm = create_tensor(tn(LLM_TENSOR_OUTPUT_NORM, \"weight\"), {n_embd}, 0);\n                    output      = create_tensor(tn(LLM_TENSOR_OUTPUT,      \"weight\"), {n_embd, n_vocab}, TENSOR_NOT_REQUIRED);\n\n                    // if output is NULL, init from the input tok embed\n                    if (output == NULL) {\n                        output = create_tensor(tn(LLM_TENSOR_TOKEN_EMBD, \"weight\"), {n_embd, n_vocab}, TENSOR_DUPLICATED);\n                    }\n\n                    const int64_t n_ff_exp = hparams.n_ff_exp ? hparams.n_ff_exp : n_ff/* / n_expert_used*/; // grok-1 n_ff_exp == n_ff\n                    for (int i = 0; i < n_layer; ++i) {\n                        auto & layer = layers[i];\n\n                        layer.attn_norm = create_tensor(tn(LLM_TENSOR_ATTN_NORM, \"weight\", i), {n_embd}, 0);\n\n                        layer.wq = create_tensor(tn(LLM_TENSOR_ATTN_Q,   \"weight\", i), {n_embd, n_embd}, 0);\n                        layer.wk = create_tensor(tn(LLM_TENSOR_ATTN_K,   \"weight\", i), {n_embd, n_embd_gqa}, 0);\n                        layer.wv = create_tensor(tn(LLM_TENSOR_ATTN_V,   \"weight\", i), {n_embd, n_embd_gqa}, 0);\n                        layer.wo = create_tensor(tn(LLM_TENSOR_ATTN_OUT, \"weight\", i), {n_embd, n_embd}, 0);\n\n                        layer.attn_out_norm   = create_tensor(tn(LLM_TENSOR_ATTN_OUT_NORM, \"weight\", i), {n_embd}, 0);\n\n                        layer.ffn_norm = create_tensor(tn(LLM_TENSOR_FFN_NORM, \"weight\", i), {n_embd}, 0);\n\n                        layer.ffn_gate = create_tensor(tn(LLM_TENSOR_FFN_GATE, \"weight\", i), {n_embd, n_ff}, TENSOR_NOT_REQUIRED);\n                        layer.ffn_down = create_tensor(tn(LLM_TENSOR_FFN_DOWN, \"weight\", i), {n_ff,   n_embd}, TENSOR_NOT_REQUIRED);\n                        layer.ffn_up   = create_tensor(tn(LLM_TENSOR_FFN_UP,   \"weight\", i), {n_embd, n_ff}, TENSOR_NOT_REQUIRED);\n\n                        layer.ffn_gate_inp  = create_tensor(tn(LLM_TENSOR_FFN_GATE_INP,  \"weight\", i), {n_embd, n_expert}, 0);\n                        layer.ffn_gate_exps = create_tensor(tn(LLM_TENSOR_FFN_GATE_EXPS, \"weight\", i), {n_embd,   n_ff_exp, n_expert}, TENSOR_NOT_REQUIRED);\n                        layer.ffn_down_exps = create_tensor(tn(LLM_TENSOR_FFN_DOWN_EXPS, \"weight\", i), {n_ff_exp, n_embd,   n_expert}, 0);\n                        layer.ffn_up_exps   = create_tensor(tn(LLM_TENSOR_FFN_UP_EXPS,   \"weight\", i), {n_embd,   n_ff_exp, n_expert}, 0);\n\n                        layer.ffn_post_norm = create_tensor(tn(LLM_TENSOR_LAYER_OUT_NORM, \"weight\", i), {n_embd}, TENSOR_NOT_REQUIRED);\n                        if (!layer.ffn_post_norm) {\n                            layer.ffn_post_norm = create_tensor(tn(LLM_TENSOR_FFN_POST_NORM, \"weight\", i), {n_embd}, 0);\n                        }\n                    }\n                } break;\n            case LLM_ARCH_DBRX:\n                {\n                    if (n_expert == 0) {\n                        throw std::runtime_error(\"DBRX model cannot have zero experts\");\n                    }\n\n                    tok_embd = create_tensor(tn(LLM_TENSOR_TOKEN_EMBD, \"weight\"), {n_embd, n_vocab}, 0);\n\n                    // output\n                    output_norm = create_tensor(tn(LLM_TENSOR_OUTPUT_NORM, \"weight\"), {n_embd}, 0);\n                    output      = create_tensor(tn(LLM_TENSOR_OUTPUT,      \"weight\"), {n_embd, n_vocab}, 0);\n\n                    for (int i = 0; i < n_layer; ++i) {\n                        auto & layer = layers[i];\n\n                        layer.attn_norm = create_tensor(tn(LLM_TENSOR_ATTN_NORM, \"weight\", i), {n_embd}, 0);\n\n                        layer.wqkv = create_tensor(tn(LLM_TENSOR_ATTN_QKV, \"weight\", i), {n_embd, n_embd + 2*n_embd_gqa}, 0);\n                        layer.wo   = create_tensor(tn(LLM_TENSOR_ATTN_OUT, \"weight\", i), {n_embd, n_embd}, 0);\n\n                        layer.attn_out_norm = create_tensor(tn(LLM_TENSOR_ATTN_OUT_NORM, \"weight\", i), {n_embd}, 0);\n\n                        layer.ffn_gate_inp  = create_tensor(tn(LLM_TENSOR_FFN_GATE_INP,  \"weight\", i), {n_embd, n_expert}, 0);\n                        layer.ffn_gate_exps = create_tensor(tn(LLM_TENSOR_FFN_GATE_EXPS, \"weight\", i), {n_embd, n_ff,   n_expert}, 0);\n                        layer.ffn_down_exps = create_tensor(tn(LLM_TENSOR_FFN_DOWN_EXPS, \"weight\", i), {n_ff,   n_embd, n_expert}, 0);\n                        layer.ffn_up_exps   = create_tensor(tn(LLM_TENSOR_FFN_UP_EXPS,   \"weight\", i), {n_embd, n_ff,   n_expert}, 0);\n                    }\n                } break;\n            case LLM_ARCH_BAICHUAN:\n                {\n                    tok_embd = create_tensor(tn(LLM_TENSOR_TOKEN_EMBD, \"weight\"), {n_embd, n_vocab}, 0);\n                    {\n                        output_norm = create_tensor(tn(LLM_TENSOR_OUTPUT_NORM, \"weight\"), {n_embd}, 0);\n                        output      = create_tensor(tn(LLM_TENSOR_OUTPUT,      \"weight\"), {n_embd, n_vocab}, 0);\n                    }\n\n                    for (int i = 0; i < n_layer; ++i) {\n                        auto & layer = layers[i];\n\n                        layer.attn_norm = create_tensor(tn(LLM_TENSOR_ATTN_NORM, \"weight\", i), {n_embd}, 0);\n\n                        layer.wq = create_tensor(tn(LLM_TENSOR_ATTN_Q,   \"weight\", i), {n_embd, n_embd}, 0);\n                        layer.wk = create_tensor(tn(LLM_TENSOR_ATTN_K,   \"weight\", i), {n_embd, n_embd_gqa}, 0);\n                        layer.wv = create_tensor(tn(LLM_TENSOR_ATTN_V,   \"weight\", i), {n_embd, n_embd_gqa}, 0);\n                        layer.wo = create_tensor(tn(LLM_TENSOR_ATTN_OUT, \"weight\", i), {n_embd, n_embd}, 0);\n\n                        layer.ffn_norm = create_tensor(tn(LLM_TENSOR_FFN_NORM, \"weight\", i), {n_embd}, 0);\n\n                        layer.ffn_gate = create_tensor(tn(LLM_TENSOR_FFN_GATE, \"weight\", i), {n_embd,   n_ff}, 0);\n                        layer.ffn_down = create_tensor(tn(LLM_TENSOR_FFN_DOWN, \"weight\", i), {  n_ff, n_embd}, 0);\n                        layer.ffn_up   = create_tensor(tn(LLM_TENSOR_FFN_UP,   \"weight\", i), {n_embd,   n_ff}, 0);\n                    }\n                } break;\n            case LLM_ARCH_FALCON:\n                {\n                    tok_embd = create_tensor(tn(LLM_TENSOR_TOKEN_EMBD, \"weight\"), {n_embd, n_vocab}, 0);\n\n                    // output\n                    {\n                        output_norm   = create_tensor(tn(LLM_TENSOR_OUTPUT_NORM, \"weight\"), {n_embd}, 0);\n                        output_norm_b = create_tensor(tn(LLM_TENSOR_OUTPUT_NORM, \"bias\"),   {n_embd}, 0);\n\n                        output = create_tensor(tn(LLM_TENSOR_OUTPUT, \"weight\"), {n_embd, n_vocab}, TENSOR_NOT_REQUIRED);\n                        if (!output) {\n                            output = create_tensor(tn(LLM_TENSOR_TOKEN_EMBD, \"weight\"), {n_embd, n_vocab}, TENSOR_DUPLICATED); // needs to be on GPU\n                        }\n                    }\n\n                    for (int i = 0; i < n_layer; ++i) {\n                        auto & layer = layers[i];\n\n                        layer.attn_norm   = create_tensor(tn(LLM_TENSOR_ATTN_NORM, \"weight\", i), {n_embd}, 0);\n                        layer.attn_norm_b = create_tensor(tn(LLM_TENSOR_ATTN_NORM, \"bias\", i),   {n_embd}, 0);\n\n                        layer.attn_norm_2   = create_tensor(tn(LLM_TENSOR_ATTN_NORM_2, \"weight\", i), {n_embd}, TENSOR_NOT_REQUIRED);\n                        layer.attn_norm_2_b = create_tensor(tn(LLM_TENSOR_ATTN_NORM_2, \"bias\", i),   {n_embd}, TENSOR_NOT_REQUIRED);\n\n                        layer.wqkv = create_tensor(tn(LLM_TENSOR_ATTN_QKV, \"weight\", i), {n_embd, n_embd + 2*n_embd_gqa}, 0);\n                        layer.wo   = create_tensor(tn(LLM_TENSOR_ATTN_OUT, \"weight\", i), {n_embd, n_embd}, 0);\n\n                        layer.ffn_down = create_tensor(tn(LLM_TENSOR_FFN_DOWN, \"weight\", i), {  n_ff, n_embd}, 0);\n                        layer.ffn_up   = create_tensor(tn(LLM_TENSOR_FFN_UP,   \"weight\", i), {n_embd,   n_ff}, 0);\n                    }\n                } break;\n            case LLM_ARCH_STARCODER:\n                {\n                    tok_embd = create_tensor(tn(LLM_TENSOR_TOKEN_EMBD, \"weight\"), {n_embd, n_vocab}, 0);\n                    pos_embd = create_tensor(tn(LLM_TENSOR_POS_EMBD,   \"weight\"), {n_embd, n_ctx_train}, 0);\n\n                    // output\n                    {\n                        output_norm   = create_tensor(tn(LLM_TENSOR_OUTPUT_NORM, \"weight\"), {n_embd}, 0);\n                        output_norm_b = create_tensor(tn(LLM_TENSOR_OUTPUT_NORM, \"bias\"),   {n_embd}, 0);\n                        output        = create_tensor(tn(LLM_TENSOR_OUTPUT,      \"weight\"), {n_embd, n_vocab}, TENSOR_NOT_REQUIRED);\n                        if (!output) {\n                            // needs to be on GPU\n                            output = create_tensor(tn(LLM_TENSOR_TOKEN_EMBD, \"weight\"), {n_embd, n_vocab}, TENSOR_DUPLICATED);\n                        }\n\n                    }\n\n                    for (int i = 0; i < n_layer; ++i) {\n                        auto & layer = layers[i];\n\n                        layer.attn_norm   = create_tensor(tn(LLM_TENSOR_ATTN_NORM, \"weight\", i), {n_embd}, 0);\n                        layer.attn_norm_b = create_tensor(tn(LLM_TENSOR_ATTN_NORM, \"bias\", i),   {n_embd}, 0);\n\n                        layer.wqkv = create_tensor(tn(LLM_TENSOR_ATTN_QKV, \"weight\", i), {n_embd, n_embd + 2*n_embd_gqa}, 0);\n                        layer.bqkv = create_tensor(tn(LLM_TENSOR_ATTN_QKV, \"bias\", i),   {n_embd + 2*n_embd_gqa}, 0);\n\n                        layer.wo = create_tensor(tn(LLM_TENSOR_ATTN_OUT, \"weight\", i), {n_embd, n_embd}, 0);\n                        layer.bo = create_tensor(tn(LLM_TENSOR_ATTN_OUT, \"bias\", i),   {n_embd}, 0);\n\n                        layer.ffn_norm   = create_tensor(tn(LLM_TENSOR_FFN_NORM, \"weight\", i), {n_embd}, 0);\n                        layer.ffn_norm_b = create_tensor(tn(LLM_TENSOR_FFN_NORM, \"bias\", i),   {n_embd}, 0);\n\n                        layer.ffn_down   = create_tensor(tn(LLM_TENSOR_FFN_DOWN, \"weight\", i), {n_ff, n_embd}, 0);\n                        layer.ffn_down_b = create_tensor(tn(LLM_TENSOR_FFN_DOWN, \"bias\", i),   {n_embd}, 0);\n\n                        layer.ffn_up   = create_tensor(tn(LLM_TENSOR_FFN_UP, \"weight\", i),   {n_embd, n_ff}, 0);\n                        layer.ffn_up_b = create_tensor(tn(LLM_TENSOR_FFN_UP, \"bias\", i),     {n_ff}, 0);\n                    }\n                } break;\n            case LLM_ARCH_BERT:\n            case LLM_ARCH_NOMIC_BERT:\n            case LLM_ARCH_NOMIC_BERT_MOE:\n            case LLM_ARCH_JINA_BERT_V3:\n                {\n                    tok_embd     = create_tensor(tn(LLM_TENSOR_TOKEN_EMBD,  \"weight\"), {n_embd, n_vocab}, 0);\n                    type_embd    = create_tensor(tn(LLM_TENSOR_TOKEN_TYPES, \"weight\"), {n_embd, n_token_types}, TENSOR_NOT_REQUIRED);\n\n                    if (arch == LLM_ARCH_BERT) {\n                        pos_embd = create_tensor(tn(LLM_TENSOR_POS_EMBD,    \"weight\"), {n_embd, n_ctx_train}, 0);\n\n                        cls   = create_tensor(tn(LLM_TENSOR_CLS, \"weight\"), {n_embd, n_embd}, TENSOR_NOT_REQUIRED);\n                        cls_b = create_tensor(tn(LLM_TENSOR_CLS, \"bias\"),   {n_embd},         TENSOR_NOT_REQUIRED);\n\n                        cls_out   = create_tensor(tn(LLM_TENSOR_CLS_OUT, \"weight\"), {n_embd, hparams.n_cls_out}, TENSOR_NOT_REQUIRED);\n                        cls_out_b = create_tensor(tn(LLM_TENSOR_CLS_OUT, \"bias\"),   {hparams.n_cls_out},         TENSOR_NOT_REQUIRED);\n                    }\n\n                    tok_norm   = create_tensor(tn(LLM_TENSOR_TOKEN_EMBD_NORM, \"weight\"), {n_embd}, 0);\n                    tok_norm_b = create_tensor(tn(LLM_TENSOR_TOKEN_EMBD_NORM, \"bias\"),   {n_embd}, 0);\n\n                    for (int i = 0; i < n_layer; ++i) {\n                        auto & layer = layers[i];\n\n                        layer.wqkv = create_tensor(tn(LLM_TENSOR_ATTN_QKV, \"weight\", i), {n_embd, n_embd + 2*n_embd_gqa}, TENSOR_NOT_REQUIRED);\n                        layer.bqkv = create_tensor(tn(LLM_TENSOR_ATTN_QKV, \"bias\", i), {n_embd + 2*n_embd_gqa}, TENSOR_NOT_REQUIRED);\n\n                        if (!layer.wqkv) {\n                            layer.wq = create_tensor(tn(LLM_TENSOR_ATTN_Q,   \"weight\", i), {n_embd, n_embd}, 0);\n                            layer.bq = create_tensor(tn(LLM_TENSOR_ATTN_Q,   \"bias\", i),   {n_embd}, 0);\n\n                            layer.wk = create_tensor(tn(LLM_TENSOR_ATTN_K,   \"weight\", i), {n_embd, n_embd_gqa}, 0);\n                            layer.bk = create_tensor(tn(LLM_TENSOR_ATTN_K,   \"bias\", i),   {n_embd_gqa}, 0);\n\n                            layer.wv = create_tensor(tn(LLM_TENSOR_ATTN_V,   \"weight\", i), {n_embd, n_embd_gqa}, 0);\n                            layer.bv = create_tensor(tn(LLM_TENSOR_ATTN_V,   \"bias\", i),   {n_embd_gqa}, 0);\n                        }\n\n                        layer.wo = create_tensor(tn(LLM_TENSOR_ATTN_OUT,      \"weight\", i), {n_embd, n_embd}, 0);\n                        layer.bo = create_tensor(tn(LLM_TENSOR_ATTN_OUT,      \"bias\", i),   {n_embd}, TENSOR_NOT_REQUIRED);\n\n                        layer.attn_out_norm   = create_tensor(tn(LLM_TENSOR_ATTN_OUT_NORM, \"weight\", i), {n_embd}, 0);\n                        layer.attn_out_norm_b = create_tensor(tn(LLM_TENSOR_ATTN_OUT_NORM, \"bias\", i),   {n_embd}, 0);\n\n                        if (hparams.moe_every_n_layers > 0 && i % hparams.moe_every_n_layers == 1) {\n                            layer.ffn_up_exps   = create_tensor(tn(LLM_TENSOR_FFN_UP_EXPS,   \"weight\", i), {  n_embd, n_ff,   n_expert}, 0);\n                            layer.ffn_down_exps = create_tensor(tn(LLM_TENSOR_FFN_DOWN_EXPS, \"weight\", i), {  n_ff,   n_embd, n_expert}, 0);\n                            layer.ffn_gate_inp = create_tensor(tn(LLM_TENSOR_FFN_GATE_INP,   \"weight\", i), {n_embd, n_expert}, 0);\n                        } else {\n                            layer.ffn_up     = create_tensor(tn(LLM_TENSOR_FFN_UP,   \"weight\", i), {n_embd, n_ff}, 0);\n                            layer.ffn_up_b   = create_tensor(tn(LLM_TENSOR_FFN_UP,   \"bias\", i),   {n_ff}, TENSOR_NOT_REQUIRED);\n                            layer.ffn_down   = create_tensor(tn(LLM_TENSOR_FFN_DOWN, \"weight\", i), {n_ff, n_embd}, 0);\n                            layer.ffn_down_b = create_tensor(tn(LLM_TENSOR_FFN_DOWN, \"bias\", i),   {n_embd}, TENSOR_NOT_REQUIRED);\n\n                            if (arch == LLM_ARCH_NOMIC_BERT) {\n                                layer.ffn_gate = create_tensor(tn(LLM_TENSOR_FFN_GATE, \"weight\", i), {n_embd, n_ff}, 0);\n                            }\n                        }\n\n                        layer.layer_out_norm   = create_tensor(tn(LLM_TENSOR_LAYER_OUT_NORM, \"weight\", i), {n_embd}, 0);\n                        layer.layer_out_norm_b = create_tensor(tn(LLM_TENSOR_LAYER_OUT_NORM, \"bias\", i),   {n_embd}, 0);\n                    }\n                } break;\n            case LLM_ARCH_NEO_BERT:\n                {\n                    tok_embd = create_tensor(tn(LLM_TENSOR_TOKEN_EMBD,  \"weight\"), {n_embd, n_vocab}, 0);\n\n                    cls   = create_tensor(tn(LLM_TENSOR_CLS, \"weight\"), {n_embd, n_embd}, TENSOR_NOT_REQUIRED);\n                    cls_b = create_tensor(tn(LLM_TENSOR_CLS, \"bias\"),   {n_embd},         TENSOR_NOT_REQUIRED);\n\n                    cls_out   = create_tensor(tn(LLM_TENSOR_CLS_OUT, \"weight\"), {n_embd, hparams.n_cls_out}, TENSOR_NOT_REQUIRED);\n                    cls_out_b = create_tensor(tn(LLM_TENSOR_CLS_OUT, \"bias\"),   {hparams.n_cls_out},         TENSOR_NOT_REQUIRED);\n\n                    output_norm_enc = create_tensor(tn(LLM_TENSOR_ENC_OUTPUT_NORM, \"weight\"), {n_embd}, 0);\n\n                    for (int i = 0; i < n_layer; ++i) {\n                        auto & layer = layers[i];\n\n                        layer.attn_norm = create_tensor(tn(LLM_TENSOR_ATTN_NORM, \"weight\", i), {n_embd}, 0);\n\n                        layer.wqkv = create_tensor(tn(LLM_TENSOR_ATTN_QKV, \"weight\", i), {n_embd, n_embd + 2*n_embd_gqa}, 0);\n                        layer.wo   = create_tensor(tn(LLM_TENSOR_ATTN_OUT, \"weight\", i), {n_embd, n_embd}, 0);\n\n                        layer.ffn_norm = create_tensor(tn(LLM_TENSOR_FFN_NORM, \"weight\", i), {n_embd}, 0);\n\n                        layer.ffn_up   = create_tensor(tn(LLM_TENSOR_FFN_UP,   \"weight\", i), {n_embd, n_ff*2}, 0);\n                        layer.ffn_down = create_tensor(tn(LLM_TENSOR_FFN_DOWN, \"weight\", i), {n_ff, n_embd}, 0);\n                    }\n                } break;\n            case LLM_ARCH_JINA_BERT_V2:\n                {\n                    tok_embd  = create_tensor(tn(LLM_TENSOR_TOKEN_EMBD,  \"weight\"), {n_embd, n_vocab}, 0); // word_embeddings\n                    type_embd = create_tensor(tn(LLM_TENSOR_TOKEN_TYPES, \"weight\"), {n_embd, n_token_types}, 0); // token_type_embeddings\n\n                    tok_norm   = create_tensor(tn(LLM_TENSOR_TOKEN_EMBD_NORM, \"weight\"), {n_embd}, 0); // LayerNorm\n                    tok_norm_b = create_tensor(tn(LLM_TENSOR_TOKEN_EMBD_NORM, \"bias\"),   {n_embd}, 0); //LayerNorm bias\n\n                    cls   = create_tensor(tn(LLM_TENSOR_CLS, \"weight\"), {n_embd, 1}, TENSOR_NOT_REQUIRED);\n                    cls_b = create_tensor(tn(LLM_TENSOR_CLS, \"bias\"),   {1},         TENSOR_NOT_REQUIRED);\n                    for (int i = 0; i < n_layer; ++i) {\n                        auto & layer = layers[i]; // JinaBertLayer\n\n                        layer.wq = create_tensor(tn(LLM_TENSOR_ATTN_Q, \"weight\", i), {n_embd, n_embd}, 0);\n                        layer.bq = create_tensor(tn(LLM_TENSOR_ATTN_Q, \"bias\", i),   {n_embd}, 0);\n\n                        layer.attn_q_norm   = create_tensor(tn(LLM_TENSOR_ATTN_Q_NORM, \"weight\", i), {n_embd}, TENSOR_NOT_REQUIRED);\n                        layer.attn_q_norm_b = create_tensor(tn(LLM_TENSOR_ATTN_Q_NORM, \"bias\",   i), {n_embd}, TENSOR_NOT_REQUIRED);\n\n                        layer.wk = create_tensor(tn(LLM_TENSOR_ATTN_K, \"weight\", i), {n_embd, n_embd_gqa}, 0);\n                        layer.bk = create_tensor(tn(LLM_TENSOR_ATTN_K, \"bias\",   i), {n_embd_gqa}, 0);\n\n                        layer.attn_k_norm   = create_tensor(tn(LLM_TENSOR_ATTN_K_NORM, \"weight\", i), {n_embd}, TENSOR_NOT_REQUIRED);\n                        layer.attn_k_norm_b = create_tensor(tn(LLM_TENSOR_ATTN_K_NORM, \"bias\",   i), {n_embd}, TENSOR_NOT_REQUIRED);\n\n                        layer.wv = create_tensor(tn(LLM_TENSOR_ATTN_V, \"weight\", i), {n_embd, n_embd_gqa}, 0);\n                        layer.bv = create_tensor(tn(LLM_TENSOR_ATTN_V, \"bias\",   i), {n_embd_gqa}, 0);\n\n                        layer.wo = create_tensor(tn(LLM_TENSOR_ATTN_OUT, \"weight\", i), {n_embd, n_embd}, 0); //output_dens\n                        layer.bo = create_tensor(tn(LLM_TENSOR_ATTN_OUT, \"bias\",   i), {n_embd}, 0); //output_dens\n\n                        layer.attn_out_norm   = create_tensor(tn(LLM_TENSOR_ATTN_OUT_NORM, \"weight\", i), {n_embd}, 0); //output_norm\n                        layer.attn_out_norm_b = create_tensor(tn(LLM_TENSOR_ATTN_OUT_NORM, \"bias\",   i), {n_embd}, 0);\n\n                        layer.attn_norm_2   = create_tensor(tn(LLM_TENSOR_ATTN_NORM_2, \"weight\", i), {n_embd}, TENSOR_NOT_REQUIRED);\n                        layer.attn_norm_2_b = create_tensor(tn(LLM_TENSOR_ATTN_NORM_2, \"bias\",   i), {n_embd}, TENSOR_NOT_REQUIRED);\n\n                        layer.ffn_gate = create_tensor(tn(LLM_TENSOR_FFN_GATE, \"weight\", i), {n_embd, n_ff}, TENSOR_NOT_REQUIRED);\n                        layer.ffn_up   = create_tensor(tn(LLM_TENSOR_FFN_UP,   \"weight\", i), {n_embd, layer.ffn_gate ? n_ff : n_ff * 2}, 0);\n\n                        layer.ffn_down   = create_tensor(tn(LLM_TENSOR_FFN_DOWN, \"weight\", i), {n_ff, n_embd}, 0);\n                        layer.ffn_down_b = create_tensor(tn(LLM_TENSOR_FFN_DOWN, \"bias\",   i), {n_embd}, 0);\n\n                        layer.layer_out_norm   = create_tensor(tn(LLM_TENSOR_LAYER_OUT_NORM, \"weight\", i), {n_embd}, 0);\n                        layer.layer_out_norm_b = create_tensor(tn(LLM_TENSOR_LAYER_OUT_NORM, \"bias\",   i), {n_embd}, 0);\n                    }\n                } break;\n            case LLM_ARCH_BLOOM:\n                {\n                    tok_embd   = create_tensor(tn(LLM_TENSOR_TOKEN_EMBD,      \"weight\"), {n_embd, n_vocab}, 0);\n                    tok_norm   = create_tensor(tn(LLM_TENSOR_TOKEN_EMBD_NORM, \"weight\"), {n_embd}, 0);\n                    tok_norm_b = create_tensor(tn(LLM_TENSOR_TOKEN_EMBD_NORM, \"bias\"),   {n_embd}, 0);\n\n                    // output\n                    output_norm   = create_tensor(tn(LLM_TENSOR_OUTPUT_NORM, \"weight\"), {n_embd}, 0);\n                    output_norm_b = create_tensor(tn(LLM_TENSOR_OUTPUT_NORM, \"bias\"),   {n_embd}, 0);\n                    output        = create_tensor(tn(LLM_TENSOR_OUTPUT,      \"weight\"), {n_embd, n_vocab}, TENSOR_NOT_REQUIRED);\n\n                    // if output is NULL, init from the input tok embed\n                    if (output == NULL) {\n                        output = create_tensor(tn(LLM_TENSOR_TOKEN_EMBD, \"weight\"), {n_embd, n_vocab}, TENSOR_DUPLICATED);\n                    }\n\n                    for (int i = 0; i < n_layer; ++i) {\n                        auto & layer = layers[i];\n\n                        layer.attn_norm   = create_tensor(tn(LLM_TENSOR_ATTN_NORM, \"weight\", i), {n_embd}, 0);\n                        layer.attn_norm_b = create_tensor(tn(LLM_TENSOR_ATTN_NORM, \"bias\",   i), {n_embd}, 0);\n\n                        layer.wqkv = create_tensor(tn(LLM_TENSOR_ATTN_QKV, \"weight\", i), {n_embd, n_embd + 2*n_embd_gqa}, 0);\n                        layer.bqkv = create_tensor(tn(LLM_TENSOR_ATTN_QKV, \"bias\",   i), {n_embd + 2*n_embd_gqa}, 0);\n\n                        layer.wo   = create_tensor(tn(LLM_TENSOR_ATTN_OUT, \"weight\", i), {n_embd, n_embd}, 0);\n                        layer.bo   = create_tensor(tn(LLM_TENSOR_ATTN_OUT, \"bias\",   i), {n_embd}, 0);\n\n                        layer.ffn_norm   = create_tensor(tn(LLM_TENSOR_FFN_NORM, \"weight\", i), {n_embd}, 0);\n                        layer.ffn_norm_b = create_tensor(tn(LLM_TENSOR_FFN_NORM, \"bias\",   i), {n_embd}, 0);\n\n                        layer.ffn_down   = create_tensor(tn(LLM_TENSOR_FFN_DOWN, \"weight\", i), {n_ff, n_embd}, 0);\n                        layer.ffn_down_b = create_tensor(tn(LLM_TENSOR_FFN_DOWN, \"bias\",   i), {n_embd}, 0);\n\n                        layer.ffn_up     = create_tensor(tn(LLM_TENSOR_FFN_UP, \"weight\", i), {n_embd, n_ff}, 0);\n                        layer.ffn_up_b   = create_tensor(tn(LLM_TENSOR_FFN_UP, \"bias\",   i), {n_ff}, 0);\n                    }\n                } break;\n            case LLM_ARCH_MPT:\n                {\n                    tok_embd = create_tensor(tn(LLM_TENSOR_TOKEN_EMBD, \"weight\"), {n_embd, n_vocab}, 0);\n                    pos_embd = create_tensor(tn(LLM_TENSOR_POS_EMBD,   \"weight\"), {n_embd, n_ctx_train}, TENSOR_NOT_REQUIRED);\n\n                    // output\n                    output_norm   = create_tensor(tn(LLM_TENSOR_OUTPUT_NORM, \"weight\"), {n_embd}, 0);\n                    output_norm_b = create_tensor(tn(LLM_TENSOR_OUTPUT_NORM, \"bias\"),   {n_embd}, TENSOR_NOT_REQUIRED);\n\n                    output        = create_tensor(tn(LLM_TENSOR_OUTPUT, \"weight\"), {n_embd, n_vocab}, TENSOR_NOT_REQUIRED);\n                    if (!output) {\n                        output    = create_tensor(tn(LLM_TENSOR_TOKEN_EMBD, \"weight\"), {n_embd, n_vocab}, TENSOR_DUPLICATED); // needs to be on GPU\n                    }\n\n                    for (int i = 0; i < n_layer; ++i) {\n                        auto & layer = layers[i];\n\n                        layer.attn_norm   = create_tensor(tn(LLM_TENSOR_ATTN_NORM, \"weight\", i), {n_embd}, 0);\n                        layer.attn_norm_b = create_tensor(tn(LLM_TENSOR_ATTN_NORM, \"bias\", i),   {n_embd}, TENSOR_NOT_REQUIRED);\n\n                        layer.wqkv = create_tensor(tn(LLM_TENSOR_ATTN_QKV, \"weight\", i), {n_embd, n_embd + 2*n_embd_gqa}, 0);\n                        layer.bqkv = create_tensor(tn(LLM_TENSOR_ATTN_QKV, \"bias\", i),   {n_embd + 2*n_embd_gqa}, TENSOR_NOT_REQUIRED);\n\n                        layer.wo   = create_tensor(tn(LLM_TENSOR_ATTN_OUT, \"weight\", i), {n_embd, n_embd}, 0);\n                        layer.bo   = create_tensor(tn(LLM_TENSOR_ATTN_OUT, \"bias\", i),   {n_embd}, TENSOR_NOT_REQUIRED);\n\n                        layer.ffn_norm   = create_tensor(tn(LLM_TENSOR_FFN_NORM, \"weight\", i), {n_embd}, 0);\n                        layer.ffn_norm_b = create_tensor(tn(LLM_TENSOR_FFN_NORM, \"bias\", i),   {n_embd}, TENSOR_NOT_REQUIRED);\n\n                        layer.ffn_down   = create_tensor(tn(LLM_TENSOR_FFN_DOWN, \"weight\", i), {n_ff, n_embd}, 0);\n                        layer.ffn_down_b = create_tensor(tn(LLM_TENSOR_FFN_DOWN, \"bias\", i),   {n_embd}, TENSOR_NOT_REQUIRED);\n\n                        layer.ffn_up     = create_tensor(tn(LLM_TENSOR_FFN_UP,   \"weight\", i), {n_embd,   n_ff}, 0);\n                        layer.ffn_up_b   = create_tensor(tn(LLM_TENSOR_FFN_UP,   \"bias\", i),   {n_ff}, TENSOR_NOT_REQUIRED);\n\n                        layer.attn_q_norm   = create_tensor(tn(LLM_TENSOR_ATTN_Q_NORM, \"weight\", i), {n_embd}, TENSOR_NOT_REQUIRED);\n                        layer.attn_q_norm_b = create_tensor(tn(LLM_TENSOR_ATTN_Q_NORM, \"bias\",   i), {n_embd}, TENSOR_NOT_REQUIRED);\n\n                        layer.attn_k_norm   = create_tensor(tn(LLM_TENSOR_ATTN_K_NORM, \"weight\", i), {n_embd}, TENSOR_NOT_REQUIRED);\n                        layer.attn_k_norm_b = create_tensor(tn(LLM_TENSOR_ATTN_K_NORM, \"bias\",   i), {n_embd}, TENSOR_NOT_REQUIRED);\n\n                        // AWQ ScaleActivation layer\n                        layer.ffn_act = create_tensor(tn(LLM_TENSOR_FFN_ACT, \"scales\", i), {n_ff}, TENSOR_NOT_REQUIRED);\n                    }\n                } break;\n            case LLM_ARCH_STABLELM:\n                {\n                    tok_embd = create_tensor(tn(LLM_TENSOR_TOKEN_EMBD, \"weight\"), {n_embd, n_vocab}, 0);\n\n                    // output\n                    output_norm_b = create_tensor(tn(LLM_TENSOR_OUTPUT_NORM, \"bias\"),   {n_embd}, 0);\n                    output_norm   = create_tensor(tn(LLM_TENSOR_OUTPUT_NORM, \"weight\"), {n_embd}, 0);\n                    output        = create_tensor(tn(LLM_TENSOR_OUTPUT,      \"weight\"), {n_embd, n_vocab}, 0);\n\n                    for (int i = 0; i < n_layer; ++i) {\n                        auto & layer = layers[i];\n\n                        layer.attn_norm =   create_tensor(tn(LLM_TENSOR_ATTN_NORM, \"weight\", i), {n_embd}, 0);\n                        layer.attn_norm_b = create_tensor(tn(LLM_TENSOR_ATTN_NORM, \"bias\", i), {n_embd}, 0);\n\n                        layer.wq = create_tensor(tn(LLM_TENSOR_ATTN_Q,   \"weight\", i), {n_embd, n_embd}, 0);\n                        layer.wk = create_tensor(tn(LLM_TENSOR_ATTN_K,   \"weight\", i), {n_embd, n_embd_gqa}, 0);\n                        layer.wv = create_tensor(tn(LLM_TENSOR_ATTN_V,   \"weight\", i), {n_embd, n_embd_gqa}, 0);\n                        layer.wo = create_tensor(tn(LLM_TENSOR_ATTN_OUT, \"weight\", i), {n_embd, n_embd}, 0);\n\n                        // optional bias tensors, present in Stable LM 2 1.6B\n                        layer.bq = create_tensor(tn(LLM_TENSOR_ATTN_Q,   \"bias\", i), {n_embd},     TENSOR_NOT_REQUIRED);\n                        layer.bk = create_tensor(tn(LLM_TENSOR_ATTN_K,   \"bias\", i), {n_embd_gqa}, TENSOR_NOT_REQUIRED);\n                        layer.bv = create_tensor(tn(LLM_TENSOR_ATTN_V,   \"bias\", i), {n_embd_gqa}, TENSOR_NOT_REQUIRED);\n\n                        // optional q and k layernorms, present in StableLM 2 12B\n                        layer.attn_q_norm = create_tensor(tn(LLM_TENSOR_ATTN_Q_NORM, \"weight\", i), {n_embd_head_k, n_head},    TENSOR_NOT_REQUIRED);\n                        layer.attn_k_norm = create_tensor(tn(LLM_TENSOR_ATTN_K_NORM, \"weight\", i), {n_embd_head_k, n_head_kv}, TENSOR_NOT_REQUIRED);\n\n                        // optional FFN norm, not present in StableLM 2 12B which uses parallel residual\n                        layer.ffn_norm   = create_tensor(tn(LLM_TENSOR_FFN_NORM, \"weight\", i), {n_embd}, TENSOR_NOT_REQUIRED);\n                        layer.ffn_norm_b = create_tensor(tn(LLM_TENSOR_FFN_NORM, \"bias\", i),   {n_embd}, TENSOR_NOT_REQUIRED);\n\n                        layer.ffn_gate = create_tensor(tn(LLM_TENSOR_FFN_GATE, \"weight\", i), {n_embd,   n_ff}, 0);\n                        layer.ffn_down = create_tensor(tn(LLM_TENSOR_FFN_DOWN, \"weight\", i), {  n_ff, n_embd}, 0);\n                        layer.ffn_up   = create_tensor(tn(LLM_TENSOR_FFN_UP,   \"weight\", i), {n_embd,   n_ff}, 0);\n                    }\n                } break;\n            case LLM_ARCH_QWEN:\n                {\n                    tok_embd = create_tensor(tn(LLM_TENSOR_TOKEN_EMBD, \"weight\"), {n_embd, n_vocab}, 0);\n\n                    // output\n                    output_norm = create_tensor(tn(LLM_TENSOR_OUTPUT_NORM, \"weight\"), {n_embd}, 0);\n                    output      = create_tensor(tn(LLM_TENSOR_OUTPUT,      \"weight\"), {n_embd, n_vocab}, 0);\n\n                    for (int i = 0; i < n_layer; ++i) {\n                        auto & layer = layers[i];\n\n                        layer.attn_norm = create_tensor(tn(LLM_TENSOR_ATTN_NORM, \"weight\", i), {n_embd}, 0);\n\n                        layer.wqkv = create_tensor(tn(LLM_TENSOR_ATTN_QKV, \"weight\", i), {n_embd, n_embd*3}, 0);\n                        layer.bqkv = create_tensor(tn(LLM_TENSOR_ATTN_QKV, \"bias\", i),   {n_embd*3}, 0);\n                        layer.wo   = create_tensor(tn(LLM_TENSOR_ATTN_OUT, \"weight\", i), {n_embd, n_embd}, 0);\n\n                        layer.ffn_norm = create_tensor(tn(LLM_TENSOR_FFN_NORM, \"weight\", i), {n_embd}, 0);\n\n                        layer.ffn_gate = create_tensor(tn(LLM_TENSOR_FFN_GATE, \"weight\", i), {n_embd, n_ff/2}, 0);\n                        layer.ffn_down = create_tensor(tn(LLM_TENSOR_FFN_DOWN, \"weight\", i), {n_ff/2, n_embd}, 0);\n                        layer.ffn_up   = create_tensor(tn(LLM_TENSOR_FFN_UP,   \"weight\", i), {n_embd, n_ff/2}, 0);\n                    }\n                } break;\n            case LLM_ARCH_QWEN2:\n            case LLM_ARCH_QWEN2VL:\n            case LLM_ARCH_DREAM:\n                {\n                    tok_embd = create_tensor(tn(LLM_TENSOR_TOKEN_EMBD, \"weight\"), {n_embd, n_vocab}, 0);\n\n                    // output\n                    output_norm = create_tensor(tn(LLM_TENSOR_OUTPUT_NORM, \"weight\"), {n_embd}, 0);\n                    output      = create_tensor(tn(LLM_TENSOR_OUTPUT,      \"weight\"), {n_embd, n_vocab}, TENSOR_NOT_REQUIRED);\n                    output_b    = create_tensor(tn(LLM_TENSOR_OUTPUT,      \"bias\"),   {n_vocab}, TENSOR_NOT_REQUIRED);\n                    // if output is NULL, init from the input tok embed\n                    if (output == NULL) {\n                        output = create_tensor(tn(LLM_TENSOR_TOKEN_EMBD, \"weight\"), {n_embd, n_vocab}, TENSOR_DUPLICATED);\n                    }\n\n                    for (int i = 0; i < n_layer; ++i) {\n                        auto & layer = layers[i];\n\n                        layer.attn_norm = create_tensor(tn(LLM_TENSOR_ATTN_NORM, \"weight\", i), {n_embd}, 0);\n\n                        layer.wq = create_tensor(tn(LLM_TENSOR_ATTN_Q,   \"weight\", i), {n_embd, n_embd}, 0);\n                        layer.wk = create_tensor(tn(LLM_TENSOR_ATTN_K,   \"weight\", i), {n_embd, n_embd_gqa}, 0);\n                        layer.wv = create_tensor(tn(LLM_TENSOR_ATTN_V,   \"weight\", i), {n_embd, n_embd_gqa}, 0);\n                        layer.wo = create_tensor(tn(LLM_TENSOR_ATTN_OUT, \"weight\", i), {n_embd, n_embd}, 0);\n\n                        // optional bias tensors\n                        layer.bq = create_tensor(tn(LLM_TENSOR_ATTN_Q,   \"bias\", i), {n_embd}, 0);\n                        layer.bk = create_tensor(tn(LLM_TENSOR_ATTN_K,   \"bias\", i), {n_embd_gqa}, 0);\n                        layer.bv = create_tensor(tn(LLM_TENSOR_ATTN_V,   \"bias\", i), {n_embd_gqa}, 0);\n\n                        layer.ffn_norm = create_tensor(tn(LLM_TENSOR_FFN_NORM, \"weight\", i), {n_embd}, 0);\n\n                        layer.ffn_gate = create_tensor(tn(LLM_TENSOR_FFN_GATE, \"weight\", i), {n_embd,   n_ff}, 0);\n                        layer.ffn_down = create_tensor(tn(LLM_TENSOR_FFN_DOWN, \"weight\", i), {  n_ff, n_embd}, 0);\n                        layer.ffn_up   = create_tensor(tn(LLM_TENSOR_FFN_UP,   \"weight\", i), {n_embd,   n_ff}, 0);\n                    }\n                } break;\n            case LLM_ARCH_QWEN2MOE:\n                {\n                    tok_embd = create_tensor(tn(LLM_TENSOR_TOKEN_EMBD, \"weight\"), {n_embd, n_vocab}, 0);\n\n                    // output\n                    output_norm = create_tensor(tn(LLM_TENSOR_OUTPUT_NORM, \"weight\"), {n_embd}, 0);\n                    output      = create_tensor(tn(LLM_TENSOR_OUTPUT,      \"weight\"), {n_embd, n_vocab}, 0);\n\n                    for (int i = 0; i < n_layer; ++i) {\n                        auto & layer = layers[i];\n\n                        layer.attn_norm = create_tensor(tn(LLM_TENSOR_ATTN_NORM, \"weight\", i), {n_embd}, 0);\n\n                        layer.wq = create_tensor(tn(LLM_TENSOR_ATTN_Q,   \"weight\", i), {n_embd, n_embd}, 0);\n                        layer.wk = create_tensor(tn(LLM_TENSOR_ATTN_K,   \"weight\", i), {n_embd, n_embd_gqa}, 0);\n                        layer.wv = create_tensor(tn(LLM_TENSOR_ATTN_V,   \"weight\", i), {n_embd, n_embd_gqa}, 0);\n                        layer.wo = create_tensor(tn(LLM_TENSOR_ATTN_OUT, \"weight\", i), {n_embd, n_embd}, 0);\n\n                        // optional bias tensors\n                        layer.bq = create_tensor(tn(LLM_TENSOR_ATTN_Q,   \"bias\", i), {n_embd}, TENSOR_NOT_REQUIRED);\n                        layer.bk = create_tensor(tn(LLM_TENSOR_ATTN_K,   \"bias\", i), {n_embd_gqa}, TENSOR_NOT_REQUIRED);\n                        layer.bv = create_tensor(tn(LLM_TENSOR_ATTN_V,   \"bias\", i), {n_embd_gqa}, TENSOR_NOT_REQUIRED);\n\n                        layer.ffn_norm = create_tensor(tn(LLM_TENSOR_FFN_NORM, \"weight\", i), {n_embd}, 0);\n\n                        layer.ffn_gate_inp = create_tensor(tn(LLM_TENSOR_FFN_GATE_INP, \"weight\", i), {n_embd, n_expert}, 0);\n\n                        if (n_expert == 0) {\n                            throw std::runtime_error(\"n_expert must be > 0 for QWEN2MOE\");\n                        }\n                        if (n_expert_used == 0) {\n                            throw std::runtime_error(\"n_expert_used must be > 0 for QWEN2MOE\");\n                        }\n\n                        // MoE branch\n                        const int64_t n_ff_exp = hparams.n_ff_exp ? hparams.n_ff_exp : n_ff / n_expert_used;\n\n                        layer.ffn_gate_exps = create_tensor(tn(LLM_TENSOR_FFN_GATE_EXPS, \"weight\", i), {  n_embd, n_ff_exp, n_expert}, 0);\n                        layer