INSERT INTO `error` VALUES (1,'ArithmeticError','','A math operation failed (base class for arithmetic errors).',NULL,NULL,123,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',1,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(2,'AssertionError','','An assertion statement failed.',NULL,NULL,122,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',2,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(3,'AttributeError','ATTRIBUTE_MISSING','You tried to access an attribute that does not exist.','Object does not have the requested attribute. Usually means __init__ did not set it, or method name is misspelled.','Check __init__ for self.attr assignment. Verify method name spelling. Check if method is registered in class registry.',126,35025,169,42,17,14,NULL,2,0.92,'vb_shared','know_problems',3,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(4,'BaseExceptionGroup','','A group of base exceptions occurred.',NULL,NULL,132,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',4,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(5,'BlockingIOError','','An I/O operation would block the system.',NULL,NULL,125,35025,51,42,17,14,NULL,1,0.00,'vb_shared','know_problems',5,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(6,'BrokenPipeError','','A pipe connection was broken during writing.',NULL,NULL,125,35025,51,42,17,14,NULL,1,0.00,'vb_shared','know_problems',6,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(7,'BufferError','','A buffer operation failed.',NULL,NULL,125,35025,51,42,17,14,NULL,1,0.00,'vb_shared','know_problems',7,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(8,'BytesWarning','','Mixing bytes and text in a way that may cause issues.',NULL,NULL,133,34870,277,42,18,14,NULL,1,0.00,'vb_shared','know_problems',8,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(9,'ChildProcessError','','A child process operation failed.',NULL,NULL,132,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',9,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(10,'ConnectionAbortedError','','A connection was aborted.',NULL,NULL,125,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',10,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(11,'ConnectionError','CONNECTION_REFUSED','A connection-related error occurred.','Service not running or port blocked.','Check if service is running. Verify port and host.',125,35025,169,42,17,14,NULL,1,0.85,'vb_shared','know_problems',11,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(12,'ConnectionRefusedError','','A connection attempt was refused.',NULL,NULL,125,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',12,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(13,'ConnectionResetError','','A connection was reset by the peer.',NULL,NULL,125,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',13,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(14,'DeprecationWarning','','Using deprecated features that will be removed.',NULL,NULL,133,34870,277,42,18,14,NULL,1,0.00,'vb_shared','know_problems',14,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(15,'EOFError','','End of file was reached unexpectedly.',NULL,NULL,125,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',15,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(16,'EncodingWarning','','Encoding issues in file operations.',NULL,NULL,133,34870,277,42,18,14,NULL,1,0.00,'vb_shared','know_problems',16,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(17,'EnvironmentError','','An environment-related error occurred.',NULL,NULL,NULL,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',17,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(18,'Exception','','An unexpected error occurred.',NULL,NULL,92,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',18,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(19,'ExceptionGroup','','A group of exceptions occurred.',NULL,NULL,92,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',19,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(20,'FileExistsError','','The file you are trying to create already exists.',NULL,NULL,125,35025,51,42,17,14,NULL,1,0.00,'vb_shared','know_problems',20,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(21,'FileNotFoundError','FILE_NOT_FOUND','The system could not find the file.','File path does not exist or is not accessible.','Check path with os.path.exists(). Verify working directory.',125,35025,51,42,17,14,NULL,1,0.94,'vb_shared','know_problems',21,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(22,'FloatingPointError','','A floating-point math operation failed.',NULL,NULL,123,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',22,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(23,'FutureWarning','','Using features that will change in future versions.',NULL,NULL,133,34870,277,42,18,14,NULL,1,0.00,'vb_shared','know_problems',23,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(24,'GeneratorExit','','A generator was closed before it finished.',NULL,NULL,132,35025,169,42,16,14,NULL,1,0.00,'vb_shared','know_problems',24,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(25,'IOError','','An input/output operation failed.',NULL,NULL,125,35025,51,42,17,14,NULL,1,0.00,'vb_shared','know_problems',25,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(26,'ImportError','IMPORT_ERROR','A module or package could not be imported.','Module exists but cannot import specific name from it.','Check if name exists in module. Check for circular imports.',124,35025,169,42,17,14,NULL,1,0.88,'vb_shared','know_problems',26,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(27,'ImportWarning','','Import-related warnings about module loading.',NULL,NULL,133,34870,277,42,18,14,NULL,1,0.00,'vb_shared','know_problems',27,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(28,'IndentationError','INDENTATION_ERROR','Python code has incorrect indentation.','Mixed tabs/spaces or incorrect indentation level.','Use 4 spaces consistently. Run auto-formatter (black).',121,35025,169,42,17,14,NULL,1,0.91,'vb_shared','know_problems',28,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(29,'IndexError','INDEX_OUT_OF_RANGE','You tried to access a list index that does not exist.','List index exceeds bounds.','Check len(list) before indexing. Use try/except for dynamic access.',130,35025,169,42,17,14,NULL,1,0.89,'vb_shared','know_problems',29,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(30,'InterruptedError','','A system call was interrupted.',NULL,NULL,125,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',30,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(31,'IsADirectoryError','','Expected a file but got a directory.',NULL,NULL,125,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',31,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(32,'KeyError','KEY_ERROR','You tried to access a dictionary key that does not exist.','Dictionary key does not exist.','Use dict.get(key) with default, or check key existence with in operator.',127,35025,169,42,17,14,NULL,1,0.90,'vb_shared','know_problems',32,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(33,'KeyboardInterrupt','','The user pressed Ctrl+C to stop the program.',NULL,NULL,132,35025,169,42,16,14,NULL,1,0.00,'vb_shared','know_problems',33,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(34,'LookupError','','A lookup operation failed (base class for KeyError, IndexError).',NULL,NULL,NULL,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',34,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(35,'MemoryError','','The program ran out of memory.',NULL,NULL,132,35025,169,42,16,14,NULL,1,0.00,'vb_shared','know_problems',35,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(36,'ModuleNotFoundError','MODULE_NOT_FOUND','A specific module could not be found.','Module is not installed or not in sys.path.','Run: pip install module_name. Or add path to sys.path.',124,35025,169,42,17,14,NULL,1,0.95,'vb_shared','know_problems',36,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(37,'NameError','NAME_NOT_DEFINED','A variable or function name is not defined.','Variable or function name used before assignment or import.','Check spelling. Add import statement. Ensure variable is defined before use.',131,35025,169,42,17,14,NULL,1,0.90,'vb_shared','know_problems',37,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(38,'NotADirectoryError','','Expected a directory but got a file.',NULL,NULL,125,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',38,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(39,'NotImplementedError','','A method or function is not implemented yet.',NULL,NULL,92,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',39,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(40,'OSError','','An operating system error occurred.',NULL,NULL,125,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',40,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(41,'OverflowError','','A math operation produced a number too large to handle.',NULL,NULL,123,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',41,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(42,'PendingDeprecationWarning','','Features that will be deprecated in the future.',NULL,NULL,133,34870,277,42,18,14,NULL,1,0.00,'vb_shared','know_problems',42,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(43,'PermissionError','PERMISSION_DENIED','You do not have permission to access this file or resource.','File or directory lacks read/write permissions.','Check permissions with ls -la. Use chmod if needed.',125,35025,169,42,17,14,NULL,1,0.86,'vb_shared','know_problems',43,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(44,'ProcessLookupError','','Could not find the specified process.',NULL,NULL,132,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',44,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(45,'PythonFinalizationError','','An error occurred during Python shutdown.',NULL,NULL,NULL,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',45,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(46,'RecursionError','RECURSION_ERROR','Too many recursive calls (infinite recursion).','Maximum recursion depth exceeded.','Add base case to recursive function.',92,35025,169,42,16,14,NULL,1,0.91,'vb_shared','know_problems',46,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(47,'ReferenceError','','A weak reference was accessed after the object was deleted.',NULL,NULL,92,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',47,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(48,'ResourceWarning','','A resource was not properly cleaned up.',NULL,NULL,133,34870,277,42,18,14,NULL,1,0.00,'vb_shared','know_problems',48,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(49,'RuntimeError','RUNTIME_ERROR','An unexpected runtime error occurred.','Generic runtime error.','Check the specific error message. Add proper error handling.',92,35025,169,42,17,14,NULL,1,0.75,'vb_shared','know_problems',49,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(50,'RuntimeWarning','','Runtime-related warnings.',NULL,NULL,133,34870,277,42,18,14,NULL,1,0.00,'vb_shared','know_problems',50,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(51,'StopAsyncIteration','','An async iterator was stopped.',NULL,NULL,92,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',51,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(52,'StopIteration','','An iterator was stopped (raised by next() when done).',NULL,NULL,92,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',52,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(53,'SyntaxError','SYNTAX_ERROR','The code has invalid Python syntax.','Invalid Python syntax - missing colon, bracket, or indentation.','Check line indicated in traceback. Fix indentation (4 spaces). Add missing colon or bracket.',121,35025,169,42,17,14,NULL,1,0.93,'vb_shared','know_problems',53,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(54,'SyntaxWarning','','Suspicious syntax that may indicate an error.',NULL,NULL,133,34870,277,42,18,14,NULL,1,0.00,'vb_shared','know_problems',54,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(55,'SystemError','','An internal Python system error occurred.',NULL,NULL,132,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',55,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(56,'SystemExit','','The program is exiting (raised by sys.exit()).',NULL,NULL,132,35025,169,42,16,14,NULL,1,0.00,'vb_shared','know_problems',56,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(57,'TabError','','Inconsistent use of tabs and spaces in indentation.',NULL,NULL,121,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',57,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(58,'TimeoutError','','A function or operation timed out.',NULL,NULL,125,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',58,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(59,'TypeError','TYPE_ERROR','You used the wrong data type for an operation.','Wrong type passed to function or operation.','Check argument types. Use isinstance() for type guards.',129,35025,169,42,17,14,NULL,2,0.88,'vb_shared','know_problems',59,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(60,'UnboundLocalError','','You referenced a local variable before it was assigned.',NULL,NULL,131,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',60,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(61,'UnicodeDecodeError','ENCODING_ERROR','Could not decode bytes into text.','File contains bytes that cannot be decoded with specified encoding.','Try encoding=utf-8 or encoding=latin-1. Use errors=replace.',128,35025,169,42,17,14,NULL,1,0.84,'vb_shared','know_problems',61,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(62,'UnicodeEncodeError','','Could not encode text into bytes.',NULL,NULL,128,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',62,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(63,'UnicodeError','','A Unicode-related encoding/decoding error occurred.',NULL,NULL,128,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',63,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(64,'UnicodeTranslateError','','Could not translate Unicode characters.',NULL,NULL,128,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',64,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(65,'UnicodeWarning','','Unicode-related warnings.',NULL,NULL,133,34870,277,42,18,14,NULL,1,0.00,'vb_shared','know_problems',65,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(66,'UserWarning','','User-defined warnings.',NULL,NULL,133,34870,277,42,18,14,NULL,1,0.00,'vb_shared','know_problems',66,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(67,'ValueError','VALUE_ERROR','A value is incorrect or malformed.','Correct type but invalid value passed to function.','Validate input before passing. Use try/except ValueError.',128,35025,169,42,17,14,NULL,2,0.87,'vb_shared','know_problems',67,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(68,'Warning','','Base class for all warnings.',NULL,NULL,133,34870,277,42,18,14,NULL,1,0.00,'vb_shared','know_problems',68,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(69,'ZeroDivisionError','ZERO_DIVISION','You tried to divide by zero.','Attempted to divide by zero.','Check divisor before dividing. Use try/except ZeroDivisionError.',123,35025,169,42,17,14,NULL,5,0.93,'vb_shared','know_problems',69,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(70,'_IncompleteInputError','','Incomplete input was provided.',NULL,NULL,NULL,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',70,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(71,'Heredoc file write corruption','','Heredoc file write corruption. Root cause: macOS has 4 buffering layers (zsh, libc stdio, Python, pipe) that silently overflow on large data. Contributing factor: Windsurf IDE auto-formats shell scripts, normalizes whitespace, and can inject CRLF/indentation changes that break heredoc parsing (EOF not at column 0, trailing spaces). Result: files get silently corrupted or scripts hang.',NULL,NULL,NULL,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',71,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(72,'Memory overflow during large dataset processing','','Loading entire dataset into memory causes overflow. Need streaming processing for billion-record scale.',NULL,NULL,NULL,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',72,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(73,'Non-deterministic consolidation results','','Dictionary iteration order varies across runs, breaking reproducibility and verification.',NULL,NULL,NULL,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',73,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(74,'Accidental data loss from destructive operations','','Source deletion without explicit opt-in causes irreversible data loss.',NULL,NULL,NULL,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',74,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(75,'Path traversal attacks in file operations','','Unvalidated file paths allow directory traversal and unsafe access.',NULL,NULL,NULL,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',75,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(76,'Backup corruption undetected','','Corrupted backups cause data loss when original sources are deleted.',NULL,NULL,NULL,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',76,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(77,'Disk space exhaustion during backup','','Insufficient disk space causes backup failure mid-operation, leaving inconsistent state.',NULL,NULL,NULL,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',77,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(78,'Slow bulk database operations','','Individual INSERT statements are 10-100x slower than bulk operations.',NULL,NULL,NULL,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',78,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(79,'Transaction corruption mid-migration','','Migration failure without rollback leaves target database in corrupted state.',NULL,NULL,NULL,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',79,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(80,'Misclassification of rules databases as chat','','Databases with rules/validation tables are governance systems, not chat data. Should be classified as non_chat to avoid incorrect migration.',NULL,NULL,NULL,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',80,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(81,'Misclassification of settings databases as chat','','Databases with settings/setting/windsurf tables are configuration systems, not chat data. Should be classified as non_chat to avoid incorrect migration.',NULL,NULL,NULL,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',81,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(82,'Misclassification of style databases as chat','','Databases with style/styles tables are styling systems, not chat data. Should be classified as non_chat to avoid incorrect migration.',NULL,NULL,NULL,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',82,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(83,'Misclassification of test databases as chat','','Databases with test_schema/test_v tables are test systems, not chat data. Should be classified as non_chat to avoid incorrect migration.',NULL,NULL,NULL,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',83,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(84,'Forced classification without evidence','','Classifying databases without proper evidence leads to incorrect migrations. Should classify as unknown with confidence 0 when no evidence matches.',NULL,NULL,NULL,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',84,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(85,'Creating mechanisms without understanding existing infrastructure','','Creating new tables, classes, or execution mechanisms without thoroughly examining existing code, CLI tools, and database patterns leads to unnecessary duplication and maintenance overhead. This happens when assumptions are made instead of investigating what already exists.',NULL,NULL,NULL,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',85,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(86,'Modifying database without backup','','Performing ALTER, DROP, DELETE, or other destructive operations on the database without creating a timestamped backup first. User does not manually backup database and expects AI to perform safe operations. If a mistake occurs, there is no way to restore the database.',NULL,NULL,NULL,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',86,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(87,'VBStyleViolation','MISSING_RETURN_TUPLE','code_db.py missing VBStyle header - violates rule vbsty/vbstyle','VBStyle methods must return Tuple3 (ok, data, error).','Ensure all Run() methods return (bool, data, error) tuple.',NULL,35025,169,42,17,14,NULL,1,0.92,'vb_shared','know_problems',87,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(88,'Schema suggestion without verification','','AI suggests creating new tables or schema changes without first querying sqlite_master, governance, or existing tables. This causes duplication, conflicts with existing patterns, and potential corruption of the database authority model.',NULL,NULL,NULL,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',88,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(89,'OOP method ownership assumption','','Assuming methods belong to classes and are assigned statically. This creates rigid binding, prevents reuse, and turns the capability pool into a class-bound mess. The correct model is dynamic capability resolution where classes declare requirements and Main Unit selects compatible methods from the pool at runtime.',NULL,NULL,NULL,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',89,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(90,'PrintStatementViolation','','Code contains print() statement which violates VBStyle rule. Must use Report class for all output.',NULL,NULL,NULL,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',90,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(91,'Swift MCP Server stdout debug output breaks MCP protocol','','Swift MCP server was printing debug output to stdout instead of stderr. The MCP stdio protocol requires only JSON-RPC messages on stdout. Debug output must go to stderr. This mixed output caused Windsurf\'s MCP client to fail parsing and get EOF errors.',NULL,NULL,NULL,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',91,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(92,'Swift MCP server not recognized by Windsurf IDE','','Swift MCP server executable was not in the correct directory for Windsurf to recognize it. The IDE requires MCP executables to be in ~/.codeium/windsurf/ directory. Moving the executable to this location and updating mcp_config.json resolved the recognition issue.',NULL,NULL,NULL,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',92,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(93,'SwiftPM unhandled files warning for backup and markdown files','','SwiftPM warned about 9 unhandled files in the SwiftMcpServer target directory: backup files (.bak, .bak2, .bak3, .bak4, .bak5) and markdown files (codeintslqitdb.md, codeintslqitdb_new.md, installation_checklist.md, installation_selection.md). These files were in the Sources directory but not declared as resources or excluded from the target.',NULL,NULL,NULL,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',93,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(94,'MCP stdio protocol EOF errors from stdout debug output','','MCP stdio transport requires ONLY JSON-RPC messages on stdout. Any debug output, print statements, or errors written to stdout will cause the MCP client to fail parsing with EOF errors. This is a critical protocol violation that breaks communication between server and client.',NULL,NULL,NULL,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',94,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(95,'MCP capability negotiation errors (-32602 Invalid Params)','','JSON-RPC error code -32602 indicates \"Invalid params\" and is returned in many contexts. A common cause is a server sending sampling or elicitation requests to a client that hasn\'t declared that capability. This happens during the initialize exchange when capabilities are not properly negotiated.',NULL,NULL,NULL,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',95,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(96,'MCP Streamable HTTP security vulnerabilities (DNS rebinding)','','Streamable HTTP transport is vulnerable to DNS rebinding attacks if Origin header validation is not implemented. Attackers could use DNS rebinding to interact with local MCP servers from remote websites. Servers must validate Origin header and bind only to localhost.',NULL,NULL,NULL,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',96,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(97,'MCP server initialization timeout','','MCP server may take too long to initialize if database is large or if auto-discovery scans many directories. IDE may timeout waiting for server to respond to initialize request, causing connection failure. Heavy operations at startup block the initialization handshake.',NULL,NULL,NULL,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',97,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(98,'MCP server working directory undefined or incorrect','','When MCP client launches a stdio server, the working directory may be undefined (like / on macOS) since the client could be started from anywhere. Relative paths in configuration fail because working directory is not what the server expects.',NULL,NULL,NULL,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',98,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(99,'MCP servers do not inherit environment variables automatically','','MCP servers launched over stdio inherit only a limited subset of environment variables automatically (platform-dependent). Required environment variables for database paths, API keys, or configuration may not be available to the server process.',NULL,NULL,NULL,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',99,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(100,'Windsurf IDE does not discover MCP server','','MCP server may be configured correctly but Windsurf IDE does not discover it. This can happen if executable path is wrong, server is not in expected location, or mcp_config.json has syntax errors. Tools may not appear in Cascade.',NULL,NULL,NULL,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',100,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(101,'Windsurf MCP admin whitelist blocks all non-whitelisted servers','','In Windsurf Teams/Enterprise, once admin whitelists even a single MCP server, ALL non-whitelisted servers are automatically blocked for team members. This can be surprising and block legitimate servers users need.',NULL,NULL,NULL,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',101,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(102,'Windsurf MCP config environment variable interpolation fails','','Windsurf mcp_config.json supports environment variable interpolation with ${env:VAR_NAME} syntax, but this may fail if variable is not set, syntax is incorrect, or interpolation is not supported in the specific field being used.',NULL,NULL,NULL,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',102,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(103,'Deprecated .text() API in Swift MCP SDK','','SwiftMcpServer uses deprecated .text() API calls. The Swift MCP SDK changed from .text(\"message\") to .text(text: \"message\", annotations: nil, _meta: nil). Compiler warnings indicate these deprecated calls need to be updated for forward compatibility.',NULL,NULL,NULL,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',103,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(104,'Swift version compatibility - Swift 6.0+ required','','Swift MCP SDK requires Swift 6.0+ and Xcode 16+. Users on older Swift versions or macOS versions cannot build or run the server. Package.swift specifies swift-tools-version: 6.0 and platforms: [.macOS(.v14)].',NULL,NULL,NULL,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',104,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(105,'macOS sandboxing blocks stdio subprocess execution','','When using stdio servers in a macOS app, sandboxing must be disabled. The app needs to run processes for each server, but sandboxing prevents subprocess execution. This is a platform-specific restriction for macOS apps.',NULL,NULL,NULL,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',105,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(106,'Unmaintained Swift MCP SDK (gsabran/mcp-swift-sdk)','','The gsabran/mcp-swift-sdk package is archived and will not be maintained anymore. Anthropic chose modelcontextprotocol/swift-sdk as the official Swift MCP SDK. Using the unmaintained SDK means no support for future MCP spec changes.',NULL,NULL,NULL,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',106,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(107,'SwiftPM Package.resolved deletion bug in Xcode','','Xcode has a widespread bug where it deletes Package.resolved when changing git branches or for seemingly no reason. This causes dozens or hundreds of \"Missing package product\" errors. The bug exists in Xcode 15.4 and has been reported since 2020.',NULL,NULL,NULL,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',107,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(108,'SwiftPM build cache corruption causing build failures','','SwiftPM build cache in .build directory can become corrupted, causing build failures that are difficult to debug. Error messages may be cryptic or misleading. This happens especially after dependency changes or Xcode updates.',NULL,NULL,NULL,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',108,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(109,'SwiftPM dependency resolution failures','','SwiftPM may fail to resolve dependencies due to network issues, dependency conflicts, or registry problems. This prevents building the server. Error messages may not clearly indicate the root cause of resolution failure.',NULL,NULL,NULL,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',109,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(110,'MCP error -32000 Connection Closed','','Error -32000 is the most common MCP error (97% of connection failures). It means the JSON-RPC connection was terminated unexpectedly. The server started but crashed or produced invalid output before completing the handshake. Causes: stdout pollution (43%), wrong Node.js/Python path (28%), JSON config syntax errors (15%), missing dependencies (9%).',NULL,NULL,NULL,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',110,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(111,'MCP error -32001 Request Timeout','','The MCP client sent a request and did not get a response within the timeout window (typically 60 seconds). The server is running but a specific tool execution is taking too long. This can happen with long-running database queries, file operations, or network requests.',NULL,NULL,NULL,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',111,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(112,'MCP 406 Not Acceptable - transport mismatch','','HTTP requests sent to a server that only accepts SSE transport, or vice versa. Modern standard uses single endpoint at /mcp for Streamable HTTP. Legacy transport uses /sse for streaming plus separate POST endpoint. This is a transport configuration mismatch.',NULL,NULL,NULL,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',112,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(113,'MCP \"Spawn ENOENT\" or \"Command Not Found\"','','The MCP client cannot find the executable specified in config. The path to node, python, npx, or uvx does not exist in the client process environment. This is especially common with nvm or pyenv because shell PATH differs from MCP client process.',NULL,NULL,NULL,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',113,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(114,'MCP server works locally but fails remotely','','Server works with stdio transport locally but remote clients cannot connect over HTTP. Common causes: missing CORS headers, Vercel deployment protection, wrong URL path, firewall or network restrictions. Server may not be configured for remote access.',NULL,NULL,NULL,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',114,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(115,'MCP authentication errors (401 Unauthorized / 403 Forbidden)','','MCP server requires authentication but client is not providing valid credentials. This can happen with OAuth, API keys, or custom authentication. Common patterns: missing Authorization header, expired tokens, invalid credentials, scope mismatch.',NULL,NULL,NULL,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',115,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(116,'Dead code path in MCPServer._handle_call_tool and incorrect call_tool return type','','Dead code path in MCPServer._handle_call_tool and incorrect call_tool return type',NULL,NULL,NULL,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',116,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(117,'Community listing / registry guidance for SignalSpore MCP','','Community listing / registry guidance for SignalSpore MCP',NULL,NULL,NULL,35025,169,42,17,14,NULL,1,0.00,'vb_shared','know_problems',117,'2026-07-02 20:04:25','2026-07-02 20:04:25','2026-07-02 20:04:25'),(118,'🏆 CHALLENGE: First External AI to Complete a Task on AI-to-AI M