CREATE TABLE `foundation_law` (
  `id` int NOT NULL AUTO_INCREMENT,
  `law_code` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL,
  `law_name` varchar(200) COLLATE utf8mb4_unicode_ci NOT NULL,
  `law_text` text COLLATE utf8mb4_unicode_ci NOT NULL,
  `domain` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'architecture',
  `scope` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'universal',
  `severity` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'mandatory',
  `source` varchar(200) COLLATE utf8mb4_unicode_ci DEFAULT 'conversation',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `law_code` (`law_code`),
  KEY `idx_foundation_law_code` (`law_code`),
  KEY `idx_foundation_law_domain` (`domain`),
  KEY `idx_foundation_law_scope` (`scope`)
) ENGINE=InnoDB AUTO_INCREMENT=21 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

LOCK TABLES `foundation_law` WRITE;
/*!40000 ALTER TABLE `foundation_law` DISABLE KEYS */;
INSERT INTO `foundation_law` VALUES (1,'LAW1','One Concept. One Authority. One Table.','Every reusable concept has exactly one authoritative table. Every other table references it via PK/FK. No duplicate lookup tables for the same concept. No kind column in authority tables — the entity provides the context.','database','universal','mandatory','conversation','2026-07-02 20:48:37'),(2,'LAW2','The Entity Is The Thing.','Entity names describe WHAT something is, never HOW it was created or WHO owns it. How it was obtained is an attribute. Who owns it is a relationship. The entity is the thing. The authorities describe the thing.','database','universal','mandatory','conversation','2026-07-02 20:48:37'),(3,'LAW3','Tables Store Pieces. The Story Is Assembled When You Read Them.','No table stores a sentence. No table stores a narrative. Every table stores one piece of truth. The story exists only at the moment of reading — assembled by following PK/FK relationships across entity and authority tables.','database','universal','mandatory','conversation','2026-07-02 20:48:37'),(4,'LAW4','A Report Is a Container of Relationships.','A report is never 1:1. A report has many errors, many problems, many causes, many fixes. Everything is linked via join tables. No comma-separated ID lists. No denormalized arrays. Every link is a row — queryable, indexable, normalizable.','database','universal','mandatory','conversation','2026-07-02 20:48:37'),(5,'LAW5','Context Gives Meaning.','The container provides the context. The array provides the members. The values have no meaning until you know which container they are inside. Store the meaning once. Reference it everywhere else. Never repeat the concept inside the concept.','bcl','universal','mandatory','conversation','2026-07-02 20:48:37'),(6,'PRINCIPLE','Store Meaning Once. Reference It Everywhere Else.','All five laws are the same law at different levels. Laws 1-2 govern the database. Laws 3-4 govern the relationship between database and report. Law 5 governs BCL. The single principle: store the meaning once, reference it everywhere else.','architecture','universal','mandatory','conversation','2026-07-02 20:48:37'),(7,'ENU','No Enums','Do not use enums. Use integer constants or string values with authority table FKs. Enums are hidden partitioning — they embed meaning in the column type instead of in a reference.','vbstyle','code','mandatory','vbpack','2026-07-02 20:48:37'),(8,'PRT','No Print Statements','No print() in class methods or authorities. Use Report class or logging. Print is hidden output — it bypasses the report engine and violates the three-layer pipeline.','vbstyle','code','mandatory','vbpack','2026-07-02 20:48:37'),(9,'DEC','No Decorators','No @property, @staticmethod, @classmethod, @dataclass, @abstractmethod, @objc. Decorators are hidden behavior — they modify execution without being visible in the dispatch chain.','vbstyle','code','mandatory','vbpack','2026-07-02 20:48:37'),(10,'DTC','No Direct Type Check','No direct type checking with isinstance() or type(). Use capability resolution or dispatch patterns instead.','vbstyle','code','mandatory','vbpack','2026-07-02 20:48:37'),(11,'VFP','No Visible Function Print','No visible function print. All output goes through the Report class.','vbstyle','code','mandatory','vbpack','2026-07-02 20:48:37'),(12,'HUD','No Hidden Behavior','No hidden or implicit behavior. All actions must be explicit. No implicit auto operations. If something happens, it must be visible in the dispatch chain.','vbstyle','code','mandatory','vbpack','2026-07-02 20:48:37'),(13,'IAO','No Implicit Auto Ops','No implicit automatic operations. Everything must be explicitly dispatched. No magic. No behind-the-scenes behavior.','vbstyle','code','mandatory','vbpack','2026-07-02 20:48:37'),(14,'FMN','No Fake Manager','No fake manager classes. Helper, Util, Service, FakeManager are warning signs. Real classes own real domains.','vbstyle','code','mandatory','vbpack','2026-07-02 20:48:37'),(15,'FWB','No Forbidden Write Back','No forbidden write back. Data flows in one direction through the pipeline. No silent writes behind the system.','vbstyle','code','mandatory','vbpack','2026-07-02 20:48:37'),(16,'NHB','No Hidden Behavior (locked)','No hidden behavior. All execution must be explicit and visible in the dispatch chain. This is the locked version of HUD.','vbstyle','architecture','mandatory','vbpack','2026-07-02 20:48:37'),(17,'NHUS','No Hidden Underscore State','No self._ variables. Use self.state dictionary. Hidden state is hidden behavior.','vbstyle','code','mandatory','vbpack','2026-07-02 20:48:37'),(18,'TUPLE3','Tuple3 Return Required','All methods must return (ok, data, error) where ok=1 success, ok=0 failure. No other return shape allowed.','vbstyle','code','mandatory','vbpack','2026-07-02 20:48:37'),(19,'GHOST','Ghost Header Required','All files must have #[@GHOST] header with file_path, date, author, session_id, context. No anonymous files.','vbstyle','code','mandatory','vbpack','2026-07-02 20:48:37'),(20,'VBSTYLE','VBStyle Header Required','All files must have #[@VBSTYLE] header with auth, role, return, orch, no, model. Identity = existence.','vbstyle','code','mandatory','vbpack','2026-07-02 20:48:37');

