er: _________________________\\n\\n# Q: What is the UI class naming contract?','3fc648a5be7992892b5c2a537b0c664c',9,NULL,NULL,NULL,'chatgpt','',0,1,2,'chatgpt_export','Questions',2587,'question_text','2026-07-02 19:43:11'),(2569,'SegmentName]UI\\n# [ ] [SegmentName]View\\n# [ ] [SegmentName]Widget\\n# [ ] Other: _________________________\\n\\n# Q: What is the handler naming contract?','0b0cc1c8b282d03a5c504da0dea079a2',9,NULL,NULL,NULL,'chatgpt','',0,1,2,'chatgpt_export','Questions',2588,'question_text','2026-07-02 19:43:11'),(2570,'Other: _________________________\\n\\n# Q: What is the handler signature rule?','e0b9a7c524c0b793a966beb9d7c58703',9,NULL,NULL,NULL,'chatgpt','',0,1,2,'chatgpt_export','Questions',2589,'question_text','2026-07-02 19:43:11'),(2571,'Must match Qt signal signature exactly\\n# [ ] Must accept *args and ignore extras\\n# [ ] Must accept zero args only\\n# [ ] Other: _________________________\\n\\n# Q: How should missing handlers be treated during verification?','5273ae5b3942f34c9ba22e0774ede927',9,NULL,NULL,NULL,'chatgpt','',0,1,2,'chatgpt_export','Questions',2590,'question_text','2026-07-02 19:43:11'),(2572,'Error (fail validation)\\n# [ ] Warning only\\n# [ ] Auto-generate handler stubs in code file\\n# [ ] Other: _________________________\\n\\n# Q: How should unknown widget types be treated?','b8bc4bebbe46b975f2fc16adf535844b',9,NULL,NULL,NULL,'chatgpt','',0,1,2,'chatgpt_export','Questions',2591,'question_text','2026-07-02 19:43:11'),(2573,'Error (reject generation)\\n# [ ] Warning and substitute QWidget\\n# [ ] Warning and skip node\\n# [ ] Other: _________________________\\n\\n# Q: How should unknown properties be treated?','e5164c7016d6faf9cda12aed51930506',9,NULL,NULL,NULL,'chatgpt','',0,1,2,'chatgpt_export','Questions',2592,'question_text','2026-07-02 19:43:11'),(2574,'Error (reject generation)\\n# [ ] Warning and ignore property\\n# [ ] Warning and record in report for later mapping\\n# [ ] Other: _________________________\\n\\n# Q: What is the sync conflict winner rule?','4923d3b411c9a7fc1f1ae808623dbc25',9,NULL,NULL,NULL,'chatgpt','',0,1,2,'chatgpt_export','Questions',2593,'question_text','2026-07-02 19:43:11'),(2575,'Central YAML always wins (regenerate files)\\n# [ ] Files always win (rewrite central YAML)\\n# [ ] Last-modified timestamp wins\\n# [ ] Interactive choice every conflict\\n# [ ] Other: _________________________\\n\\n# Q: If timestamps are used, what is the clock authority?','9f209cdf3b348001d8d9620fa7b432e5',9,NULL,NULL,NULL,'chatgpt','',0,1,2,'chatgpt_export','Questions',2594,'question_text','2026-07-02 19:43:11'),(2576,'File system mtime only\\n# [ ] Hash-based content versioning in YAML\\n# [ ] Both; mismatch is error\\n# [ ] Other: _________________________\\n\\n# Q: What is the required report output format for all commands?','ba0e85913e899d9d80c490f1430ba8fe',9,NULL,NULL,NULL,'chatgpt','',0,1,2,'chatgpt_export','Questions',2595,'question_text','2026-07-02 19:43:11'),(2577,'Plain text only\\n# [ ] JSON report file per run\\n# [ ] YAML report file per run\\n# [ ] Both: human text + machine report artifact\\n# [ ] Other: _________________________\\n\\n# Q: What is the required error packet content?','b70383ed1c482feb90bfba83cdab75ba',9,NULL,NULL,NULL,'chatgpt','',0,1,2,'chatgpt_export','Questions',2596,'question_text','2026-07-02 19:43:11'),(2578,'Other: _________________________\\n\\n# Q: What exit code policy should CLI follow?','b12d9531fddfe0b11a25b83be2ddc254',9,NULL,NULL,NULL,'chatgpt','',0,1,2,'chatgpt_export','Questions',2597,'question_text','2026-07-02 19:43:11'),(2579,'Other: _________________________\\n\\n# Q: Should the generator produce deterministic ordering of widgets and imports?','6d73156168d4512cdfd8d8848fd531c9',9,NULL,NULL,NULL,'chatgpt','',0,1,2,'chatgpt_export','Questions',2598,'question_text','2026-07-02 19:43:11'),(2580,'Yes, sort imports and widget creation deterministically\\n# [ ] No, preserve authoring order only\\n# [ ] Other: ___________________