e',NULL,136,'report','report_id+evidence_id',1,1,'2026-07-02 21:02:32'),(32,'report_rule','Report-Rule','M:N link between report and rule',NULL,136,'report','report_id+rule_id',1,1,'2026-07-02 21:02:32'),(33,'report_question','Report-Question','M:N link between report and question',NULL,136,'report','report_id+question_id',1,1,'2026-07-02 21:02:32'),(34,'incident_problem','Incident-Problem','M:N link between incident and problem (legacy)',NULL,138,'report','incident_id+problem_id',1,1,'2026-07-02 21:02:32'),(35,'problem_solution','Problem-Solution','Known solutions for a problem type (legacy — should be entity not junction)',NULL,138,'report','id',1,1,'2026-07-02 21:02:32'),(36,'question_type','Question Type','Legacy type table — replaced by type authority',NULL,138,'report','id',0,1,'2026-07-02 21:02:32'),(37,'foundation_law','Foundation Law','Deprecated — replaced by law + pattern + pattern_law + decision',NULL,139,'architecture','id',0,1,'2026-07-02 21:02:32'),(38,'table_registry','Table Registry','One row per table — what the table is',NULL,137,'architecture','id',1,1,'2026-07-02 21:02:32'),(39,'table_column','Table Column','One row per column — what each column means',NULL,137,'architecture','id',1,1,'2026-07-02 21:02:32'),(40,'table_relationship','Table Relationship','One row per FK — how tables connect',NULL,137,'architecture','id',1,1,'2026-07-02 21:02:32'),(41,'table_rule','Table Rule','Which laws apply to which table',NULL,137,'architecture','id',1,1,'2026-07-02 21:02:32'),(42,'Method','Method','The smallest executable unit — a single method/function with its own Code, BCL, BCLIR, Graph representations',NULL,135,'code','Id',1,1,'2026-07-02 21:09:02'),(43,'ComputationUnit','ComputationUnit','A composition of methods — a computational unit that groups methods into a reusable unit',NULL,135,'code','Id',1,1,'2026-07-02 21:09:02'),(44,'Class','Class','A composition of computation units — the highest level code structure entity',NULL,135,'code','Id',1,1,'2026-07