CREATE TABLE sessions (
  id              BIGINT AUTO_INCREMENT PRIMARY KEY,
  title           VARCHAR(300) NOT NULL,             -- filename or conversation title
  model           VARCHAR(100),                      -- gpt-4o-mini, claude-sonnet-4, etc.
  created_at      BIGINT,                            -- file date / conversation date (unix)
  imported_at     TIMESTAMP DEFAULT CURRENT_TIMESTAMP,  -- when it entered MySQL
  INDEX idx_title (title)
);

CREATE TABLE messages (
  row_id          BIGINT AUTO_INCREMENT PRIMARY KEY,
  session_id      BIGINT NOT NULL,
  node_id         INT NOT NULL,                      -- sequential within session
  role            VARCHAR(20) NOT NULL,              -- user|assistant|system|tool
  content         LONGTEXT,                          -- the message text
  created_at      BIGINT,                            -- unix timestamp (if known)
  FOREIGN KEY (session_id) REFERENCES sessions(id) ON DELETE CASCADE,
  INDEX idx_session (session_id),
  INDEX idx_session_node (session_id, node_id),
  INDEX idx_role (role)
);

CREATE TABLE prompts (
  id              BIGINT AUTO_INCREMENT PRIMARY KEY,
  session_id      BIGINT NOT NULL,
  content         TEXT NOT NULL,
  timestamp       BIGINT,
  FOREIGN KEY (session_id) REFERENCES sessions(id) ON DELETE CASCADE,
  INDEX idx_session (session_id),
  INDEX idx_timestamp (timestamp)
);



-- ======================================================================
-- SQL: gui_engine/GuisEngins_db.sql (4.4KB)
-- ======================================================================
CREATE TABLE IF NOT EXISTS gui_files (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    file_path TEXT UNIQUE NOT NULL,
    file_name TEXT NOT NULL,
    language TEXT NOT NULL DEFAULT 'python',
    file_hash TEXT,
    full_source TEXT,
    line_count INTEGER DEFAULT 0,
    purpose TEXT,
    domain TEXT,
    ingested_at TEXT DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE IF NOT EXISTS gui_classes (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    file_id INTEGER NOT NULL,
    file_path TEXT NOT NULL,
    class_name TEXT NOT NULL,
    base_class TEXT,
    line_start INTEGER,
    line_end INTEGER,
    method_count INTEGER DEFAULT 0,
    is_qt_window INTEGER DEFAULT 0,
    source_text TEXT,
    purpose TEXT,
    domain TEXT,
    FOREIGN KEY (file_id) REFERENCES gui_files(id)
);

CREATE INDEX IF NOT EXISTS idx_gse_gc_class ON gui_classes(class_name);
CREATE INDEX IF NOT EXISTS idx_gse_gc_file ON gui_classes(file_path);

CREATE TABLE IF NOT EXISTS gui_comp_units (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    class_id INTEGER NOT NULL,
    file_path TEXT NOT NULL,
    class_name TEXT NOT NULL,
    unit_name TEXT NOT NULL,
    unit_type TEXT NOT NULL CHECK (unit_type IN
        ('METHOD','FUNCTION','INIT','RUN','DISPATCH','HANDLER','RENDERER',
         'BUILDER','PARSER','VALIDATOR','SCANNER','READER','WRITER',
         'PROPERTY','LAMBDA','NESTED','MAIN_BLOCK','MODULE_CONST')),
    line_start INTEGER,
    line_end INTEGER,
    line_count INTEGER DEFAULT 0,
    source_text TEXT,
    docstring TEXT,
    calls TEXT,
    returns TEXT,
    params TEXT,
    is_vbstyle INTEGER DEFAULT 0,
    has_run INTEGER DEFAULT 0,
    has_state INTEGER DEFAULT 0,
    returns_tuple3 INTEGER DEFAULT 0,
    FOREIGN KEY (class_id) REFERENCES gui_classes(id)
);

CREATE INDEX IF NOT EXISTS idx_gse_gcu_class ON gui_comp_units(class_name);
CREATE INDEX IF NOT EXISTS idx_gse_gcu_file ON gui_comp_units(file_path);
CREATE INDEX IF NOT EXISTS idx_gse_gcu_type ON gui_comp_units(unit_type);

CREATE TABLE IF NOT EXISTS gui_methods (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    comp_unit_id INTEGER NOT NULL,
    file_path TEXT NOT NULL,
    class_name TEXT NOT NULL,
    method_name TEXT NOT NULL,
    line_start INTEGER,
    line_end INTEGER,
    line_count INTEGER DEFAULT 0,
    source_text TEXT,
    docstring TEXT,
    params TEXT,
    calls TEXT,
    widget_refs TEXT,
    is_handler INTEGER DEFAULT 0,
    is_vbstyle INTEGER DEFAULT 0,
    returns_tuple3 INTEGER DEFAULT 0,
    FOREIGN KEY (comp_unit_id) REFERENCES gui_comp_units(id)
);

CREATE INDEX IF NOT EXISTS idx_gse_gm_class ON gui_methods(class_name);
CREATE INDEX IF NOT EXISTS idx_gse_gm_method ON gui_methods(method_name);
CREATE INDEX IF NOT EXISTS idx_gse_gm_file ON gui_methods(file_path);

CREATE TABLE IF NOT EXISTS gui_bcl_stamps (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    scope_type TEXT NOT NULL CHECK (scope_type IN
        ('FILE','CLASS','COMP_UNIT','METHOD')),
    scope_id INTEGER NOT NULL,
    file_path TEXT NOT NULL,
    class_name TEXT,
    unit_name TEXT,
    method_name TEXT,
    stamp_tier TEXT NOT NULL DEFAULT 'SURFACE',
    stamp_tag TEXT NOT NULL,
    stamp_key TEXT,
    stamp_value TEXT,
    reasoning TEXT,
    details TEXT,
    line_num INTEGER,
    created_at TEXT DEFAULT CURRENT_TIMESTAMP
);

CREATE INDEX IF NOT EXISTS idx_gse_gbs_scope ON gui_bcl_stamps(scope_type, scope_id);
CREATE INDEX IF NOT EXISTS idx_gse_gbs_tag ON gui_bcl_stamps(stamp_tag);
CREATE INDEX IF NOT EXISTS idx_gse_gbs_file ON gui_bcl_stamps(file_path);
CREATE INDEX IF NOT EXISTS idx_gse_gbs_class ON gui_bcl_stamps(class_name);

CREATE TABLE IF NOT EXISTS gui_edges (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    file_path TEXT NOT NULL,
    from_class TEXT,
    from_method TEXT,
    to_class TEXT,
    to_method TEXT,
    edge_type TEXT NOT NULL CHECK (edge_type IN
        ('CALLS','CONTAINS','INHERITS','IMPORTS','REFERENCES','DECORATES',
         'DISPATCHES_TO','RETURNS_TO','SIGNAL_TO')),
    line_num INTEGER,
    evidence TEXT
);

CREATE INDEX IF NOT EXISTS idx_gse_ge_from ON gui_edges(from_class, from_method);
CREATE INDEX IF NOT EXISTS idx_gse_ge_to ON gui_edges(to_class, to_method);
CREATE INDEX IF NOT EXISTS idx_gse_ge_type ON gui_edges(edge_type);



-- ======================================================================
-- SQL: gui_engine/gui_engine_db.sql (4.6KB)
-- ======================================================================
CREATE TABLE IF NOT EXISTS gui_files (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    file_path TEXT UNIQUE NOT NULL,
    file_hash TEXT,
    full_source TEXT,
    line_count INTEGER DEFAULT 0,
    class_count INTEGER DEFAULT 0,
    widget_count INTEGER DEFAULT 0,
    signal_count INTEGER DEFAULT 0,
    style_count INTEGER DEFAULT 0,
    ingested_at TEXT DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE IF NOT EXISTS gui_classes (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    file_path TEXT NOT NULL,
    class_name TEXT NOT NULL,
    base_class TEXT,
    line_start INTEGER,
    line_end INTEGER,
    is_qmainwindow INTEGER DEFAULT 0,
    method_count INTEGER DEFAULT 0,
    FOREIGN KEY (file_path) REFERENCES gui_files(file_path)
);

CREATE INDEX IF NOT EXISTS idx_gc_class ON gui_classes(class_name);
CREATE INDEX IF NOT EXISTS idx_gc_file ON gui_classes(file_path);

CREATE TABLE IF NOT EXISTS gui_widgets (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    file_path TEXT NOT NULL,
    class_name TEXT,
    widget_var TEXT NOT NULL,
    widget_type TEXT NOT NULL,
    widget_text TEXT,
    parent_var TEXT,
    parent_type TEXT,
    line_num INTEGER,
    context TEXT,
    properties_json TEXT,
    FOREIGN KEY (file_path) REFERENCES gui_files(file_path)
);

CREATE INDEX IF NOT EXISTS idx_gw_var ON gui_widgets(widget_var);
CREATE INDEX IF NOT EXISTS idx_gw_type ON gui_widgets(widget_type);
CREATE INDEX IF NOT EXISTS idx_gw_file ON gui_widgets(file_path);
CREATE INDEX IF NOT EXISTS idx_gw_class ON gui_widgets(class_name);

CREATE TABLE IF NOT EXISTS gui_styles (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    file_path TEXT NOT NULL,
    class_name TEXT,
    widget_var TEXT,
    selector TEXT,
    property_name TEXT,
    property_value TEXT,
    raw_stylesheet TEXT,
    line_num INTEGER,
    FOREIGN KEY (file_path) REFERENCES gui_files(file_path)
);

CREATE INDEX IF NOT EXISTS idx_gs_var ON gui_styles(widget_var);
CREATE INDEX IF NOT EXISTS idx_gs_file ON gui_styles(file_path);

CREATE TABLE IF NOT EXISTS gui_signals (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    file_path TEXT NOT NULL,
    class_name TEXT,
    widget_var TEXT NOT NULL,
    signal_name TEXT NOT NULL,
    handler_name TEXT NOT NULL,
    handler_type TEXT,
    line_num INTEGER,
    FOREIGN KEY (file_path) REFERENCES gui_files(file_path)
);

CREATE INDEX IF NOT EXISTS idx_gsig_var ON gui_signals(widget_var);
CREATE INDEX IF NOT EXISTS idx_gsig_handler ON gui_signals(handler_name);
CREATE INDEX IF NOT EXISTS idx_gsig_file ON gui_signals(file_path);

CREATE TABLE IF NOT EXISTS gui_layouts (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    file_path TEXT NOT NULL,
    class_name TEXT,
    layout_var TEXT NOT NULL,
    layout_type TEXT NOT NULL,
    parent_var TEXT,
    line_num INTEGER,
    FOREIGN KEY (file_path) REFERENCES gui_files(file_path)
);

CREATE INDEX IF NOT EXISTS idx_gl_var ON gui_layouts(layout_var);
CREATE INDEX IF NOT EXISTS idx_gl_file ON gui_layouts(file_path);

CREATE TABLE IF NOT EXISTS gui_edges (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    file_path TEXT NOT NULL,
    from_var TEXT,
    to_var TEXT,
    edge_type TEXT NOT NULL CHECK (edge_type IN
        ('CONTAINS','SIGNAL_TO','STYLE_ON','LAYOUT_OF','PARENT_OF','ADD_WIDGET','ADD_TAB','SET_CENTRAL')),
    line_num INTEGER,
    evidence TEXT,
    FOREIGN KEY (file_path) REFERENCES gui_files(file_path)
);

CREATE INDEX IF NOT EXISTS idx_ge_from ON gui_edges(from_var);
CREATE INDEX IF NOT EXISTS idx_ge_to ON gui_edges(to_var);
CREATE INDEX IF NOT EXISTS idx_ge_type ON gui_edges(edge_type);
CREATE INDEX IF NOT EXISTS idx_ge_file ON gui_edges(file_path);

CREATE TABLE IF NOT EXISTS gui_methods (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    file_path TEXT NOT NULL,
    class_name TEXT,
    method_name TEXT NOT NULL,
    line_start INTEGER,
    line_end INTEGER,
    is_handler INTEGER DEFAULT 0,
    widget_refs TEXT,
    FOREIGN KEY (file_path) REFERENCES gui_files(file_path)
);

CREATE INDEX IF NOT EXISTS idx_gm_class ON gui_methods(class_name);
CREATE INDEX IF NOT EXISTS idx_gm_method ON gui_methods(method_name);
CREATE INDEX IF NOT EXISTS idx_gm_file ON gui_methods(file_path);

CREATE TABLE IF NOT EXISTS gui_findings (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    finding_type TEXT NOT NULL,
    file_path TEXT,
    class_name TEXT,
    widget_var TEXT,
    description TEXT,
    severity TEXT DEFAULT 'info',
    found_at TEXT DEFAULT CURRENT_TIMESTAMP
);

CREATE INDEX IF NOT EXISTS idx_gf_type ON gui_findings(finding_type);



-- ======================================================================
-- SQL: gui_engine/style_db_v2.sql (0.8KB)
-- ======================================================================
CREATE TABLE IF NOT EXISTS gui_objects (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    object_type TEXT NOT NULL,
    object_name TEXT NOT NULL,
    UNIQUE(object_type, object_name)
);

CREATE TABLE IF NOT EXISTS property_stores (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    store_name TEXT NOT NULL UNIQUE
);

CREATE TABLE IF NOT EXISTS style_selectors (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    object_id INTEGER NOT NULL,
    store_id INTEGER NOT NULL,
    property_name TEXT NOT NULL,
    property_value TEXT,
    UNIQUE(object_id, store_id, property_name),
    FOREIGN KEY (object_id) REFERENCES gui_objects(id),
    FOREIGN KEY (store_id) REFERENCES property_stores(id)
);



-- ======================================================================
-- SQL: gui_engine/ui_db_v4.sql (0.9KB)
-- ======================================================================
CREATE TABLE IF NOT EXISTS components (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    component_type TEXT NOT NULL,
    component_name TEXT NOT NULL,
    base_component TEXT,
    properties TEXT,
    UNIQUE(component_type, component_name)
);

CREATE TABLE IF NOT EXISTS ui_nodes (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    parent_id INTEGER,
    component_id INTEGER NOT NULL,
    node_name TEXT NOT NULL,
    properties TEXT,
    order_index INTEGER DEFAULT 0,
    FOREIGN KEY (parent_id) REFERENCES ui_nodes(id),
    FOREIGN KEY (component_id) REFERENCES components(id)
);

CREATE TABLE IF NOT EXISTS ui_screens (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    screen_name TEXT NOT NULL UNIQUE,
    root_node_id INTEGER NOT NULL,
    FOREIGN KEY (root_node_id) REFERENCES ui_nodes(id)
);

